import type { Verse } from '../types';

// Capítulos reais deste livro. Segue o mesmo formato de src/bible/genesis.ts:
// { n: <capítulo>: [ { n: <versículo>, text: '<texto>' }, ... ] }
export const DEUTERONOMY_CHAPTERS: Record<number, Verse[]> = {
  1: [
    { n: 1, text: 'Lawa i marito lawa Moxe a ma vuleke eka Israyele hinkwayo entsungeni wa Yordani emananga, emabaleni ku langutana ni Lwandle lwo Tshwuka, exikarhi ka Parana, Tofele, Labana, Haseroti ni Di-sahaba.' },
    { n: 2, text: 'Ku ni pfhuka wa masiku ya khume-rin’we ku suka eHorebe hi ndlela ya Ntshava ya Seiri ku ya fika eKadesi-barnea.' },
    { n: 3, text: 'Kutani ku endleka hi lembe ra vumune-khume, hi n’hweti ya vukhume-ni-xin’we, hi siku ro sungula ra n’hweti, Moxe a vulavula ni vana va Israyele hi ku landza hinkwaswo leswi Yehovha a n’wi leriseke swona eka vona;' },
    { n: 4, text: 'endzhaku ka loko a dlayile Sihoni, hosi ya Vaamori, loyi a a tshama eHesboni, na Ogo, hosi ya Basani, loyi a a tshama eAxtaroti eEdreyi.' },
    { n: 5, text: 'Entsungeni wa Yordani, etikweni ra Mowabu, Moxe a sungula ku hlamusela nawu lowu, a ku:' },
    { n: 6, text: 'Yehovha Xikwembu xa hina u vulavurile na hina eHorebe, a ku: ‘Mi tshamile nkarhi wo leha entshaveni leyi;' },
    { n: 7, text: 'hundzukani, mi teka riendzo ra n’wina, mi ya entshaveni ya Vaamori ni le ka tindhawu hinkwato leti nga ekusuhi na yona, emabaleni, etintshaveni, etindhawini leti tsongahateke, ni le dzongeni, ni le ribuweni ra lwandle, etikweni ra Vakanana, ni le Libanoni, ku ya fika enambyeni lowukulu, ku nga nambu wa Yufrata.' },
    { n: 8, text: 'Vonani, ndzi vekile tiko leri mahlweni ka n’wina; nghenani mi teka tiko leri Yehovha a nga hlambanya eka vata va n’wina, ku nga Abrahama, Isaka na Yakobo, leswaku u ta va nyika rona xikan’we ni vana va vona endzhaku ka vona.' },
    { n: 9, text: 'Kutani ndzi vulavurile na n’wina hi nkarhi wolowo, ndzi ku: ‘Ndzi ri ndzexe a ndzi swi koti ku mi rhwala;' },
    { n: 10, text: 'Yehovha Xikwembu xa n’wina u mi tweetsile, naswona vonani, namuntlha mi tele ku fana ni tinyeleti ta tilo.' },
    { n: 11, text: 'Yehovha, Xikwembu xa vata va n’wina, a a mi engetele ku hundza hilaha mi nga hakona kambirhi ka gidi ra swiyenge, naswona a a mi katekise hilaha a mi tshembiseke hakona!' },
    { n: 12, text: 'Xana ndzi nga swi kotisa kuvhani ndzi ri ndzexe ku rhwala ndzhwalo wa n’wina, ni swirilo swa n’wina, ni timholovo ta n’wina?' },
    { n: 13, text: 'Hlawulani vavanuna va vutlhari, ni va ku twisisaka, lava tiviwaka eka tinyimba ta n’wina, leswaku ndzi va veka va va tinhloko ehenhla ka n’wina.' },
    { n: 14, text: 'Kutani mi ndzi hlamurile, mi ku: ‘Mhaka leyi u vuleke ku yi endla i yinene.' },
    { n: 15, text: 'Kutani ndzi teka tinhloko ta tinyimba ta n’wina, vavanuna va vutlhari ni lava tiviwaka, ndzi va veka va va tinhloko ehenhla ka n’wina, va va tindhuna ta magidi, ni tindhuna ta madzana, ni tindhuna ta makume ntlhanu, ni tindhuna ta makume, ni vafambisi va tinyimba ta n’wina.' },
    { n: 16, text: 'Kutani ndzi lerisa vaavanyisi va n’wina hi nkarhi wolowo, ndzi ku: ‘Yingiselani timhaka exikarhi ka vamakwenu, mi avanyisa hi ku lulama exikarhi ka munhu ni makwerhu kumbe muhluri loyi a tshamaka na yena.' },
    { n: 17, text: 'Mi nga tshuki mi hlawula nghohe eku avanyiseni; mi fanele ku yingisela lowutsongo ni lonkulu hi ku fana; mi nga chavi munhu ntsena, hikuva ku avanyisa i ka Xikwembu; naswona mhaka leyi nga ta mi tikela, mi ta yi tisa eka mina, ndzi ta yi yingisela.' },
    { n: 18, text: 'Kutani ndzi mi lerisile hi nkarhi wolowo swilo hinkwaswo leswi mi faneleke ku swi endla.' },
    { n: 19, text: 'Kutani hi suka eHorebe, hi famba emananga lawa hinkwawo lamakulu ni yo chavisa lawa mi ma voneke, hi ndlela ya ntshava ya Vaamori, hilaha Yehovha Xikwembu xa hina a hi leriseke hakona; kutani hi fika eKadesi-barnea.' },
    { n: 20, text: 'Kutani ndzi ku eka n’wina: ‘Mi fikile entshaveni ya Vaamori, leyi Yehovha Xikwembu xa hina a hi nyikaka yona.' },
    { n: 21, text: 'Vonani, Yehovha Xikwembu xa n’wina u vekile tiko mahlweni ka n’wina; tlhandlukani mi ri teka hilaha Yehovha Xikwembu xa vata va n’wina a mi vuleleke hakona; mi nga chavi, naswona mi nga tsemeki mbilu.' },
    { n: 22, text: 'Kuni n’wina hinkwenu mi tshinela eka mina, mi ku: ‘A hi rhumeni vavanuna va rhanga mahlweni ka hina, va ta hi kambelela tiko, va vuya va ta hi tivisa ndlela leyi hi faneleke ku tlhandluka hi yona ni miti leyi hi nga ta fika eka yona.' },
    { n: 23, text: 'Mhaka leyi yi va yinene emihlweni ya mina; kutani ndzi teka vavanuna va khume-mbirhi eka n’wina, munhu un’we eka nyimba yin’wana ni yin’wana.' },
    { n: 24, text: 'Va jika, va tlhandluka va ya entshaveni, va fika enkoveni wa Exikolo, va wu kambela.' },
    { n: 25, text: 'Va teka mihandzu ya tiko hi mavoko ya vona, va xika na yona eka hina; va vuya va hi tivisa, va ku: ‘I tiko rinene leri Yehovha Xikwembu xa hina a hi nyikaka rona.' },
    { n: 26, text: 'Kambe mi tsandzekile ku tlhandluka, mi pfukela xileriso xa Yehovha Xikwembu xa n’wina;' },
    { n: 27, text: 'Mi gungula ematendeni ya n’wina, mi ku: ‘Hi ku va Yehovha a hi vengile, hi swona swi n’wi endleke a hi humesa etikweni ra Egipta leswaku a hi nyiketa emavokweni ya Vaamori leswaku va hi lovisa.' },
    { n: 28, text: 'Xana hi tlhandlukela kwihi? Vamakwerhu va tsemile timbilu ta hina, va ku: Vanhuxaka i vakulu ni ku leha ku hundza hina; miti i yikulu naswona yi rhendzeriwile hi makhumbi lama fikeke etilweni; naswona hi vone na vana va Vaenaka kona.' },
    { n: 29, text: 'Kutani ndzi ku eka n’wina: ‘Mi nga tsemeki mbilu, naswona mi nga va chavi.' },
    { n: 30, text: 'Yehovha Xikwembu xa n’wina loyi a fambaka mahlweni ka n’wina, hi yena a nga ta mi lweri, hi ku landza hinkwaswo leswi a mi endleleke swona eEgipta mahlweni ka mahlo ya n’wina,' },
    { n: 31, text: 'ni le mananga, lomu u voneke leswaku Yehovha Xikwembu xa wena u ku rwele hilaha tatana a rwalaka n’wana wa yena hakona, emandleleni hinkwayo lawa mi fambeke ha wona ku fika lomu mi fikeke kona ndhawu leyi.' },
    { n: 32, text: 'Kambe eka mhaka leyi, a mi n’wi tshembanga Yehovha Xikwembu xa n’wina,' },
    { n: 33, text: 'loyi a fambaka mahlweni ka n’wina endleleni ku mi lavela ndhawu yo gwimba eka yona, hi ndzilo nivusiku ku mi komba ndlela leyi mi faneleke ku famba ha yona, ni hi papa ninhlikanhi.' },
    { n: 34, text: 'Yehovha a twa rito ra marito ya n’wina; kutani a hlundzuka, a hlambanya, a ku:' },
    { n: 35, text: 'Hakunene ku hava un’we wa vavanuna lava, wa xitukulwana lexi cho biha, loyi a nga ta vona tiko leri ra kahle leri ndzi hlambanyeke ku ri nyika vata va n’wina,' },
    { n: 36, text: 'handle ka Kalebe n’wana wa Yefune; u ta ri vona, naswona ndzi ta nyika yena ni vana va yena tiko leri a kandziyeke eka rona, hi ku va a landzele Yehovha hi mbilu hinkwayo.' },
    { n: 37, text: 'Na mina Yehovha u ndzi hlundzukerile hikwalaho ka n’wina, a ku: Na wena u nga ka u nga ngheni kona.'  },
    { n: 38, text: 'Yoxuwa n’wana wa Nuni, loyi a yimaka mahlweni ka wena, hi yena loyi a nga ta nghena kona; n’wi tiyise mbilu, hikuva u ta endla leswaku Israyele a ri dya ndzhaka.'},
    { n: 39, text: 'Naswona vana va n’wina lava mi vuleke leswaku va ta va swo phangiwa, ni vana va n’wina lava namuntlha va nga tiviki leswinene kumbe leswo biha, va ta nghena kona, naswona ndzi ta va nyika rona, va ta ri teka ri va ra vona.' },
    { n: 40, text: 'Kasi n’wina, hundzukani mi teka riendzo ra n’wina mi ya emananga hi ndlela ya Lwandle lwo Tshwuka.' },
    { n: 41, text: 'Kutani mi hlamurile, mi ku eka mina: ‘Hi dyohele Yehovha; hi ta tlhandluka hi lwa, hi ku landza hinkwaswo leswi Yehovha Xikwembu xa hina a hi leriseke swona. Kutani un’wana ni un’wana wa n’wina a tikhonza swilwi swa yena swa nyimpi, mi ehleketa leswaku swi olova ku tlhandluka entshaveni.' },
    { n: 42, text: 'Kambe Yehovha a ku eka mina: ‘Byela vona u ku: Mi nga tlhandluki, naswona mi nga lwi, hikuva a ndzi kona exikarhi ka n’wina; leswaku mi nga dlayiwi mahlweni ka valala va n’wina.' },
    { n: 43, text: 'Ndzi vulavurile na n’wina, kambe a mi yingiselanga; mi pfukele xileriso xa Yehovha, mi ya mahlweni hi ku titlakusa mi tlhandlukela entshaveni.' },
    { n: 44, text: 'Kutani Vaamori lava tshamaka entshaveni yoleyo va huma va mi hlangabeza, va mi hlongola hilaha tinyoxi ti endlaka hakona, va mi dlaya eSeiri ku ya fika eHorma.' },
    { n: 45, text: 'Kutani mi vuya mi rila mahlweni ka Yehovha; kambe Yehovha a nga yingiselanga rito ra n’wina, naswona a nga mi nyikanga ndleve.' },
    { n: 46, text: 'Kutani mi tshama eKadesi masiku yo tala, hi ku landza masiku lawa mi tshamgeke ha wona.' }
  ],
  2: [
    { n: 1, text: 'Kutani hi hundzuka, hi teka riendzo ra hina hi ya emananga hi ndlela ya Lwandle lwo Tshwuka, hilaha Yehovha a ndzi vuleleke hakona; kutani hi rhendzela Ntshava ya Seiri masiku yo tala.' },
    { n: 2, text: 'Yehovha a vulavula na mina, a ku:' },
    { n: 3, text: 'Mi rhendzele ntshava leyi nkarhi wo leha; hundzukelani hi le n’walungwini.' },
    { n: 4, text: 'Lerisa vanhu u ku: ‘Mi hundza hi le mundzilakanini wa vamakwenu, vana va Esawu, lava tshamaka eSeiri; va ta mi chava, hikwalaho tivoneleni swinene.' },
    { n: 5, text: 'Mi nga pfuxeli nyimpi na vona, hikuva a ndzi nga mi nyiki tiko ra vona hambi ku ri ndhawu leyi nenge wu kandziyaka eka yona; hikuva ndzi nyikile Esawu Ntshava ya Seiri ku va ndzhaka ya yena.' },
    { n: 6, text: 'Mi ta xava swakudya eka vona hi mali leswaku mi dya, ni mati mi ta xava eka vona hi mali leswaku mi nwa.' },
    { n: 7, text: 'Hikuva Yehovha Xikwembu xa wena u ku katekisile emisebenzeni hinkwayo ya voko ra wena; wa tiva ku famba ka wena emananga lawa lamakulu; malembe lawa ya mune-khume Yehovha Xikwembu xa wena a a ri na wena; a ku pfumalekanga nchumu.' },
    { n: 8, text: 'Kutani hi hundza ekusuhi ni vamakwerhu, vana va Esawu, lava tshamaka eSeiri, hi ndlela ya mabalani ku suka eElati ni le Esiyoni-gebere; kutani hi hundzuka hi famba hi ndlela ya mananga ya Mowabu.' },
    { n: 9, text: 'Kutani Yehovha a ku eka mina: ‘U nga xanisi Vamowabu, naswona u nga pfuxi nyimpi na vona, hikuva a ndzi nga ku nyiki ndzhaka etikweni ra vona; hikuva ndzi nyikile vana va Loti tiko ra Ari ku va ndzhaka.' },
    { n: 10, text: '(Vaemi a va tshama kona eku sunguleni, vanhu lava a va ri vakulu ni ku tala ni ku leha ku fana ni Vaenaka;' },
    { n: 11, text: 'na vona a va tekiwa va ri Varifayimi ku fana ni Vaenaka; kambe Vamowabu a va va vitana Vaemi.' },
    { n: 12, text: 'Na le Seiri ku sungule ku tshama Vahori, kambe vana va Esawu va va hlongorile, va va lovisa mahlweni ka vona, va tshama endhawini ya vona; hilaha Israyele a endleke hakona etikweni ra ndzhaka ya yena, leri Yehovha a va nyikeke rona.)' },
    { n: 13, text: 'Kutani se sukani, mi hundza nambu wa Seredi. Kutani hi hundza nambu wa Seredi.' },
    { n: 14, text: 'Kasi masiku ya ku famba ka hina ku suka eKadesi-barnea ku fika loko hi hundza nambu wa Seredi, a ku ri malembe ya makume nharhu na nharhu, ku fika loko xitukulwana hinkwaswo xa vavanuna va nyimpi xi herile exikarhi ka mixaxa, hilaha Yehovha a va hlambanyeleke hakona.' },
    { n: 15, text: 'Hakunene voko ra Yehovha a ri ri ehenhla ka vona ku va lovisa exikarhi ka mixaxa, ku fika loko va herile hinkwavo.' },
    { n: 16, text: 'Kutani ku endleka leswaku, loko vavanuna hinkwavo va nyimpi va dlayiwile va herile exikarhi ka vanhu,' },
    { n: 17, text: 'Yehovha a vulavula na mina, a ku:' },
    { n: 18, text: 'Namuntlha u ta hundza hi le mundzilakanini wa Mowabu, ku nga Ari;’' },
    { n: 19, text: 'Kutani loko u tshinela ekusuhi ni vana va Amoni, u nga va xanisi, naswona u nga lwi na vona; hikuva a ndzi nga ku nyiki ndzhaka etikweni ra vana va Amoni; hikuva ndzi ri nyikile vana va Loti ku va ndzhaka ya vona.' },
    { n: 20, text: '(Na rona a ri tekiwa ri ri tiko ra Varifayimi; Varifayimi a va tshama kona eku sunguleni, naswona Vaamoni a va va vitana Vasamsumi;' },
    { n: 21, text: 'vanhu vakulu ni ku tala ni ku leha ku fana ni Vaenaka; kambe Yehovha a va lovisa mahlweni ka vona, kutani va va hlongola, va tshama endhawini ya vona;' },
    { n: 22, text: 'hilaha a endleke hakona eka vana va Esawu, lava tshamaka eSeiri, loko a lovisa Vahori mahlweni ka vona, kutani va va hlongola va tshama endhawini ya vona ku fika namuntlha;' },
    { n: 23, text: 'ni Vaavhimi, lava a va tshama emitini ku ya fika eGaza, Vakafitori lava humeke eKaftori va va lovisile, va tshama endhawini ya vona.)' },
    { n: 24, text: 'Sukani, mi teka riendzo ra n’wina, mi hundza nambu wa Arnoni; vonani, ndzi nyiketile emandleni ya wena Sihoni, hosi ya Hesboni wa Muamori, ni tiko ra yena; sungula ku ri teka, mi endla nyimpi na yena.' },
    { n: 25, text: 'Namuntlha ndzi sungula ku tisa ku chava ni ku tsemeka mbilu ka wena ehenhla ka vanhu ehansi ka tilo hinkwaswo, lava nga ta twa mahungu ya wena, va ta tsemeka mbilu, va rhurhumela hikwalaho ka wena.' },
    { n: 26, text: 'Kutani ndzi rhuma varhumi ku suka emananga ya Kedemoti eka Sihoni, hosi ya Hesboni, hi marito ya ku rhula, ndzi ku:' },
    { n: 27, text: 'Ndzi pfumelele ku hundza hi le tikweni ra wena; ndzi ta famba hi ndlela leyikulu ntsena; a ndzi nga hambuki ku ya eximatsini kumbe exineneni.' },
    { n: 28, text: 'U ta ndzi xavisela swakudya hi mali ndzi dya, ni mati u ta ndzi nyika hi mali ndzi nwa; ntsena ndzi pfumelele ku hundza hi milenge,’ ' },
    { n: 29, text: 'hilaha vana va Esawu lava tshamaka eSeiri, ni Vamowabu lava tshamaka eAri va ndzi endleleke hakona, ku fika loko ndzi hundza Yordani ku nghena etikweni leri Yehovha Xikwembu xa hina a hi nyikaka rona.' },
    { n: 30, text: 'Kambe Sihoni, hosi ya Hesboni, a nga pfumelanga ku hi hundzisa hi le tikweni ra yena; hikuva Yehovha Xikwembu xa wena u satshise mbilu ya yena, a endla mbilu ya yena yi nononha leswaku a n’wi nyiketa emandleni ya wena, hilaha swi nga hakona namuntlha.' },
    { n: 31, text: 'Kutani Yehovha a ku eka mina: ‘Vonani, ndzi sungurile ku nyiketa Sihoni ni tiko ra yena mahlweni ka wena; sungula ku teka tiko ra yena ri va ra wena.' },
    { n: 32, text: 'Kutani Sihoni a huma ku hi hlangabeza, yena ni vanhu va yena hinkvavo, ku endla nyimpi eYahasi.' },
    { n: 33, text: 'Yehovha Xikwembu xa hina a n’wi nyiketa mahlweni ka hina; kutani hi n’wi dlaya, yena ni vana va yena ni vanhu va yena hinkvavo.' },
    { n: 34, text: 'Hi teka miti ya yena hinkwayo hi nkarhi wolowo, hi lovisa miti hinkwayo, vavanuna, vavasati ni vatsongo; a hi siyanga hambi a ri un’we loyi a poneke;' },
    { n: 35, text: 'ntsena swifuwo hi swi teka swi va swa hina, xikan’we ni swilo leswi phangiweke emitini leyi hi nga yi teka.' },
    { n: 36, text: 'Ku sukela eAroere, lowu nga eribuweni ra nambu wa Arnoni, ni muti lowu nga enkoveni, ku ya fika eGiliyadi, a ku vanga ni muti ni wun’we lowu a wu hi tikela; Yehovha Xikwembu xa hina u swi nyiketile hinkwaswo mahlweni ka hina.' },
    { n: 37, text: 'Ntsena etikweni ra vana va Amoni a mi tshinelelanga, hambi ku ri etlhelo hinkwaro ra nambu wa Yaboki, ni le mitini ya tintshava, ni hinkwako lomu Yehovha Xikwembu xa hina a hi tsimbiseke kona.' }
  ],
  3: [
    { n: 1, text: 'Kutani hi hundzuka, hi tlhandluka hi ndlela ya Basani; na Ogo, hosi ya Basani, a huma ku hi hlangabeza, yena ni vanhu va yena hinkvavo, ku endla nyimpi eEdreyi.' },
    { n: 2, text: 'Kutani Yehovha a ku eka mina: ‘U nga n’wi chavi; hikuva ndzi n’wi nyiketile emandleni ya wena, yena ni vanhu va yena hinkvavo ni tiko ra yena; naswona u ta n’wi endla hilaha u endleke hakona Sihoni, hosi ya Vaamori, loyi a a tshama eHesboni.' },
    { n: 3, text: 'Kutani Yehovha Xikwembu xa hina a nyiketa na Ogo, hosi ya Basani, ni vanhu va yena hinkvavo emandleni ya hina; hi n’wi dlaya ku fika loko ku nga ponanga hambi a ri un’we wa yena.' },
    { n: 4, text: 'Hi teka miti ya yena hinkwayo hi nkarhi wolowo; a ku vanga ni muti ni wun’we lowu hi nga faka hi nga wu tekanga eka vona, ku nga makume ntlhanu na nharhu wa miti, xifundza hinkwaswo xa Argobo, mfumo wa Ogo eBasani.' },
    { n: 5, text: 'Miti leyi hinkwayo a yi simekiwile hi makhumbi lama tlakukeke, ni tinyangwa ni swigogo; handle ka miti yo tala swinene leyi nga riki na makhumbi.' },
    { n: 6, text: 'Kutani hi swi lovisa hakunene hilaha hi endleke hakona eka Sihoni hosi ya Hesboni, hi ku lovisa muti wun’wana ni wun’wana, vavanuna, vavasati ni vatsongo.' },
    { n: 7, text: 'Kambe swifuwo hinkwaswo ni swilo leswi phangiweke emitini, hi swi tekerile hina vini.' },
    { n: 8, text: 'Kutani hi nkarhi wolowo hi teka tiko emavokweni ya tihosi timbirhi ta Vaamori lava a va ri entsungeni wa Yordani, ku sukela enambyeni wa Arnoni ku ya fika eNtshaveni ya Hermoni;' },
    { n: 9, text: '(Vatidoni va vitana Hermoni va ku i Siriyoni, kasi Vaamori va wu vitana Seniri;)' },
    { n: 10, text: 'Miti hinkwayo ya mabalani, na Giliyadi hinkwayo, na Basani hinkwayo ku ya fika eSaleka ni le Edreyi, miti ya mfumo wa Ogo eBasani.' },
    { n: 11, text: '(Hikuva i Ogo ntsena, hosi ya Basani, loyi a a sele exikarhi ka masalela ya Varifayimi; vonani, mubhedlo wa yena a a ri mubhedlo wa ntsimbi; xana a wu le Raba wa vana va Amoni? Ku leha ka wona a ku ri tixekele ta nkombo, na ku anama ka wona a ku ri tixekele ta mune, hi ku landza xekele ra munhu.)' },
    { n: 12, text: 'Kutani hi teka tiko leri ku va ndzhaka hi nkarhi wolowo; ku sukela eAroere, lowu nga enambyeni wa Arnoni, ni hafu ya tintshava ta Giliyadi ni miti ya rona, ndzi swi nyikile Varuben na Vagadi.' },
    { n: 13, text: 'Kasi masalela ya Giliyadi, na Basani hinkwayo, mfumo wa Ogo, ndzi swi nyikile hafu ya nyimba ya Manase; xifundza hinkwaswo xa Argobo xikan’we na Basani hinkwayo, leyi a yi vuriwa tiko ra Varifayimi.' },
    { n: 14, text: 'Yairi, n’wana wa Manase, a teka xifundza hinkwaswo xa Argobo ku ya fika emundzilakanini wa Vagesuri ni wa Vamakati; a tixaka tindhawu ta Basani hi vito ra yena, a ku i Havoti-yairi ku fika namuntlha.' },
    { n: 15, text: 'Kutani ndzi nyika Makiri tiko ra Giliyadi.' },
    { n: 16, text: 'Kasi Varuben ni Vagadi ndzi va nyikile ku sukela eGiliyadi ku ya fika enambyeni wa Arnoni, exikarhi ka nambu ku va ndzilakana, ku ya fika enambyeni wa Yaboki, lowu nga ndzilakana wa vana va Amoni;' },
    { n: 17, text: 'ni mabalani, ni Yordani ku va ndzilakana, ku sukela eKinereti ku ya fika eLwandleni ra mabalani, ku nga Lwandle ra Munyu, ehansi ka tindlela ta Pisga hi le vuxeni.' },
    { n: 18, text: 'Kutani ndzi mi lerisile hi nkarhi wolowo, ndzi ku: ‘Yehovha Xikwembu xa n’wina u mi nyikile tiko leri leswaku mi ri teka ri va ra n’wina; un’wana ni un’wana wa n’wina loyi a nga ni matimba u ta tikhonza swilwi a hundza mahlweni ka vamakwenu vana va Israyele.' },
    { n: 19, text: 'Ntsena vavasati va n’wina, ni vatsongo va n’wina, ni swifuwo va n’wina (ndza tiva leswaku mi ni swifuwo swo tala), va ta tshama emitini ya n’wina leyi ndzi mi nyikaka yona,’ ' },
    { n: 20, text: 'Ku fika loko Yehovha a nyika vamakwenu ku wisa, hilaha a endleke hakona eka n’wina, na vona va teka tiko leri Yehovha Xikwembu xa n’wina a va nyikaka rona entsungeni wa Yordani; kutani mi ta tlhela un’wana ni un’wana eka ndzhaka ya yena leyi ndzi mi nyikaka yona.' },
    { n: 21, text: 'Kutani ndzi lerisa Yoxuwa hi nkarhi wolowo, ndzi ku: ‘Mahlo ya wena ya vonile hinkwaswo leswi Yehovha Xikwembu xa n’wina a swi endleleke tihosi leti mambirhi; hi swona leswi Yehovha a nga ta swi endla eka mifumo hinkwayo lomu u hundzaka eka yona.' },
    { n: 22, text: 'Mi nga va chavi; hikuva Yehovha Xikwembu xa n’wina, hi yena a nga ta mi lweri.' },
    { n: 23, text: 'Kutani ndzi khongela eka Yehovha hi nkarhi wolowo, ndzi ku:' },
    { n: 24, text: 'O Yehovha Xikwembu, u sungurile ku komba nandza wa wena vukulu bya wena ni voko ra wena leri nga ni matimba; hikuva i xikwembu xihi lexi nga tilweni kumbe emisaveni lexi nga endlaka hi ku landza swilo swa wena ni hi matimba ya wena?' },
    { n: 25, text: 'Ndzi pfumelele ndzi hundza ndzi ya vona tiko leri ra kahle leri nga entsungeni wa Yordani, ntshava leyi yo saseka ni Libanoni.' },
    { n: 26, text: 'Kambe Yehovha a a ndzi hlundzukerile hikwalaho ka n’wina, a nga ndzi yingiselanga; kutani Yehovha a ku eka mina: ‘Swi ringene; u nga ha tlhveli u vulavula na mina hi mhaka leyi.' },
    { n: 27, text: 'Tlhandlukela ehenhla ka Pisga, u tlakusa mahlo ya wena hi le vupela-dyambu, ni hi le n’walungwini, ni hi le dzongeni, ni hi le vuxeni, u swi langutisa hi mahlo ya wena; hikuva u nga ka u nga hundzi Yordani lowu.' },
    { n: 28, text: 'Kambe lerisa Yoxuwa, n’wi tiyise mbilu, u n’wi nyika matimba; hikuva hi yena loyi a nga ta hundza mahlweni ka vanhu lava, naswona hi yena loyi a nga ta va avela tiko leri u nga ta ri vona.' },
    { n: 29, text: 'Kutani hi tshama enkoveni ku langutana ni Beta-peori.' }
  ],
  4: [
    { n: 1, text: 'Kutani sweswi, O Israyele, yingisela milawu ni swiboho leswi ndzi mi dyondzisaka swona ku swi endla, leswaku mi hanya, mi nghena mi teka tiko leri Yehovha, Xikwembu xa vata va n’wina, a mi nyikaka rona.' },
    { n: 2, text: 'Mi nga engeteli eka rito leri ndzi mi lerisaka rona, naswona mi nga hunguti eka rona, leswaku mi hlayisa swileriso swa Yehovha Xikwembu xa n’wina leswi ndzi mi lerisaka swona.' },
    { n: 3, text: 'Mahlo ya n’wina ya vonile leswi Yehovha a swi endleke hikwalaho ka Baala-peori; hikuva vavanuna hinkwavo lava landzeleke Baala-peori, Yehovha Xikwembu xa n’wina u va lovisile exikarhi ka n’wina;' },
    { n: 4, text: 'Kambe n’wina lava namarheleke Yehovha Xikwembu xa n’wina, mi hinkwerhu mi hanyile namuntlha.' },
    { n: 5, text: 'Vonani, ndzi mi dyondzisile milawu ni swiboho hilaha Yehovha Xikwembu xa mina a ndzi leriseke hakona, leswaku mi endla tano etikweni leri mi nghenaka eka rona ku ri teka ri va ra n’wina.' },
    { n: 6, text: 'Kutani swi hlayiseni, mi swi endla; hikuva lowu i vutlhari bya n’wina ni ku twisisa ka n’wina emihlweni ya vanhu, lava nga ta twa milawu leyi hinkwayo, va ku: ‘Hakunene tiko leri ra kahle i vanhu va vutlhari ni va ku twisisa.' },
    { n: 7, text: 'Hikuva i tiko rihi leri nga ritsongo leri nga ni swikwembu leswi nga ekusuhi na rona, ku fana ni ndlela leyi Yehovha Xikwembu xa hina a nga ekusuhi na hina hinkwako lomu hi n’wi vitanaka kona?' },
    { n: 8, text: 'Naswona i tiko rihi leri nga ritsongo leri nga ni milawu ni swiboho leswi lulameke ku fana ni nawu lowu hinkwawo lowu ndzi wu vekaka mahlweni ka n’wina namuntlha?' },
    { n: 9, text: 'Ntsena tivonele, u hlayisa moya wa wena swinene, leswaku u nga rivali swilo leswi mahlo ya wena ya swi voneke, naswona swi nga suki mbilwini ya wena masiku hinkwaswo ya vutomi bya wena; u swi tivisa vana va wena ni vana va vana va wena;' },
    { n: 10, text: 'siku leri u yimeke mahlweni ka Yehovha Xikwembu xa wena eHorebe, loko Yehovha a ku eka mina: ‘Nhlengelanisa vanhu mahlweni ka mina, ndzi va twisa marito ya mina, leswaku va dyondza ku ndzi chava masiku hinkwaswo lawa va nga ta hanya ha wona emisaveni, naswona va dyondzisa na vana va vona.' },
    { n: 11, text: 'Kutani mi tshinela, mi yima ehansi ka ntshava; ntshava a yi pfurha ndzilo ku ya fika exikarhi ka tilo, ku ri ni munyama, papa ni mumu lowukulu.' },
    { n: 12, text: 'Yehovha a vulavula na n’wina exikarhi ka ndzilo; mi twe rito ra marito, kambe a mi vonanga xivumbeko; ku ri ni rito ntsena.' },
    { n: 13, text: 'A mi tivisa ntwanano wa yena, lowu a mi leriseke ku wu endla, ku nga milawu ya khume; kutani a yi tsala ematleleni mambirhi ya maribye.' },
    { n: 14, text: 'Kutani Yehovha a ndzi lerisa hi nkarhi wolowo ku mi dyondzisa milawu ni swiboho, leswaku mi swi endla etikweni leri mi hundzaka ku ya ri teka ri va ra n’wina.' },
    { n: 15, text: 'Kutani hlayisani mimoya ya n’wina swinene, hikuva a mi vonanga xivumbeko ni xin’we hi siku leri Yehovha a vulavuleke na n’wina eHorebe exikarhi ka ndzilo;' },
    { n: 16, text: 'leswaku mi nga tinyamisi, mi tiendlela xifaniso lexi gundziweke xa xivumbeko xa muxaka wun’wana ni wun’wana, xifaniso xa wanuna kumbe xa wansati,' },
    { n: 17, text: 'xifaniso xa xiharhi xihi ni xihi lexi nga emisaveni, xifaniso xa xinyenyana xihi ni xihi lexi tlhukaka ahandle emoyeni,' },
    { n: 18, text: 'xifaniso xa nchumu xihi ni xihi lexi fambaka ehansi, xifaniso xa nhlampfi yihi ni xihi leyi nga ematini ehansi ka misava;' },
    { n: 19, text: 'naswona leswaku u nga tlakusi mahlo ya wena etilweni, u vona dyambu, ni n’weti, ni tinyeleti, mavuthu hinkwaswo ya tilo, u kuceteleka ku swi gandzela ni ku swi tirhela, swilo leswi Yehovha Xikwembu xa wena a swi aveleke vanhu hinkvavo ehansi ka tilo hinkwaswo.' },
    { n: 20, text: 'Kambe Yehovha u mi tekile, a mi humesa ekheleni ra ntsimbi, eEgipta, leswaku mi va vanhu va ndzhaka ya yena, hilaha swi nga hakona namuntlha.' },
    { n: 21, text: 'Na mina Yehovha u ndzi hlundzukerile hikwalaho ka n’wina, a hlambanya leswaku a ndzi nga hundzi Yordani, naswona a ndzi nga ngheni etikweni ra kahle leri Yehovha Xikwembu xa wena a ku nyikaka rona ku va ndzhaka;' },
    { n: 22, text: 'hikuva ndzi fanele ku fela etikweni leri, a ndzi nga hundzi Yordani; kambe n’wina mi ta hundza, mi teka tiko leri ra kahle.' },
    { n: 23, text: 'Tivoneleni leswaku mi nga rivali ntwanano wa Yehovha Xikwembu xa n’wina, lowu a wu endleke na n’wina, mi tiendlela xifaniso lexi gundziweke xa xivumbeko xa nchumu xihi ni xihi lexi Yehovha Xikwembu xa wena a ku tsimbiseke xona.' },
    { n: 24, text: 'Hikuva Yehovha Xikwembu xa wena i ndzilo lowu dlayaka, i Xikwembu lexi lavaka ku tinyiketela loku hlayisekeke.' },
    { n: 25, text: 'Loko mi ta va mi tswele vana ni vana va vana, naswona mi tshamile nkarhi wo leha etikweni, mi tinyamisa, mi endla xifaniso lexi gundziweke xa xivumbeko xa nchumu xihi ni xihi, mi endla swo biha emihlweni ya Yehovha Xikwembu xa n’wina, ku n’wi nyurhisa;' },
    { n: 26, text: 'ndzi teka tilo ni misava ku va timbhoni ehenhla ka n’wina namuntlha leswaku mi ta lova hi ku hatlisa etikweni leri mi hundzaka Yordani ku ya ri teka; mi nga ka mi nga tshamisi masiku yo tala eka rona, hikuva mi ta lovisiwa hakunene.' },
    { n: 27, text: 'Yehovha u ta mi hangalasela exikarhi ka vanhu, naswona mi ta sala mi ri vatsongo exikarhi ka matiko lomu Yehovha a nga ta mi fambisela kona.' },
    { n: 28, text: 'Kona mi ta tirhela swikwembu leswi endliweke hi mavoko ya vanhu, swa ntsandza ni ribye, leswi nga voniki, leswi nga twiki, leswi nga dyiki, naswona leswi nga nuhiki.' },
    { n: 29, text: 'Kambe loko u lavisela Yehovha Xikwembu xa wena u ri kona, u ta n’wi kuma, loko u n’wi lava hi mbilu ya wena hinkwayo ni hi moya wa wena hinkwayo.' },
    { n: 30, text: 'Loko u ri enhlomulweni, naswona swilo leswi hinkwaswo swi ku fikeleke emasikwini yo hetelela, u ta vuyela eka Yehovha Xikwembu xa wena, u yingisela rito ra yena;' },
    { n: 31, text: '(hikuva Yehovha Xikwembu xa wena i Xikwembu xa tintswalo;) a nga ka a nga ku tshiki, naswona a nga ka a nga ku lovisi, hambi ku ri ku rivala ntwanano wa vata va wena lowu a nga hlambanya eka vona.' },
    { n: 32, text: 'Hikuva vutisa sweswi hi masiku ya khale, lawa a ma ri mahlweni ka wena ku sukela hi siku leri Xikwembu xi nga tumbuluxa munhu emisaveni, ni ku sukela emakumu man’wana ya tilo ku ya emakumu man’wana ya rona, xana ku endlekile nchumu wo fana ni lowu lowukulu, kumbe ku twakele lowu fana na wona?' },
    { n: 33, text: 'Xana va kona vanhu lava nga twa rito ra Xikwembu xi vulavula exikarhi ka ndzilo, hilaha u tweke hakona, kutani va hanya?' },
    { n: 34, text: 'Kumbe xana Xikwembu xi tshukile xi ringeta ku ya tiendlela tiko exikarhi ka tiko rin’wana, hi mindzhingo, ni hi swikombiso, ni hi swihlamariso, ni hi nyimpi, ni hi voko leri nga ni matimba, ni hi voko leri extended, ni hi ku chavisa lokukulu, hilaha Yehovha Xikwembu xa n’wina a mi endleleke hakona eEgipta mahlweni ka mahlo ya wena?' },
    { n: 35, text: 'Wena u kombiwile leswaku u tiva leswaku Yehovha hi yena Xikwembu; ku hava un’wana handle ka yena.' },
    { n: 36, text: 'Ku suka etilweni u ku twisile rito ra yena leswaku a ku lulamisa; naswona emisaveni u ku kombisile ndzilo wa yena lowukulu, naswona u twe marito ya yena exikarhi ka ndzilo.' },
    { n: 37, text: 'Naswona hi ku va a rhandzile vata va wena, a hlawula ni vana va vona endzhaku ka vona, a ku humesa hi xivumbeko xa yena, hi matimba ya yena lamakulu eEgipta;' },
    { n: 38, text: 'Ku hlongola matiko makulu ni lama nga ni matimba ku hundza wena mahlweni ka wena, ku ku nghenisa, ku ku nyika tiko ra vona ku va ndzhaka, hilaha swi nga hakona namuntlha.' },
    { n: 39, text: 'Tiva namuntlha, u veka mbilwini ya wena leswaku Yehovha hi yena Xikwembu etilweni ehenhla ni le misaveni ehansi; ku hava un’wana.' },
    { n: 40, text: 'Kutani u hlayisa milawu ya yena ni swileriso ya yena leswi ndzi ku lerisaka swona namuntlha, leswaku swi ku fambela kahle, wena ni vana va wena endzhaku ka wena, naswona u tshamisa masiku yo tala etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona hilaha ku nga heriki.' },
    { n: 41, text: 'Kutani Moxe a hlawula miti ya nharhu entsungeni wa Yordani hi le vuxeni, eku humeni ka dyambu;' },
    { n: 42, text: 'leswaku mudlayi a nga balekela kona, loyi a nga dlaya munhuxakulobye hi xihoxo, a nga n’wi venganga mahlweni; a nga balekela eka wun’wana wa miti leyi kutani a hanya:' },
    { n: 43, text: 'Besere emananga, emabalani, ya Varuben; na Ramoti eGiliyadi, ya Vagadi; na Golani eBasani, ya Vamanase.' },
    { n: 44, text: 'Lowu hi wona nawu lowu Moxe a wu vekeke mahlweni ka vana va Israyele;' },
    { n: 45, text: 'leti hi tona timbhoni, ni milawu, ni swiboho leswi Moxe a swi vuleke eka vana va Israyele loko va humile eEgipta;' },
    { n: 46, text: 'entsungeni wa Yordani, enkoveni ku langutana ni Beta-peori, etikweni ra Sihoni, hosi ya Vaamori, loyi a a tshama eHesboni, loyi Moxe ni vana va Israyele va n’wi dlayeke loko va humile eEgipta;' },
    { n: 47, text: 'Kutani va teka tiko ra yena ri va ra vona, ni tiko ra Ogo, hosi ya Basani, tihosi timbirhi ta Vaamori, lava a va ri entsungeni wa Yordani hi le vuxeni, eku humeni ka dyambu;' },
    { n: 48, text: 'Ku sukela eAroere, lowu nga eribuweni ra nambu wa Arnoni, ku ya fika eNtshaveni ya Siyoni, ku nga Hermoni;' },
    { n: 49, text: 'ni mabalani hinkwaswo entsungeni wa Yordani hi le vuxeni, ku ya fika eLwandleni ra mabalani, ehansi ka tindlela ta Pisga.' }
  ],
  5: [
    { n: 1, text: 'Moxe a vitana Israyele hinkwayo, a ku eka vona: Yingiselani, O Israyele, milawu ni swiboho leswi ndzi mi byelaka swona namuntlha, mi swi dyondza, mi tiyisela ku swi endla.' },
    { n: 2, text: 'Yehovha Xikwembu xa hina u endle ntwanano na hina eHorebe.' },
    { n: 3, text: 'Yehovha a nga endlanga ntwanano lowu ni vata va hina ntsena, kambe u wu endle na hina, hina hinkwerhu lava hanyaka namuntlha lahha.' },
    { n: 4, text: 'Yehovha u vulavurile na n’wina hi ku kongoma entshaveni, exikarhi ka ndzilo.' },
    { n: 5, text: '(Ndzi yimile exikarhi ka Yehovha na n’wina hi nkarhi wolowo ku mi byela rito ra Yehovha; hikuva a mi chava ndzilo, naswona a mi tlhandlukanga entshaveni,) a ku:' },
    { n: 6, text: 'Hi mina Yehovha Xikwembu xa wena, loyi a ku humeseke etikweni ra Egipta, endlwini ya vuhlonga.' },
    { n: 7, text: 'U nga tshuki u va ni swikwembu swin’wana mahlweni ka mina.' },
    { n: 8, text: 'U nga tiendleli xifaniso lexi gundziweke, hambi ku ri xivumbeko xa nchumu xihi ni xihi lexi nga etilweni ehenhla, kumbe lexi nga emisaveni ehansi, kumbe lexi nga ematini ehansi ka misava.' },
    { n: 9, text: 'U nga swi khinsameli, naswona u nga swi tirheli; hikuva mina, Yehovha Xikwembu xa wena, ndzi Xikwembu lexi lavaka ku tinyiketela loku hlayisekeke, lexi xanisaka vana hikwalaho ka vuhlayiseki byo biha bya vata va vona, ku ya fika eka xitukulwana xa vunharhu ni xa vumune xa lava ndzi vengaka,' },
    { n: 10, text: 'Kambe ndzi komba rirhandzu leri nga heriki eka gidi ra swiyenge swa lava ndzi rhandzaka ni lava hlayisaka swileriso swa mina.' },
    { n: 11, text: 'U nga tshuki u vitana vito ra Yehovha Xikwembu xa wena hi ndlela yo pfumala xichavo; hikuva Yehovha a nga ka a nga n’wi pfumali nandzu loyi a vitanaka vito ra yena hi ndlela yo pfumala xichavo.' },
    { n: 12, text: 'Hlayisa siku ra Savata u ri hlawula, hilaha Yehovha Xikwembu xa wena a ku leriseke hakona.' },
    { n: 13, text: 'U ta tirha masiku ya tsevu, u endla ntirho wa wena hinkwaro;' },
    { n: 14, text: 'Kambe siku ra vuntsumbuye i Savata ra Yehovha Xikwembu xa wena; u nga tshuki u endla ntirho ni wun’we eka rona, wena, kumbe n’wana wa wena wa jaha, kumbe n’wana wa wena wa nhwanyana, kumbe nandza wa wena wa xinuna, kumbe nandza wa wena wa xisati, kumbe nkuzi ya wena, kumbe mbhongolo ya wena, kumbe xifuwo xa wena ni xin’we, kumbe muhluri loyi a nga endzeni ka tinyangwa ta wena; leswaku nandza wa wena wa xinuna ni wa xisati a wisa ku fana na wena.' },
    { n: 15, text: 'Tsundzuka leswaku u we u ri hlonga etikweni ra Egipta, ni leswaku Yehovha Xikwembu xa wena u ku humesile kona hi voko leri nga ni matimba ni hi voko leri extended; hikwalaho Yehovha Xikwembu xa wena u ku lerisile ku hlayisa siku ra Savata.' },
    { n: 16, text: 'Xichava tata wa wena ni mhana wena, hilaha Yehovha Xikwembu xa wena a ku leriseke hakona; leswaku masiku ya wena ya lehisiwa, ni leswaku swi ku fambela kahle etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona.' },
    { n: 17, text: 'U nga tshuki u dlaya.' },
    { n: 18, text: 'U nga tshuki u oswa.' },
    { n: 19, text: 'U nga tshuki u yiva.' },
    { n: 20, text: '<b>‘U nga tshuki u hemba hi mhaka ya munhuxakulobye.</b>' },
    { n: 21, text: 'U nga tshuki u navela nsati wa munhuxakulobye; naswona u nga tshuki u navela yindlu ya munhuxakulobye, tiko ra yena, kumbe nandza wa yena wa xinuna, kumbe nandza wa yena wa xisati, kumbe nkuzi ya wena, kumbe mbhongolo ya wena, hambi ku ri nchumu xihi ni xihi lexi nga xa munhuxakulobye.' },
    { n: 22, text: 'Marito lawa Yehovha u ma vuleke eka nhlengeletano hinkwayo ya n’wina entshaveni, exikarhi ka ndzilo, papa ni mumu lowukulu, hi rito leri tlakukeke; a nga engetelanga nchumu. Kutani a ma tsala ematleleni mambirhi ya maribye, a ndzi nyika wona.' },
    { n: 23, text: 'Kutekeka loko mi twa rito exikarhi ka munyama, ntshava yi ri karhi yi pfurha ndzilo, mi tshinela eka mina, tinhloko hinkwato ta tinyimba ta n’wina ni vakulukumba va n’wina;' },
    { n: 24, text: 'Mi ku: ‘Vonani, Yehovha Xikwembu xa hina u hi kombisile vukulu bya yena ni ku kwetsima ka yena, naswona hi twe rito ra yena exikarhi ka ndzilo; namuntlha hi vone leswaku Xikwembu xi vulavula ni munhu, kambe u ya mahlweni a hanya.' },
    { n: 25, text: 'Kutani sweswi, hikwalaho ka yini hi fanele ku fela? Hikuva ndzilo lowu lowukulu wu ta hi lovisa; loko ho tlhela hi twa rito ra Yehovha Xikwembu xa hina, hakunene hi ta fa.' },
    { n: 26, text: 'Hikuva i mani eka hinkwavo va nyama loyi a tweke rito ra Xikwembu lexi hanyaka xi vulavula exikarhi ka ndzilo, ku fana na hina, kutani a hanya?' },
    { n: 27, text: 'Tshinela wena, u yingisela hinkwaswo leswi Yehovha Xikwembu xa hina a nga ta swi vula; kutani u hi byela hinkwaswo leswi Yehovha Xikwembu xa hina a nga ta ku byela swona; hi ta yingisela, hi swi endla.' },
    { n: 28, text: 'Yehovha a twa rito ra marito ya n’wina, loko mi vulavula na mina; kutani Yehovha a ku eka mina: ‘Ndzi twile rito ra marito ya vanhu lava, lawa va ku byeleke wona; hinkwaswo leswi va swi vuleke i swinene.' },
    { n: 29, text: 'Ah, loko mbilu ya vona a yi ta va tano masiku hinkwaswo, ku ndzi chava ni ku hlayisa swileriso hinkwaswo swa mina, leswaku swi va fambela kahle, vona ni vana va vona hilaha ku nga heriki!' },
    { n: 30, text: 'Famba, u va byela u ku: Tlelani ematendeni ya n’wina.' },
    { n: 31, text: 'Kasi wena, yima lahha na mina, ndzi ta ku byela swileriso hinkwaswo, ni milawu, ni swiboho leswi u nga ta va dyondzisa swona, leswaku va swi endla etikweni leri ndzi va nyikaka rona leswaku va ri dya ndzhaka.' },
    { n: 32, text: 'Kutani hlayisani ku endla hilaha Yehovha Xikwembu xa n’wina a mi leriseke hakona; mi nga hambuki ku ya exineneni kumbe eximatsini.' },
    { n: 33, text: 'Mi fanele ku famba emandleleni hinkwayo lawa Yehovha Xikwembu xa n’wina a mi leriseke wona, leswaku mi hanya, ni leswaku swi mi fambela kahle, ni leswaku mi tshamisa masiku yo tala etikweni leri mi nga ta ri dya ndzhaka.' }
  ],
  6: [
    { n: 1, text: 'Kutekeka lawa i swileriso, ni milawu, ni swiboho leswi Yehovha Xikwembu xa n’wina a ndzi leriseke ku mi dyondzisa swona, leswaku mi swi endla etikweni leri mi hundzaka ku ya ri teka;' },
    { n: 2, text: 'leswaku u chava Yehovha Xikwembu xa wena, u hlayisa milawu ya yena hinkwayo ni swileriso ya yena leswi ndzi ku lerisaka swona, wena, ni n’wana wa wena, ni n’wana wa n’wana wa wena, masiku hinkwaswo ya vutomi bya wena, leswaku masiku ya wena ya lehisiwa.' },
    { n: 3, text: 'Yingisela, O Israyele, u hlayisa ku swi endla, leswaku swi ku fambela kahle, ni leswaku mi tala swinene etikweni leri khulukaka ntswamba ni vulombe, hilaha Yehovha, Xikwembu xa vata va wena, a ku tshembiseke hakona.' },
    { n: 4, text: 'Yingisela, O Israyele: Yehovha Xikwembu xa hina, i Yehovha un’we ntsena.' },
    { n: 5, text: 'Rhandza Yehovha Xikwembu xa wena hi mbilu ya wena hinkwayo, ni hi moya wa wena hinkwayo, ni hi matimba ya wena hinkwayo.' },
    { n: 6, text: 'Marito lawa ndzi ku lerisaka wona namuntlha ya fanele ku va embilwini ya wena;' },
    { n: 7, text: 'U ta ma dyondzisa vana va wena hi ku hiseka, u vulavula ha wona loko u tshama endlwini ya wena, ni loko u famba endleleni, ni loko u etlela, ni loko u pfuka.' },
    { n: 8, text: 'U ta ma boha ma va xikombiso evokweni ra wena, naswona ya ta va xisirhelelo exikarhi ka mahlo ya wena;' },
    { n: 9, text: 'U ta ma tsala na le timbambeni ta yindlu ya wena ni le tinyangweni ta wena.' },
    { n: 10, text: 'Kutani swi ta endleka leswaku, loko Yehovha Xikwembu xa wena a ku nghenisile etikweni leri a nga hlambanya eka vata va wena, eka Abrahama, Isaka na Yakobo, ku ku nyika rona, miti yikulu ni yo saseka leyi u nga yi simekangiki;' },
    { n: 11, text: 'ni tiyindlu leti teleke swilo hinkwaswo swaswinene leswi u nga swi hlengeletangiki, ni swihlovo leswi keriweke leswi u nga swi kelangiki, ni masimu ya vhinyo ni maoliva lawa u nga ma rimangiki; kutani u dya u xurha;' },
    { n: 12, text: 'Tivonele leswaku u nga rivali Yehovha, loyi a ku humeseke etikweni ra Egipta, endlwini ya vuhlonga.' },
    { n: 13, text: 'Chava Yehovha Xikwembu xa wena, u n’wi tirhela, naswona u hlambanya hi vito ra yena ntsena.' },
    { n: 14, text: 'Mi nga landzeli swikwembu swin’wana, swikwembu swa vanhu lava mi rhendzeleke;' },
    { n: 15, text: '(hikuva Yehovha Xikwembu xa wena loyi a nga exikarhi ka wena i Xikwembu lexi lavaka ku tinyiketela loku hlayisekeke;) hikuva vukari bya Yehovha Xikwembu xa wena byi nga ku pfurhela, a ku herisa ehenhla ka misava.' },
    { n: 16, text: 'Mi nga tshuki mi ringa Yehovha Xikwembu xa n’wina, hilaha mi n’wi ringeke hakona eMasa.' },
    { n: 17, text: 'Hlayisani swileriso swa Yehovha Xikwembu xa n’wina hi ku hiseka, ni timbhoni ta yena, ni milawu ya yena leswi a mi leriseke swona.' },
    { n: 18, text: 'U ta endla leswi lulameke ni leswaswinene emihlweni ya Yehovha, leswaku swi ku fambela kahle, u nghena u teka tiko leri ra kahle leri Yehovha a nga hlambanya eka vata va wena;' },
    { n: 19, text: 'hi ku hlongola valala va wena hinkvavo mahlweni ka wena, hilaha Yehovha a vuleke hakona.' },
    { n: 20, text: 'Loko n’wana wa wena a ku vutisa enkarhini lowu taka, a ku: ‘Xana swi vula yini timbhoni le ti, ni milawu, ni swiboho leswi Yehovha Xikwembu xa hina a mi leriseke swona?' },
    { n: 21, text: 'Kutani u ta byela n’wana wa wena u ku: ‘A hi ri mahlonga ya Faro eEgipta; kutani Yehovha a hi humesa eEgipta hi voko leri nga ni matimba;' },
    { n: 22, text: 'Yehovha u kombisile swikombiso ni swihlamariso swo tala ni swo chavisa ehenhla ka Egipta, Faro ni yindlu ya yena hinkwayo, mahlweni ka mahlo ya hina;' },
    { n: 23, text: 'Kutani a hi humesa kona leswaku a hi tisa lahha, ku hi nyika tiko leri a nga hlambanya eka vata va hina.' },
    { n: 24, text: 'Kutani Yehovha u hi lerisile ku endla milawu leyi hinkwayo, ku chava Yehovha Xikwembu xa hina, leswaku swi hi fambela kahle masiku hinkwaswo, ku hi hanyisa hilaha swi nga hakona namuntlha.' },
    { n: 25, text: 'Kutani ku ta va ku lulama ka hina, loko hi hlayisa ku endla swileriso leswi hinkwaswo mahlweni ka Yehovha Xikwembu xa hina, hilaha a hi leriseke hakona.' }
  ],
  7: [
    { n: 1, text: 'Loko Yehovha Xikwembu xa wena a ku nghenisile etikweni leri u yaka eka rona ku ri teka, a hlongorile matiko yo tala mahlweni ka wena, Vahete, Vagirgasi, Vaamori, Vakanana, Vapekezi, Vahivi ni Vayebusi, matiko ya ntlhanu na mambirhi lama nga makulu ni ku ku hundza hi matimba;' },
    { n: 2, text: 'naswona loko Yehovha Xikwembu xa wena a va nyiketile emandleni ya wena, u va dlaya; u fanele ku va lovisa hi ku helela; u nga tshuki u endla ntwanano na vona, naswona u nga va kombi tintswalo;' },
    { n: 3, text: 'U nga tshuki u tekana na vona; n’wana wa wena wa nhwanyana u nga n’wi nyiki n’wana wa yena wa jaha, naswona n’wana wa yena wa nhwanyana u nga n’wi tekeli n’wana wa wena wa jaha;' },
    { n: 4, text: 'hikuva va ta hambukisa vana va wena ku ndzi landzela, va tirhela swikwembu swin’wana; kutani vukari bya Yehovha byi ta mi pfurhela, a mi lovisa hi ku hatlisa.' },
    { n: 5, text: 'Kambe mi ta va endla leswi: mi ta thlava tialtari ta vona, mi thleketla ni tiyindlu ta vona ta maribye, mi tsema ni timhandzi ta vona to kwetsima, mi hisa ni swifaniso swa vona leswi gundziweke hi ndzilo.' },
    { n: 6, text: 'Hikuva u vanhu va ku hlawuleka eka Yehovha Xikwembu xa wena; Yehovha Xikwembu xa wena u ku hlawurile leswaku u va vanhu va yena n’winyi exikarhi ka vanhu hinkvavo lava nga ehenhla ka misava.' },
    { n: 7, text: 'Yehovha a nga mi rhandzanga ni ku mi hlawula hikwalaho ka ku va mi ri va tala ku hundza vanhu van’wana hinkvavo, hikuva a mi ri vatsongo swinene exikarhi ka vanhu hinkvavo;' },
    { n: 8, text: 'Kambe hikwalaho ka ku va Yehovha a mi rhandzile, ni ku hlayisa hlambanyo lowu a nga hlambanya eka vata va n’wina, Yehovha u mi humesile hi voko leri nga ni matimba, a mi n’wi kutsula endlwini ya vuhlonga, emandleni ya Faro hosi ya Egipta.' },
    { n: 9, text: 'Tiva leswaku Yehovha Xikwembu xa wena hi yena Xikwembu, Xikwembu xo tshembeka, lexi hlayisaka ntwanano ni rirhandzu leri nga heriki ku ya fika eka gidi ra swiyenge swa lava n’wi rhandzaka ni lava hlayisaka swileriso swa yena;' },
    { n: 10, text: 'Kambe u hakula eka loyi a n’wi vengaka hi ku n’wi lovisa hi ku tiva; a nga ka a nga hlweli ku hakula loyi a n’wi vengaka, u ta n’wi hakula hi ku tiva.' },
    { n: 11, text: 'Kutani u ta hlayisa swileriso, ni milawu, ni swiboho leswi ndzi ku lerisaka swona namuntlha ku swi endla.' },
    { n: 12, text: 'Kutani swi ta endleka leswaku, loko mi yingisela swiboho leswi, mi swi hlayisa ni ku swi endla, Yehovha Xikwembu xa wena u ta ku hlayisela ntwanano ni rirhandzu leri nga heriki leri a nga hlambanya eka vata va wena;' },
    { n: 13, text: 'U ta ku rhandza, a ku katekisa ni ku ku tswalisa; u ta katekisa na mihandzu ya mbilu ya wena ni mihandzu ya tiko ra wena, mavele ya wena, ni vhinyo ya wena leyintshwa, ni mafurha ya wena, ku tswaleka ka tihomu ta wena ni swifuwo swa wena switsongo, etikweni leri a nga hlambanya eka vata va wena ku ku nyika rona.' },
    { n: 14, text: 'U ta katekisiwa ku hundza vanhu hinkvavo; a ku nga vi na wanuna kumbe wansati wa timba exikarhi ka wena, hambi ku ri exikarhi ka swifuwo va wena.' },
    { n: 15, text: 'Yehovha u ta susa vuvabyi hinkwaswo eka wena; naswona a nga ka a nga ku nghenisi vuvabyi hinkwaswo byo biha bya Egipta, lebyi u byi tivaka, kambe u ta byi tisa ehenhla ka hinkvavo lava ku vengaka.' },
    { n: 16, text: 'U ta dlayisa vanhu hinkvavo lava Yehovha Xikwembu xa wena a nga ta va nyiketa eka wena; jiso ra wena ri nga va tsetseleli; naswona u nga tirheli swikwembu swa vona, hikuva swolewo swi ta va ntlhamu eka wena.' },
    { n: 17, text: 'Loko u nga ku embilwini ya wena: ‘Matiko lawa i makulu ku hundza mina; ndzi nga va hlongorisa kuvhani?' },
    { n: 18, text: 'U nga va chavi; tsundzuka swinene leswi Yehovha Xikwembu xa wena a swi endleke eka Faro ni le ka Egipta hinkwayo;' },
    { n: 19, text: 'swikombiso swakulu leswi mahlo ya wena ya swi voneke, ni swihlamariso, ni voko leri nga ni matimba, ni voko leri extended, leyi Yehovha Xikwembu xa wena a ku humeseke ha yona; hi swona leswi Yehovha Xikwembu xa wena a nga ta swi endla eka vanhu hinkvavo lava u va chavaka.' },
    { n: 20, text: 'Naswona Yehovha Xikwembu xa wena u ta rhumela mahlalela exikarhi ka vona, ku fika loko lava seleke ni lava tihleleke mahlweni ka wena va herile.' },
    { n: 21, text: 'U nga chavi mahlweni ka vona; hikuva Yehovha Xikwembu xa wena loyi a nga exikarhi ka wena i Xikwembu lexikulu ni xo chavisa.' },
    { n: 22, text: 'Yehovha Xikwembu xa wena u ta hlongola matiko lawa mahlweni ka wena kanyana-kanyana; u nga ka u nga koti ku va herisa hi ku hatlisa, leswaku swiharhi swa nhova swi nga tali swinene ku ku lwa.' },
    { n: 23, text: 'Kambe Yehovha Xikwembu xa wena u ta va nyiketa mahlweni ka wena, a va tsemela mbilu hi ku hlangana lokukulu, ku fika loko va herile.' },
    { n: 24, text: 'U ta nyiketa ni tihosi ta vona emandleni ya wena, naswona u ta herisa vito ra tona ehansi ka tilo; ku hava un’we loyi a nga ta yima mahlweni ka wena, ku fika loko u va lovisile.' },
    { n: 25, text: 'Mi ta hisa swifaniso swa vona leswi gundziweke swa swikwembu swa vona hi ndzilo; u nga tshuki u navela silivhere kumbe nsuku lowu nga eka swona, hambi ku ri ku wu teka, leswaku u nga phasiwi hi wona; hikuva i nchumu lowu nyenyetsaka eka Yehovha Xikwembu xa wena.' },
    { n: 26, text: 'Naswona u nga tshuki u nghenisa nchumu lowu nyenyetsaka endlwini ya wena, u endla leswaku u va nchumu lowu herisiwaka ku fana na wona; u fanele ku wu nyenya hi ku helela ni ku wu sola hi mbilu hinkwayo, hikuva i nchumu lowu fanelaka ku herisiwa.' }
  ],
  8: [
    { n: 1, text: 'Swileriso hinkwaswo leswi ndzi ku lerisaka swona namuntlha, mi ta hlayisa ku swi endla, leswaku mi hanya, mi tala, mi nghena mi teka tiko leri Yehovha a nga hlambanya eka vata va n’wina.' },
    { n: 2, text: 'U ta tsundzuka ndlela hinkwayo leyi Yehovha Xikwembu xa wena a ku fambiseke ha yona malembe lawa ya mune-khume emananga, ku ku tsongahata, ku ku ringa leswaku a tiva leswi nga embilwini ya wena, xana u ta hlayisa swileriso swa yena kumbe e-e.' },
    { n: 3, text: 'Kutani u ku tsongahatile, a ku tisa hi ndlala, a ku phamela hi mana leyi u nga yi tiviki, ni vata va wena a va nga yi tivi; leswaku a ku tivisa leswaku munhu a nga hanyiswi hi vuswa ntsena, kambe u hanya hi rito rin’wana ni rin’wana leri humaka enon’wini wa Yehovha.' },
    { n: 4, text: 'Singu ra wena a ri hlakalanga ehenhla ka wena, naswona nenge wa wena a wu vimbanga malembe lawa ya mune-khume.' },
    { n: 5, text: 'Tiva embilwini ya wena leswaku, hilaha tatana a lulamisaka n’wana wa yena hakona, Yehovha Xikwembu xa wena u ku lulamisile tano.' },
    { n: 6, text: 'Kutani u ta hlayisa swileriso swa Yehovha Xikwembu xa wena, u famba emandleleni ya yena ni ku n’wi chava.' },
    { n: 7, text: 'Hikuva Yehovha Xikwembu xa wena u ku nghenisa etikweni rinene, tiko ra milambu ya mati, ni swihlovo, ni tiva leti khulukaka emikoveni ni le tintshaveni;' },
    { n: 8, text: 'Tiko ra koroni ni maxalana, ni rirhandzu ra vhinyo, ni makuwa ni magranada; tiko ra maoliva ni vulombe;' },
    { n: 9, text: 'Tiko leri u nga ta dya vuswa eka rona hi ku pfumala ku sihalala, u nga nga pfumali nchumu eka rona; tiko leri maribye ya rona ya nga ntsimbi, naswona etintshaveni ya rona u nga ta kela mukgako.' },
    { n: 10, text: 'Kutani u ta dya, u xurha, u katekisa Yehovha Xikwembu xa wena hikwalaho ka tiko rinene leri a ku nyikeke rona.' },
    { n: 11, text: 'Tivoneleni leswaku mi nga rivali Yehovha Xikwembu xa n’wina, hi ku tsandzeka ku hlayisa swileriso swa yena, ni swiboho swa yena, ni milawu ya yena leswi ndzi mi lerisaka swona namuntlha;' },
    { n: 12, text: 'leswaku loko u dyile u xurha, u simekile na tiyindlu to saseka, u tshama eka tona;' },
    { n: 13, text: 'ni tihomu ta wena, ni swifuwo swa wena switsongo loko swi talile, ni silivhere ya wena, ni nsuku wa wena loko swi talile, ni hinkwaswo leswi u nga na swona loko swi engetelekile;' },
    { n: 14, text: 'Mbilu ya wena yi nga tshuki yi titlakusa, u rivali Yehovha Xikwembu xa wena, loyi a ku humeseke etikweni ra Egipta, endlwini ya vuhlonga;' },
    { n: 15, text: 'loyi a ku fambiseke emananga lawa lamakulu ni yo chavisa, exikarhi ka tinyoka leti pfurhaka ni swipame, ni le ndhawu yo pfumala mati lomu ku nga riki na mati; loyi a ku humeseleke mati eribyeni ra mukhukhulo;' },
    { n: 16, text: 'loyi a ku phameleke hi mana emananga, leyi vata va wena va nga yi tiviki, leswaku a ku tsongahata, ni leswaku a ku ringa, leswaku a ku endlela leswaswinene emakumu;' },
    { n: 17, text: 'naswona u nga tshuki u ku embilwini ya wena: ‘Matimba ya mina ni ku hlangana ka voko ra mina hi swona swi ndzi endleleke rifuwo leri.' },
    { n: 18, text: 'Kambe u ta tsundzuka Yehovha Xikwembu xa wena, hikuva hi yena loyi a ku nyikaka matimba yo endla rifuwo, leswaku a simeka ntwanano wa yena lowu a nga hlambanya eka vata va wena, hilaha swi nga hakona namuntlha.' },
    { n: 19, text: 'Kutani swi ta endleka leswaku, loko ho rivala Yehovha Xikwembu xa wena, mi landzela swikwembu swin’wana, mi swi tirhela ni ku swi khinsameli, ndzi teka tilo ni misava ku va timbhoni ehenhla ka n’wina namuntlha leswaku mi ta lova hakunene.' },
    { n: 20, text: 'Ku fana ni matiko lawa Yehovha a ma lovisaka mahlweni ka n’wina, na n’wina mi ta lova tano, hikwalaho ka ku va mi nga yingiselanga rito ra Yehovha Xikwembu xa n’wina.' }
  ],
  9: [
    { n: 1, text: 'Yingisela, O Israyele: Namuntlha u tsemakanya Yordani ku nghena u teka matiko lamakulu ni ya matimba ku ku hundza, miti leyikulu leyi tiyisiweke ku fika etilweni;' },
    { n: 2, text: 'vanhu lava kulu ni vo leha, vana va Vaenaka, lava u va tivaka, ni lava u tweke ku vuriwa ha vona ku tsariwa: ‘I mani loyi a nga yimaka mahlweni ka vana va Enaka?' },
    { n: 3, text: 'Tiva namuntlha leswaku Yehovha Xikwembu xa wena hi yena loyi a tsemakanyaka mahlweni ka wena a ri ndzilo lowu lovisaka; u ta va herisa, a va tsongahata mahlweni ka wena; kutani u ta va hlongola u va lovisa hi ku hatlisa, hilaha Yehovha a ku byeleke hakona.' },
    { n: 4, text: 'U nga tshuki u ku embilwini ya wena, loko Yehovha Xikwembu xa wena a va hlongorile mahlweni ka wena: ‘Hikwalaho ka ku lulama ka mina Yehovha u ndzi nghenisile ku dya ndzhaka ya tiko leri; kasi i hikwalaho ka ku homboloka ka matiko lawa Yehovha a ma hlongolaka mahlweni ka wena.' },
    { n: 5, text: 'A hi hikwalaho ka ku lulama ka wena kumbe ku lulama ka mbilu ya wena leswaku u nghena ku teka tiko ra vona; kambe i hikwalaho ka ku homboloka ka matiko lawa Yehovha Xikwembu xa wena a ma hlongolaka mahlweni ka wena, ni leswaku a simeka rito leri Yehovha a nga hlambanya eka vata va wena, eka Abrahama, Isaka na Yakobo.' },
    { n: 6, text: 'Tiva leswaku a hi hikwalaho ka ku lulama ka wena leswaku Yehovha Xikwembu xa wena a ku nyikaka tiko leri rinene leswaku u ri dya ndzhaka; hikuva u vanhu va nhloko-nonon’hwa.' },
    { n: 7, text: 'Tsundzuka, u nga rivali ndlela leyi u n’wi dundzuleke ha yona Yehovha Xikwembu xa wena emanananga; ku sukela siku leri u humeke ha rona etikweni ra Egipta ku fika loko mi fika laha, mi vile lava pfukelaka Yehovha.' },
    { n: 8, text: 'Hambi ku ri eHorebe mi n’wi pfuxerile vukari bya Yehovha, lerova Yehovha a ku pfurhela hi vukari a lava ku mi herisa.' },
    { n: 9, text: 'Loko ndzi tlhandlukile entshaveni ku ya amukela matlele ya maribye, matlele ya ntwanano lowu Yehovha a nga wu endla na n’wina, ndzi tshamile entshaveni masiku ya mune-khume ni vusiku bya mune-khume, ndzi nga dyi vuswa naswona ndzi nga nwi mati;' },
    { n: 10, text: 'Kutani Yehovha a ndzi nyika matlele mambirhi ya maribye lama tsariweke hi rintiho ra Xikwembu; eka wona a ku tsariwe marito hinkwawo lawa Yehovha a ma vuleke eka n’wina entshaveni, exikarhi ka ndzilo, hi siku ra nhlengeletano.' },
    { n: 11, text: 'Swi endlekile emakumu ka masiku ya mune-khume ni vusiku bya mune-khume, Yehovha a ndzi nyika matlele mambirhi ya maribye, matlele ya ntwanano.' },
    { n: 12, text: 'Kutani Yehovha a ku eka mina: ‘Pfuka, xika hi ku hatlisa lahha; hikuva vanhu va wena, lava u va humeseke eEgipta, va tiyimisele ku onha; va hambukile hi ku hatlisa endleleni leyi ndzi va leriseke yona; va tiendlerile xifaniso lexi n’hendzisiweke.' },
    { n: 13, text: 'Yehovha a tlhela a vulavula na mina, a ku: ‘Ndzi vone vanhu lava, naswona, vona, i vanhu va nhloko-nonon’hwa;' },
    { n: 14, text: 'ndzi tshike ndzi va herisa, ndzi herisa vito ra vona ehansi ka tilo; kutani ndzi ta ku endla u va tiko ra matimba ni leri taleke ku va hundza.' },
    { n: 15, text: 'Kutani ndzi hundzulukile ndzi xika entshaveni, kasi ntshava a yi pfurha ndzilo; naswona matlele mambirhi ya ntwanano a ya ri emavokweni ya mina mambirhi.' },
    { n: 16, text: 'Ndzi langutile, kutani ndzi vona leswaku mi dyohile eka Yehovha Xikwembu xa n’wina; mi tiendlerile rhole leri n’hendzisiweke; mi hambukile hi ku hatlisa endleleni leyi Yehovha a mi leriseke yona.' },
    { n: 17, text: 'Kutani ndzi khomile matlele mambirhi, ndzi ma lahlela ehansi hi mavoko ya mina mambirhi, ndzi ma fayetla mahlweni ka mahlo ya n’wina.' },
    { n: 18, text: 'Ndzi tlhele ndzi khinsama mahlweni ka Yehovha, ku fana na le ku sunguleni, masiku ya mune-khume ni vusiku bya mune-khume; a ndzi dyanga vuswa naswona a ndzi nwanga mati, hikwalaho ka swidyoho hinkwaswo swa n’wina leswi mi nga swi endla, hi ku endla swo biha emihlweni ya Yehovha leswaku mi n’wi pfurhisa vukari;' },
    { n: 19, text: 'hikuva a ndzi chava vukari ni ku hisa ka mbilu leyi Yehovha a a ku pfurhela ha yona ku mi herisa. Kambe Yehovha u ndzi yingiserile na hi nkarhi wolowo.' },
    { n: 20, text: 'Yehovha a a n’wi karihele swinene Aroni lerova a a lava ku n’wi herisa; hikwalaho ndzi khongelele na yena Aroni hi nkarhi wolowo.' },
    { n: 21, text: 'Ndzi teke xidyoho xa n’wina, rhole leri mi nga ri endla, ndzi ri hisa hi ndzilo, ndzi ri faya, ndzi ri sila swinene ku fika loko ri va ritshuri; kutani ndzi lahlele ritshuri ra rona enambini lowu xikaka hi le ntshaveni.' },
    { n: 22, text: 'Na le Tabera, ni le Masa, ni le Kibrote-Hatafaka, mi dundzurile Yehovha a kariha.' },
    { n: 23, text: 'Loko Yehovha a mi rhumile ku suka eKadexi-Barneya, a ku: ‘Tlhandlukani mi ya teka tiko leri ndzi mi nyikeke rona; mi pfukerile rito ra Yehovha Xikwembu xa n’wina, naswona a mi n’wi tshembanga kumbe ku yingisela rito ra yena.' },
    { n: 24, text: 'Mi vile lava pfukelaka Yehovha ku sukela siku leri ndzi mi tivaka ha rona.' },
    { n: 25, text: 'Ndzi khinsamile mahlweni ka Yehovha masiku lawa ya mune-khume ni vusiku bya mune-khume; hikuva Yehovha a a vurile leswaku u lava ku mi herisa.' },
    { n: 26, text: 'Ndzi khongerile eka Yehovha, ndzi ku: ‘O Hosi Yehovha, u nga herisi vanhu va wena ni ndzhaka ya wena, lava u va kutsuleke hi vukulu bya wena, lava u va humeseke eEgipta hi voko leri nga ni matimba.' },
    { n: 27, text: 'Tsundzuka malandza ya wena, Abrahama, Isaka na Yakobo; u nga languti ku nonon’hwa ka vanhu lava, kumbe ku homboloka ka vona, kumbe xidyoho xa vona;' },
    { n: 28, text: 'leswaku tiko leri u hi humeseke eka rona ri nga ku: Hikwalaho ka ku va Yehovha a nga swi kotanga ku va nghenisa etikweni leri a va tshembiseke rona, ni hikwalaho ka ku va a va vengile, u va humesile ku ya va dlayela emananga.' },
    { n: 29, text: 'Kambe i vanhu va wena ni ndzhaka ya wena, lava u va humeseke hi matimba ya wena lamakulu ni hi voko ra wena leri extended.' }
  ],
  10: [
    { n: 1, text: 'Hi nkarhi wolowo Yehovha a ku eka mina: ‘Gevha matlele mambirhi ya maribye lama fanaka na lawa yo sungula, u tlhandluka entshaveni u ta eka mina, u tiendlela ni bokisi ra ntsandza.' },
    { n: 2, text: 'Ndzi ta tsala ematleleni lawa marito lawa a ya ri ematleleni yo sungula lawa u nga ya fayetla, naswona u ta ya nghenisa ebokisini.' },
    { n: 3, text: 'Kutani ndzi endle bokisi hi ntsandza wa akasiya, ndzi gevha ni matlele mambirhi ya maribye lama fanaka na lawa yo sungula, ndzi tlhandluka entshaveni ndzi khome matlele mambirhi emavokweni ya mina.' },
    { n: 4, text: 'Kutekeka a tsala ematleleni, ku fana ni matsalelo yo sungula, swileriso swa khume leswi Yehovha a mi byeleke swona entshaveni exikarhi ka ndzilo, hi siku ra nhlengeletano; kutani Yehovha a ndzi nyika wona.' },
    { n: 5, text: 'Ndzi hundzulukile ndzi xika entshaveni, ndzi nghenisa matlele ebokisini leri ndzi ri endleke; naswona ya ha ri kona lahho, hilaha Yehovha a ndzi leriseke hakona.' },
    { n: 6, text: '(Vana va Israyele va sukile eBiyeroti-Bene-Yaka ku ya eMoserah. Lahho Aroni u felerile, a lahliwa kona; kutani Eleyazara n’wana wa yena a tirha tanihi muprista exikhundleni xa yena.)' },
    { n: 7, text: '(Kona va sukile va ya eGudgoda, naswona ku suka eGudgoda va ya eYotbata, tiko ra milambu ya mati.)' },
    { n: 8, text: 'Hi nkarhi wolowo Yehovha a hlawurile nyimba ya Levhi ku rwala bokisi ra ntwanano wa Yehovha, ku yima mahlweni ka Yehovha ku n’wi tirhela ni ku katekisa hi vito ra yena ku fika namuntlha.' },
    { n: 9, text: 'Hikwalaho Levhi a nga na xiavelo kumbe ndzhaka exikarhi ka vamakwavo; Yehovha hi yena ndzhaka ya yena, hilaha Yehovha Xikwembu xa wena a n’wi tshembiseke hakona.' },
    { n: 10, text: 'Ndzi tshamile entshaveni masiku ya mune-khume ni vusiku bya mune-khume, ku fana na le ku sunguleni; Yehovha u ndzi yingiserile na hi nkarhi wolowo; Yehovha a nga lavanga ku ku herisa.' },
    { n: 11, text: 'Kutani Yehovha a ku eka mina: ‘Pfuka, famba mahlweni ka vanhu lava, leswaku va nghena va teka tiko leri ndzi hlambanyeke eka vata va vona ku va nyika rona.' },
    { n: 12, text: 'Kutani sweswi, O Israyele, xana Yehovha Xikwembu xa wena u lava yini eka wena? Loko ku nga ri ku chava Yehovha Xikwembu xa wena, ku famba emandleleni ya yena hinkwayo, ni ku n’wi rhandza, ni ku tirhela Yehovha Xikwembu xa wena hi mbilu ya wena hinkwayo ni hi moya wa wena hinkwayo;' },
    { n: 13, text: 'ni ku hlayisa swileriso swa Yehovha ni milawu ya yena leswi ndzi ku lerisaka swona namuntlha, leswaku swi ku fambela kahle?' },
    { n: 14, text: 'Vonani, eka Yehovha Xikwembu xa wena ku na tilo, ni matilo ya matilo, misava ni hinkwaswo leswi nga eka yona.' },
    { n: 15, text: 'Kambe Yehovha u namarhele vata va wena ku va rhandza, kutani a hlawula n’wina, mindzhaku ya vona, exikarhi ka vanhu hinkvavo, hilaha swi nga hakona namuntlha.' },
    { n: 16, text: 'Kutani tsembelani vugingu bya timbilu ta n’wina, naswona mi nga ha vi va nhloko-nonon’hwa.' },
    { n: 17, text: 'Hikuva Yehovha Xikwembu xa n’wina, hi yena Xikwembu xa swikwembu ni Hosi ya tihosi, Xikwembu lexikulu, xa matimba ni xo chavisa, lexi nga langutiki xiyimo xa munhu, naswona xi nga amukeliki tinyiko;' },
    { n: 18, text: 'xi avanyisela n’wana wa mufandzi ni noni hi ku lulama, naswona xi rhandza muhluri, xi n’wi nyika vuswa ni swiambalo.' },
    { n: 19, text: 'Rhandzani muhluri; hikuva na n’wina mi vile vahluri etikweni ra Egipta.' },
    { n: 20, text: 'U ta chava Yehovha Xikwembu xa wena, u n’wi tirhela, u namarhela eka yena, naswona u hlambanya hi vito ra yena.' },
    { n: 21, text: 'Hi yena ku dzuneka ka wena, naswona hi yena Xikwembu xa wena, lexi ku endleleke swilo leswi swikulu ni swo chavisa leswi mahlo ya wena ya swi voneke.' },
    { n: 22, text: 'Vata va wena va xikile eEgipta va ri vanhu va mune-khume na khume-nharhu; kasi sweswi Yehovha Xikwembu xa wena u ku endle u tala ku fana ni tinyeleti ta tilo.' }
  ],
  11: [
    { n: 1, text: 'Kutani u ta rhandza Yehovha Xikwembu xa wena, u hlayisa vutihlamuleri bya yena, ni milawu ya yena, ni swiboho swa yena, ni swileriso swa yena masiku hinkwaswo.' },
    { n: 2, text: 'Tivani namuntlha (hikuva a ndzi vulavuli ni vana va n’wina lava nga tiviki ni lava nga vonangiki ku lulamisiwa ka Yehovha Xikwembu xa n’wina), vukulu bya yena, voko ra yena leri nga ni matimba, ni voko ra yena leri extended;' },
    { n: 3, text: 'ni swikombiso swa yena, ni mintirho ya yena leyi a nga yi endla exikarhi ka Egipta, eka Faro hosi ya Egipta, ni le tikweni ra yena hinkwaro;' },
    { n: 4, text: 'ni leswi a swi endleke eka vuthu ra Egipta, eka tihanci ta vona ni le ka makalichi ya vona; ndlela leyi a nga funengeta ha yona hi mati ya Lwandle ro Pshuka loko va mi hlongorisa, ni ndlela leyi Yehovha a va loviseke ha yona ku fika namuntlha;' },
    { n: 5, text: 'ni leswi a mi endleleke swona emanananga ku fika loko mi fika laha;' },
    { n: 6, text: 'ni leswi a swi endleke eka Datana na Abiramu, vana va Eliyaba, n’wana wa Ruveni; ndlela leyi misava a yi ahlamisa nomu wa yona yi va mita, swin’we ni tiyindlu ta vona, matende ya vona, ni swilo hinkwaswo leswi hanyaka leswi a swi va landzela, exikarhi ka Israyele hinkwayo;' },
    { n: 7, text: 'hikuva mahlo ya n’wina ya vone mintirho hinkwayo leyikulu leyi Yehovha a nga yi endla.' },
    { n: 8, text: 'Hlayisani swileriso hinkwaswo leswi ndzi ku lerisaka swona namuntlha, leswaku mi kuma matimba, mi nghena mi teka tiko leri mi yaka eka rona ku ri teka;' },
    { n: 9, text: 'ni leswaku mi lehisa masiku ya n’wina etikweni leri Yehovha a nga hlambanya eka vata va n’wina ku va nyika rona ni vana va vona, tiko leri khulukaka ntswamba ni vulombe.' },
    { n: 10, text: 'Hikuva tiko leri u nghenaka eka rona ku ri teka, a ri fani ni tiko ra Egipta lomu u humeke kona, lomu u nga byala mbewu ya wena, u yi cheleta hi nenge wa wena, ku fana ni xirhapa xa matsavu;' },
    { n: 11, text: 'Kambe tiko leri mi yaka eka rona ku ri teka, i tiko ra tintshava ni mikova, leri nwaka mati ya mpfula leyi xikaka hi le tilweni;' },
    { n: 12, text: 'i tiko leri Yehovha Xikwembu xa wena a ri hlayisaka; mahlo ya Yehovha Xikwembu xa wena ya tshamela ku va ehenhla ka rona, ku sukela eku sunguleni ka lembe ku fika emakumu ka rona.' },
    { n: 13, text: 'Kutani swi ta endleka leswaku, loko mo yingisela hi ku hiseka swileriso swa mina leswi ndzi mi lerisaka swona namuntlha, ku rhandza Yehovha Xikwembu xa n’wina, ni ku n’wi tirhela hi mbilu ya n’wina hinkwayo ni hi moya wa n’wina hinkwayo;' },
    { n: 14, text: 'ndzi ta nyika mpfula ya tiko ra n’wina hi nkarhi wa yona, mpfula yo sungula ni mpfula yo hetelela, leswaku u hlengeleta mavele ya wena, ni vhinyo ya wena leyintshwa, ni mafurha ya wena.' },
    { n: 15, text: 'Ndzi ta nyika na byanyi emasinemu ya wena hikwalaho ka swifuwo swa wena, kutani u ta dya u xurha.' },
    { n: 16, text: 'Tivoneleni leswaku timbilu ta n’wina ti nga hambukisiwi, mi hambuka mi tirhela swikwembu swin’wana ni ku swi khinsameli;' },
    { n: 17, text: 'Kutani vukari bya Yehovha byi mi pfurhela, a pfala matilo leswaku mpfula yi nga na, tiko ri nga nyiki mihandzu ya rona; kutani mi lova hi ku hatlisa etikweni leri rinene leri Yehovha a mi nyikaka rona.' },
    { n: 18, text: 'Kutani vekani marito lawa ya mina embilwini ya n’wina ni le moyeni wa n’wina, mi ma boha ya va xikombiso evokweni ra n’wina, naswona ya ta va xisirhelelo exikarhi ka mahlo ya n’wina;' },
    { n: 19, text: 'Mi ta ma dyondzisa vana va n’wina, mi vulavula ha wona loko u tshama endlwini ya wena, ni loko u famba endleleni, ni loko u etlela, ni loko u pfuka;' },
    { n: 20, text: 'U ta ma tsala na le timbambeni ta yindlu ya wena ni le tinyangweni ta wena;' },
    { n: 21, text: 'leswaku masiku ya n’wina ni masiku ya vana va n’wina ya va yo tala etikweni leri Yehovha a nga hlambanya eka vata va n’wina ku va nyika rona, ku fana ni masiku ya matilo ehenhla ka misava.' },
    { n: 22, text: 'Hikuva loko mo hlayisa swileriso leswi hinkwaswo hi ku hiseka leswi ndzi mi lerisaka swona ku swi endla, ku rhandza Yehovha Xikwembu xa n’wina, ku famba emandleleni ya yena hinkwayo ni ku namarhela eka yena;' },
    { n: 23, text: 'Yehovha u ta hlongola matiko lawa hinkwawo mahlweni ka n’wina, naswona mi ta teka matiko lamakulu ni ya matimba ku mi hundza.' },
    { n: 24, text: 'Ndhawu hinkwayo leyi nkondzo wa nenge wa n’wina u nga ta kandziya eka yona yi ta va ya n’wina; ku sukela emananga ni le Libanoni, ku sukela enambini, nambu wa Yufrata, ku fika elwandle leri nga evupela-dyambu yi ta va ndzilakana wa n’wina.' },
    { n: 25, text: 'Ku hava loyi a nga ta yima mahlweni ka n’wina; Yehovha Xikwembu xa n’wina u ta veka ku chava ni ku rhendzeleka ka n’wina ehenhla ka tiko hinkwaro leri mi nga ta kandziya eka rona, hilaha a mi byeleke hakona.' },
    { n: 26, text: 'Vonani, ndzi veka mahlweni ka n’wina namuntlha nkateko ni ndzhukano:' },
    { n: 27, text: 'nkateko, loko mo yingisela swileriso swa Yehovha Xikwembu xa n’wina leswi ndzi mi lerisaka swona namuntlha;' },
    { n: 28, text: 'ni ndzhukano, loko mi nga yingiseli swileriso swa Yehovha Xikwembu xa n’wina, kambe mi hambuka endleleni leyi ndzi mi lerisaka yona namuntlha, mi landzela swikwembu swin’wana leswi mi nga swi tiviki.' },
    { n: 29, text: 'Kutani swi ta endleka leswaku, loko Yehovha Xikwembu xa wena a ku nghenisile etikweni leri u yaka eka rona ku ri teka, u ta veka nkateko entshaveni ya Gerizimi, ni ndzhukano entshaveni ya Ebali.' },
    { n: 30, text: '(Xana a ti kona entsheni ka Yordani, endzhaku ka ndlela ya vupela-dyambu, etikweni ra Vakanana lava tshamaka eAraba, mahlweni ka Gilgala, etlhelo ka timhandzi ta More?)' },
    { n: 31, text: 'Hikuva mi ta tsemakanya Yordani ku nghena mi teka tiko leri Yehovha Xikwembu xa n’wina a mi nyikaka rona; naswona mi ta ri teka, mi tshama eka rona.' },
    { n: 32, text: 'Kutani hlayisani ku endla milawu hinkwayo ni swiboho leswi ndzi mi vekelaka swona namuntlha mahlweni ka n’wina.' }
  ],
  12: [
    { n: 1, text: 'Lawa i milawu ni swiboho leswi mi faneleke ku hlayisa ku swi endla etikweni leri Yehovha Xikwembu xa vata va wena a ku nyikeke rona leswaku u ri dya ndzhaka, masiku hinkwaswo lawa mi hanyaka ehenhla ka misava.' },
    { n: 2, text: 'Mi ta lovisa hi ku helela tindhawu hinkwato lomu matiko lawa mi nga ta ma hlongola ya nga tirhela swikwembu swa wona kona, etintshaveni leti tlakukeke, ni le switsungeni, ni ehansi ka ntsandza hinkwawo lowu nga ni mihandzu.' },
    { n: 3, text: 'Mi ta thleketla tialtari ta vona, mi fayetla ni timhandzi ta vona to kwetsima, mi hisa ni swifaniso swa vona swa Axera hi ndzilo, mi tsema ni swifaniso leswi gundziweke swa swikwembu swa vona, mi herisa ni vito ra swona endhawini yaleyo.' },
    { n: 4, text: 'Mi nga tshuki mi endla tano eka Yehovha Xikwembu xa n’wina;' },
    { n: 5, text: 'Kambe ndhawu leyi Yehovha Xikwembu xa n’wina a nga ta yi hlawula exikarhi ka tinyimba hinkwato ta n’wina ku veka vito ra yena kona, ku va vutshamo bya yena, hi yona leyi mi nga ta yi lava, naswona u ta fika kona;' },
    { n: 6, text: 'Kutani mi ta tisa kona magandzelo ya n’wina yo hisiwa, ni tihlengo ta n’wina, ni swikhume swa n’wina, ni tihlengo ta mavoko ya n’wina, ni switshembiso swa n’wina, ni magandzelo ya n’wina ya ku tirhandzela, ni mativula ya tihomu ta n’wina ni ya swifuwo swa n’wina switsongo;' },
    { n: 7, text: 'naswona mi ta dya kona mahlweni ka Yehovha Xikwembu xa n’wina, mi tsaka, n’wina ni tiyindlu ta n’wina, hi hinkwaswo leswi mi nga veka voko ra n’wina eka swona, leswi Yehovha Xikwembu xa wena a ku katekiseke ha swona.' },
    { n: 8, text: 'Mi nga tshuki mi endla hilaha hi endlaka hakona namuntlha lahha, un’wana ni un’wana a endla leswi lulameke emihlweni ya yena n’winyi;' },
    { n: 9, text: 'hikuva a mi nga si fika eku wiseni ni le ndzhakeni leyi Yehovha Xikwembu xa wena a ku nyikaka yona.' },
    { n: 10, text: 'Kambe loko mi tsemakanyile Yordani, mi tshama etikweni leri Yehovha Xikwembu xa n’wina a mi nyikaka rona leswaku mi ri dya ndzhaka, naswona a mi nyika ku wisa eka valala va n’wina hinkvavo lava mi rhendzeleke, mi tshama mi hlayisekile;' },
    { n: 11, text: 'Kutani swi ta endleka leswaku ndhawu leyi Yehovha Xikwembu xa n’wina a nga ta yi hlawula ku simeka vito ra yena kona, hi yona leyi mi nga ta tisa eka yona hinkwaswo leswi ndzi mi lerisaka swona: magandzelo ya n’wina yo hisiwa, ni tihlengo ta n’wina, ni swikhume swa n’wina, ni tihlengo ta mavoko ya n’wina, ni switshembiso hinkwaswo swo hlawuleka leswi mi nga ta hlambanyela Yehovha;' },
    { n: 12, text: 'naswona mi ta tsaka mahlweni ka Yehovha Xikwembu xa n’wina, n’wina, ni vana va n’wina va majaha ni va vanhwanyana, ni malandza ya n’wina ya xinuna ni ya xisati, swin’we ni Mulevhi loyi a nga endzeni ka tinyangwa ta n’wina, hikuva a nga na xiavelo kumbe ndzhaka na n’wina.' },
    { n: 13, text: 'Tivonele leswaku u nga hisi magandzelo ya wena yo hisiwa endhawini yihi ni yihi leyi u yi vonaka;' },
    { n: 14, text: 'Kambe endhawini leyi Yehovha a nga ta yi hlawula exikarhi ka yin’we ya tinyimba ta wena, hi kona lomu u nga ta hisa kona magandzelo ya wena yo hisiwa, naswona hi kona lomu u nga ta endla kona hinkwaswo leswi ndzi ku lerisaka swona.' },
    { n: 15, text: 'Kambe u nga tlhabela u dya nyama endzeni ka tinyangwa ta wena hinkwato, hilaha mbilu ya wena yi navelaka hakona, hi ku landza nkateko lowu Yehovha Xikwembu xa wena a ku nyikeke wona; la nga tengangiki ni la tengeke a nga dya eka yona, ku fana ni mhala ni nhlangu.' },
    { n: 16, text: 'Ntsena mi nga tshuki mi dya ngati; mi ta yi lahlela ehansi ku fana ni mati.' },
    { n: 17, text: 'U nga tshuki u dyela endzeni ka tinyangwa ta wena swikhume swa mavele ya wena, kumbe swa vhinyo ya wena leyintshwa, kumbe swa mafurha ya wena, kumbe mativula ya tihomu ta wena kumbe ya swifuwo swa wena switsongo, kumbe switshembiso swa wena swo hlawuleka leswi u nga swi hlambanya, kumbe magandzelo ya wena ya ku tirhandzela, kumbe tihlengo ta voko ra wena;' },
    { n: 18, text: 'Kambe u ta swi dyela mahlweni ka Yehovha Xikwembu xa wena endhawini leyi Yehovha Xikwembu xa wena a nga ta yi hlawula, wena, ni n’wana wa wena wa jaha, ni n’wana wa wena wa nhwanyana, ni nandza wa wena wa xinuna, ni nandza wa wena wa xisati, swin’we ni Mulevhi loyi a nga endzeni ka tinyangwa ta wena; naswona u ta tsaka mahlweni ka Yehovha Xikwembu xa wena hi hinkwaswo leswi u nga veka voko ra wena eka swona.' },
    { n: 19, text: 'Tivonele leswaku u nga tshuki u tshika Mulevhi masiku hinkwaswo lawa u hanyaka etikweni ra wena.' },
    { n: 20, text: 'Loko Yehovha Xikwembu xa wena a andlisile ndzilakana wa wena, hilaha a ku tshembiseke hakona, kutani u ku: ‘Ndzi ta dya nyama’, hikuva mbilu ya wena yi navela ku dya nyama; u nga dya nyama hilaha mbilu ya wena yi navelaka hakona.' },
    { n: 21, text: 'Loko ndhawu leyi Yehovha Xikwembu xa wena a nga ta yi hlawula ku veka vito ra yena kona yi ri kule na wena, u nga tlhabela eka tihomu ta wena kumbe eka swifuwo swa wena switsongo leswi Yehovha a ku nyikeke swona, hilaha ndzi ku leriseke hakona, u dyela endzeni ka tinyangwa ta wena hilaha mbilu ya wena yi navelaka hakona.' },
    { n: 22, text: 'Ku fana ni ku dyiwa ka mhala ni nhlangu, u ta yi dyisa tano; la nga tengangiki ni la tengeke va nga dya eka yona swin’we.' },
    { n: 23, text: 'Ntsena tiyisela leswaku u nga dyi ngati; hikuva ngati i vutomi, naswona u nga tshuki u dya vutomi swin’we ni nyama.' },
    { n: 24, text: 'U nga tshuki u yi dya; u ta yi lahlela ehansi ku fana ni mati.' },
    { n: 25, text: 'U nga tshuki u yi dya, leswaku swi ku fambela kahle, wena ni vana va wena endzhaku ka wena, loko u endla leswi lulameke emihlweni ya Yehovha.' },
    { n: 26, text: 'Ntsena swilo swa wena swo kwetsima leswi u nga na swona, ni switshembiso swa wena, u ta swi teka, u ya endhawini leyi Yehovha a nga ta yi hlawula;' },
    { n: 27, text: 'naswona u ta endla magandzelo ya wena yo hisiwa, nyama ni ngati, ealtarini ya Yehovha Xikwembu xa wena; ngati ya magandzelo ya wena yi ta cheriwa ealtarini ya Yehovha Xikwembu xa wena, kasi nyama u nga yi dya.' },
    { n: 28, text: 'Hlayisa u yingisela marito lawa hinkwawo ndzi ku lerisaka wona, leswaku swi ku fambela kahle, wena ni vana va wena endzhaku ka wena hilaha ku nga heriki, loko u endla leswaswinene ni leswi lulameke emihlweni ya Yehovha Xikwembu xa wena.' },
    { n: 29, text: 'Loko Yehovha Xikwembu xa wena a herisile matiko lawa u yaka eka rona ku ya ma hlongola mahlweni ka wena, kutani u ma hlongola, u tshama etikweni ra wona;' },
    { n: 30, text: 'Tivonele leswaku u nga phasiwi hi ku ma landzela, endzhaku ka loko ya herisiwile mahlweni ka wena; naswona u nga tshuki u vutisa hi swikwembu swa wona, u ku: ‘Xana matiko lawa a ya tirhela swikwembu swa wona kuvhani? Ndzi ta endla tano na mina.' },
    { n: 31, text: 'U nga tshuki u endla tano eka Yehovha Xikwembu xa wena; hikuva hinkwaswo leswi nyenyetsaka eka Yehovha, leswi a swi vengaka, va swi endlerile swikwembu swa vona; hambi ku ri vana va vona va majaha ni va vanhwanyana va va hisela swikwembu swa vona hi ndzilo.' },
    { n: 32, text: 'Hinkwaswo leswi ndzi mi lerisaka swona, mi ta hlayisa ku swi endla; u nga engeteli nchumu eka rona, naswona u nga hunguti nchumu eka rona.' }
  ],
  13: [
    { n: 1, text: 'Loko ku pfuka exikarhi ka n’wina muprofeta kumbe mulorhi wa milorhi, a ku nyika xikombiso kumbe hlamariso,' },
    { n: 2, text: 'Kutani xikombiso xaleyo kumbe hlamariso lowu a ku byeleke wona wu endleka, a ku: ‘A hi landzeleni swikwembu swin’wana (leswi u nga swi tiviki), hi swi tirhela;' },
    { n: 3, text: 'U nga tshuki u yingisela marito ya muprofeta yoloye kumbe mulorhi yoloye wa milorhi; hikuva Yehovha Xikwembu xa n’wina u mi ringa leswaku a tiva loko mi rhandza Yehovha Xikwembu xa n’wina hi mbilu ya n’wina hinkwayo ni hi moya wa n’wina hinkwayo.' },
    { n: 4, text: 'Mi ta landzela Yehovha Xikwembu xa n’wina, mi n’wi chava, mi hlayisa swileriso swa yena, mi yingisela rito ra yena, mi n’wi tirhela, naswona mi namarhela eka yena.' },
    { n: 5, text: 'Kambe muprofeta yoloye kumbe mulorhi yoloye wa milorhi u ta dlayiwa, hikuva u vulavurile swo hambukisa eka Yehovha Xikwembu xa n’wina, loyi a mi humeseke etikweni ra Egipta a mi kutsula endlwini ya vuhlonga, a lava ku ku hambukisa endleleni leyi Yehovha Xikwembu xa wena a ku leriseke ku famba eka yona. Ndlela yaleyo u ta herisa swo biha exikarhi ka wena.' },
    { n: 6, text: 'Loko makwenu, n’wana wa mhani wa wena, kumbe n’wana wa wena wa jaha, kumbe n’wana wa wena wa nhwanyana, kumbe nsati wa xingwavila xa wena, kumbe munghana wa wena loyi a fanaka ni moya wa wena, a ku kanganyisa exihundleni, a ku: ‘A hi yene hi ya tirhela swikwembu swin’wana’, leswi wena kumbe vata va wena mi nga swi tiviki,' },
    { n: 7, text: 'exikarhi ka swikwembu swa vanhu lava mi rhendzeleke, lava nga kusuhi na wena kumbe lava nga kule na wena, ku sukela emakumu ka misava ku fika emakumu ka yona;' },
    { n: 8, text: 'U nga pfumelani na yena naswona u nga n’wi yingiseli; ihlo ra wena ri nga n’wi tsetseleli, u nga n’wi ntswitsweli, naswona u nga n’wi fihli;' },
    { n: 9, text: 'Kambe u ta n’wi dlaya hakunene; voko ra wena ri ta va ro sungula ku yimela ku n’wi dlaya, kutani ku landzela mavoko ya vanhu hinkvavo.' },
    { n: 10, text: 'U ta n’wi kandziya hi maribye ku fika loko a fa, hikuva u lavile ku ku hambukisa eka Yehovha Xikwembu xa wena, loyi a ku humeseke etikweni ra Egipta, endlwini ya vuhlonga.' },
    { n: 11, text: 'Kutani Israyele hinkwayo yi ta swi twa yi chava, naswona a va nga ha ta tlhela va endla nchumu wo biha wo fana ni lowu exikarhi ka wena.' },
    { n: 12, text: 'Loko u twa ku vuriwa swin’wana hi un’wana wa miti ya wena, leyi Yehovha Xikwembu xa wena a ku nyikaka yona ku tshama eka yona, ku tsariwa:' },
    { n: 13, text: 'Ku humelele vavanuna vahuha exikarhi ka n’wina, va hambukisa vaaki va muti wa vona, va ku: A hi fambeni hi ya tirhela swikwembu swin’wana (leswi mi nga swi tiviki);' },
    { n: 14, text: 'Kutani u ta lavisisa, u pfuxela u vutisa hi ku hiseka; naswona, loko ku ri ntiyiso lowu tiyisisiweke leswaku xilo lexi nyenyetsaka xi endlekile exikarhi ka wena;' },
    { n: 15, text: 'U ta dlaya vaaki va muti woloyo hi banga, u wu lovisa hi ku helela swin’we ni hinkwaswo leswi nga eka wona, ni swifuwo swa wona u swi dlaya hi banga.' },
    { n: 16, text: 'U ta hlengeleta swilo hinkwaswo leswi phangiweke exikarhi ka rivala ra wona, u hisa muti hinkwaro ni swilo hinkwaswo leswi phangiweke hi ndzilo eka Yehovha Xikwembu xa wena; naswona wu ta va rito hilaha ku nga heriki, a wu nga ha ta tlhela wu akiwa.' },
    { n: 17, text: 'Kutani ku nga mambirhi ya swilo leswi lovisiweke lama nga ta namarhela evokweni ra wena; leswaku Yehovha a tlhentla eku hiseni ka vukari bya yena, a ku nyika nsetselelo, a ku tsetselela, a ku tswalisa, hilaha a nga hlambanya hakona eka vata va wena;' },
    { n: 18, text: 'loko u yingisela rito ra Yehovha Xikwembu xa wena, ku hlayisa swileriso hinkwaswo leswi ndzi ku lerisaka swona namuntlha, leswaku u endla leswi lulameke emihlweni ya Yehovha Xikwembu xa wena.' }
  ],
  14: [
    { n: 1, text: 'Mi vana va Yehovha Xikwembu xa n’wina; mi nga tshuki mi tichela swivati emiandleni ya n’wina kumbe mi tsemeta timbyandza ta mimombo ya n’wina hikwalaho ka mufi;' },
    { n: 2, text: 'hikuva u vanhu vo kwetsima eka Yehovha Xikwembu xa wena, naswona Yehovha u ku hlawurile ku va vanhu va yena n’winyi, exikarhi ka vanhu hinkvavo lava nga ehenhla ka misava.' },
    { n: 3, text: 'U nga dya nchumu ni wu un’we lowu nyenyetsaka.' },
    { n: 4, text: 'Lawa i swifuwo leswi mi nga swi dyaka: homu, nyimpfu, mbuti,' },
    { n: 5, text: 'Mhala, nhlangu, mhangela, mbuti ya le nhova, timhunti, tinyala, ni swifuwo swin’wana swa nhova.' },
    { n: 6, text: 'Xifuwo xin’wana ni xin’wana lexi handzukeke rinya leri avaneke hi le xikarhi, xi endla rinya mambirhi, xi tlhela xi vuyisa ritswalo exikarhi ka swifuwo, hi xona lexi mi nga xi dyaka.' },
    { n: 7, text: 'Kambe eka leswi vuyisaka ritswalo ntsena, kumbe leswi nga ni rinya leri handzukeke, mi nga tshuki mi dya leswi: kamela, ni nfundla, ni khungunyu, hikuva swi vuyisa ritswalo kambe a swi na rinya leri handzukeke; swi nyenyelekile eka n’wina.' },
    { n: 8, text: 'Ni nguluve, hikuva yi ni rinya leri handzukeke kambe a yi vuyisi ritswalo; yi nyenyelekile eka n’wina. Mi nga dya nyama ya tona naswona mi nga khumbi ntsumbu wa tona.' },
    { n: 9, text: 'Eka hinkwaswo leswi nga ematini mi nga dya leswi: hinkwaswo leswi nga ni swiphambati ni tinhla ta timbambu mi nga swi dya;' },
    { n: 10, text: 'Kambe hinkwaswo leswi nga riki na swiphambati ni tinhla ta timbambu mi nga dya; swi nyenyelekile eka n’wina.' },
    { n: 11, text: 'Swinyenyana hinkwaswo leswi tengeke mi nga swi dya.' },
    { n: 12, text: 'Kambe leswi hi swona leswi mi nga fanelangiki ku swi dya: gora, hunguva, xigaza,' },
    { n: 13, text: 'nkuzi ya mati, ni xikotse, ni mahlolwane hi ku landza tinxaka ta wona;' },
    { n: 14, text: 'ni xikova xin’wana ni xin’wana hi ku landza tinxaka ta xona;' },
    { n: 15, text: 'ni yimbulu, ni xikhovha, ni xingandzana, ni ximhungu hi ku landza tinxaka ta xona;' },
    { n: 16, text: 'ni xikhovhana, ni xihunguvana, ni xikotse xa mati,' },
    { n: 17, text: 'ni gava, ni mpondzo, ni magora ya lwandle,' },
    { n: 18, text: 'ni nhlanganiso, ni ngulukwani hi ku landza tinxaka ta yona, ni xinyenyetana xa vusiku, ni mampfampfahlanyana.' },
    { n: 19, text: 'Ni switsotswana hinkwaswo leswi pfelelaka swi tinyanga swi nyenyelekile eka n’wina; a swi nga dyiwi.' },
    { n: 20, text: 'Swinyenyana hinkwaswo leswi tengeke mi nga swi dya.' },
    { n: 21, text: 'Mi nga dya nchumu ni wu un’we lowu feke hi woxe; u nga wu nyika muhluri loyi a nga endzeni ka tinyangwa ta wena leswaku a wu dya, kumbe u wu xavisa eka muluveri; hikuva u vanhu vo kwetsima eka Yehovha Xikwembu xa wena. U nga tshuki u sweka n’wana wa mbuti hi ntswamba wa mhani wa yona.' },
    { n: 22, text: 'Hakunene u ta nyika xikhume xa hinkwaswo leswi humaka eka mbewu ya wena, leswi humaka ensin’wini lembe ni lembe.' },
    { n: 23, text: 'Kutani u ta dyela mahlweni ka Yehovha Xikwembu xa wena, endhawini leyi a nga ta yi hlawula ku simeka vito ra yena kona, xikhume xa mavele ya wena, xa vhinyo ya wena leyintshwa, xa mafurha ya wena, ni mativula ya tihomu ta wena ni ya swifuwo xa wena switsongo, leswaku u dyondza ku chava Yehovha Xikwembu xa wena masiku hinkwaswo.' },
    { n: 24, text: 'Loko ndlela yi ri kule swinene na wena, lerova u nga swi koti ku swi rwala, hikuva ndhawu leyi Yehovha Xikwembu xa wena a nga ta yi hlawula ku veka vito ra yena kona yi ri kule swinene na wena, loko Yehovha Xikwembu xa wena a ku katekise;' },
    { n: 25, text: 'U ta swi hundzula mali, u khoma mali evokweni ra wena, u ya endhawini leyi Yehovha Xikwembu xa wena a nga ta yi hlawula;' },
    { n: 26, text: 'Kutani u ta xava hi mali yaleyo hinkwaswo leswi mbilu ya wena yi swi navelaka: tihomu, nyimpfu, mbuti, vhinyo, kumbe swakunwa leswi tlhantlhaka mbilu, kumbe hinkwaswo leswi mbilu ya wena yi swi lavaka; u ta dya kona mahlweni ka Yehovha Xikwembu xa wena, u tsaka, wena ni tiyindlu ta wena.' },
    { n: 27, text: 'U nga tshuki u rivala Mulevhi loyi a nga endzeni ka tinyangwa ta wena, hikuva a nga na xiavelo kumbe ndzhaka na wena.' },
    { n: 28, text: 'Eku heleni ka malembe manharhu, u ta humesa xikhume hinkwaro xa mbewu ya wena ya lembe rero, u xi hlayisa endzeni ka tinyangwa ta wena;' },
    { n: 29, text: 'Kutani Mulevhi, hikuva a nga na xiavelo kumbe ndzhaka na wena, ni muhluri, ni n’wana wa mufandzi, ni noni lava nga endzeni ka tinyangwa ta wena, va ta dya va xurha; leswaku Yehovha Xikwembu xa wena a ku katekisa emintirhweni hinkwayo ya voko ra wena leyi u nga ta yi endla.' }
  ],
  15: [
    { n: 1, text: 'Eku heleni ka malembe mankombo, u ta endla ntshunxo wa swikoloto.' },
    { n: 2, text: 'Ndlela ya ntshunxo hi leyi: mukoloti un’wana ni un’wana u ta ntshunxa xikoloto lexi a nga seletela makwavo; a nga tshuki a sindzisa makwavo kumbe nyandza ya yena, hikuva ntshunxo wa Yehovha wu tivisiwile.' },
    { n: 3, text: 'Muloveri u nga n’wi sindzisa; kambe lexi nga xa wena eka makwenu, voko ra wena ri ta xi ntshunxa.' },
    { n: 4, text: 'Ntsena a ku nga ha ta va ni xisiwana exikarhi ka n’wina (hikuva Yehovha u ta ku katekisa swinene etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona ku ri teka ku ri dya ndzhaka);' },
    { n: 5, text: 'loko mo yingisela ntsena rito ra Yehovha Xikwembu xa n’wina hi ku hiseka, ku hlayisa ku endla swileriso leswi hinkwaswo leswi ndzi ku lerisaka swona namuntlha.' },
    { n: 6, text: 'Hikuva Yehovha Xikwembu xa wena u ta ku katekisa hilaha a ku tshembiseke hakona; u ta kolotisa matiko yo tala, kambe wena a u nga ta kolota; u ta fuma matiko yo tala, kambe wona a ma nga ta ku fuma.' },
    { n: 7, text: 'Loko ku ri ni xisiwana exikarhi ka n’wina, un’wana wa vamakwenu endzeni ka tinyangwa ta wena, etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona, u nga tshuki u nonon’hwisa mbilu ya wena, kumbe u pfala voko ra wena eka makwenu loyi a nga xisiwana;' },
    { n: 8, text: 'Kambe u ta n’wi pfululela voko ra wena hi ku anama, u n’wi kolotisa hi ku ntsako leswi a swi pfumalaka leswaku swi n’wi pfuna.' },
    { n: 9, text: 'Tivonele leswaku ku nga vi ni mianakanyo yo biha embilwini ya wena, u ku: ‘Lembe ra vunkombo, lembe ra ntshunxo, ri kusuhi; kutani ihlo ra wena ri va ro biha eka makwenu loyi a nga xisiwana, u nga n’wi nyiki nchumu; kutani a huvelela eka Yehovha hikwalaho ka wena, naswona ku ta va xidyoho eka wena.' },
    { n: 10, text: 'U ta n’wi nyika hi mbilu hinkwayo, naswona mbilu ya wena a yi nga gunguli loko u n’wi nyika; hikuva hikwalaho ka xilo lexi Yehovha Xikwembu xa wena a ku katekisa emintirhweni ya wena hinkwayo ni le ka hinkwaswo leswi u nga veka voko ra wena eka swona.' },
    { n: 11, text: 'Hikuva swisiwana a swi nga ha ta hela etikweni; hikwalaho ndzi ku lerisa, ndzi ku: ‘U ta pfululela makwenu voko ra wena, eka lava pfumalaka ni le ka swisiwana swa wena etikweni ra wena.' },
    { n: 12, text: 'Loko makwenu wa Muheveru, wa xinuna kumbe wa xisati, a xavisiwile eka wena, a ku tirhela malembe ya tsevu; hi lembe ra vunkombo u ta n’wi tshika a famba a ntshunxekile eka wena.' },
    { n: 13, text: 'Kutani loko u n’wi tshika a famba a ntshunxekile, u nga n’wi tshiki a famba a tiandla ti mbe;' },
    { n: 14, text: 'U ta n’wi fambisa hi ku nyika swinene swa swifuwo swa wena, ni swa xivuwa xa wena, ni swa xitsandza xa wena xa vhinyo; hilaha Yehovha Xikwembu xa wena a ku katekiseke hakona, u ta n’wi nyika.' },
    { n: 15, text: 'Tsundzuka leswaku u vile hlonga etikweni ra Egipta, naswona Yehovha Xikwembu xa wena a ku kutsula; hikwalaho ndzi ku lerisaka xilo lexi namuntlha.' },
    { n: 16, text: 'Kambe loko a ku eka wena: ‘A ndzi lavi ku suka eka wena’, hikuva a ku rhandza na vandyangu va wena, ni hikuva swi n’wi fambela kahle na wena;' },
    { n: 17, text: 'U ta teka xitlhoma-tindleve, u tlhoma ndleve ya yena emnyangweni, kutani u ta va nandza wa wena hilaha ku nga heriki. Naswona u ta endla tano na le ka nandza wa wena wa xisati.' },
    { n: 18, text: 'U nga tshuki swi ku nonon’hwela ku n’wi tshika a famba a ntshunxekile, hikuva u ku tirhele malembe ya tsevu, a vuyisa swinene ku hundza xandla xa mutirhi la thariweke; kutani Yehovha Xikwembu xa wena a ku katekisa eka hinkwaswo leswi u nga ta swi endla.' },
    { n: 19, text: 'Mativula hinkwawo ya xinuna lawa ku nga ta tswariwa exikarhi ka tihomu ta wena ni swifuwo swa wena switsongo, u ta ma kwetsimisa eka Yehovha Xikwembu xa wena; u nga tshuki u tirhisa xivula xa tihomu ta wena, naswona u nga tsemi voya bya mativula ya swifuwo swa wena switsongo.' },
    { n: 20, text: 'U ta ma dyela mahlweni ka Yehovha Xikwembu xa wena lembe ni lembe, endhawini leyi Yehovha a nga ta yi hlawula, wena ni vandyangu va wena.' },
    { n: 21, text: 'Kambe loko xifuwo xolexo xi ri ni vulema, xi khuta kumbe xi fe mahlo, kumbe xi ri ni vulema byihi na byihi byo biha, u nga tshuki u xi tlhavela Yehovha Xikwembu xa wena.' },
    { n: 22, text: 'U ta xi dyela endzeni ka tinyangwa ta wena; la nga tengangiki ni la tengeke va nga dya eka xona swin’we, ku fana ni mhala ni nhlangu.' },
    { n: 23, text: 'Ntsena u nga tshuki u dya ngati ya xona; u ta yi chululela ehansi ku fana ni mati.' }
  ],
  16: [
    { n: 1, text: 'Hlayisa n’weti wa Abibi, u tlangela Paska ya Yehovha Xikwembu xa wena; hikuva hi n’weti wa Abibi, Yehovha Xikwembu xa wena u ku humesile eEgipta hi vusiku.' },
    { n: 2, text: 'U ta tlhavela Yehovha Xikwembu xa wena Paska, swifuwo switsongo ni swikulu, endhawini leyi Yehovha a nga ta yi hlawula ku veka vito ra yena kona.' },
    { n: 3, text: 'U nga tshuki u dyela Paska na vuswa lebyi nga ni comela; masiku ya kombo u ta dyela kwalaho vuswa lebyi nga riki na comela, vuswa bya mahlomulo (hikuva u humele eEgipta hi ku hatlisa), leswaku u tsundzuka siku leri u humeke ha rona etikweni ra Egipta masiku hinkwaswo ya vutomi va wena.' },
    { n: 4, text: 'Ku nga tshuki ku voniwa comela etikweni ra wena hinkwaro masiku ya kombo; naswona ku nga tshuki ku sala nyama ni yitsongo hi vusiku byo sungula ku fika nimixo.' },
    { n: 5, text: 'U nga tshuki u tlhavela Paska endzeni ka yin’we ya tinyangwa ta wena leyi Yehovha Xikwembu xa wena a ku nyikaka yona;' },
    { n: 6, text: 'Kambe endhawini leyi Yehovha Xikwembu xa wena a nga ta yi hlawula ku simeka vito ra yena kona, hi kona lomu u nga ta tlhavela Paska hi dyambu loko ri pela, hi nkarhi lowu u humeke ha rona eEgipta.' },
    { n: 7, text: 'U ta yi sweka u dyela endhawini leyi Yehovha Xikwembu xa wena a nga ta yi hlawula; kutani nimixo u ta hundzuluka u ya ematendeni ya wena.' },
    { n: 8, text: 'Masiku ya tsevu u ta dya vuswa lebyi nga riki na comela, naswona hi siku ra vunkombo ku ta va ni nhlengeletano yo kwetsima eka Yehovha Xikwembu xa wena; u nga tshuki u endla ntirho na wu un’we.' },
    { n: 9, text: 'U ta hlayela mavhiki ya kombo; u ta sungula ku hlayela mavhiki ya kombo ku sukela loko u sungula ku tsema mavele.' },
    { n: 10, text: 'Kutani u ta tlangela nkhuvo wa mavhiki eka Yehovha Xikwembu xa wena hi gandzelo ra ku tirhandzela ra voko ra wena, leri u nga ta ri nyika hilaha Yehovha Xikwembu xa wena a ku katekiseke hakona;' },
    { n: 11, text: 'naswona u ta tsaka mahlweni ka Yehovha Xikwembu xa wena, wena, ni n’wana wa wena wa jaha, ni n’wana wa wena wa nhwanyana, ni nandza wa wena wa xinuna, ni nandza wa wena wa xisati, ni Mulevhi loyi a nga endzeni ka tinyangwa ta wena, ni muhluri, ni n’wana wa mufandzi, ni noni lava nga exikarhi ka wena, endhawini leyi Yehovha Xikwembu xa wena a nga ta yi hlawula ku simeka vito ra yena kona.' },
    { n: 12, text: 'Tsundzuka leswaku u vile hlonga eEgipta; kutani u ta hlayisa u endla milawu leyi.' },
    { n: 13, text: 'U ta tlangela nkhuvo wa matende masiku ya kombo, endzhaku ka loko u hlengeletile swilo swa xivuwa xa wena ni swa xitsandza xa wena xa vhinyo;' },
    { n: 14, text: 'naswona u ta tsaka enkhuvweni wa wena, wena, ni n’wana wa wena wa jaha, ni n’wana wa wena wa nhwanyana, ni nandza wa wena wa xinuna, ni nandza wa wena wa xisati, swin’we ni Mulevhi, ni muhluri, ni n’wana wa mufandzi, ni noni lava nga endzeni ka tinyangwa ta wena.' },
    { n: 15, text: 'Masiku ya kombo u ta tlangela nkhuvo eka Yehovha Xikwembu xa wena endhawini leyi Yehovha a nga ta yi hlawula; hikuva Yehovha Xikwembu xa wena u ta ku katekisa emihandzwini ya wena hinkwayo ni le mintirhweni hinkwayo ya mavoko ya wena, naswona u ta tsaka hakunene.' },
    { n: 16, text: 'Kunharhu hi lembe vavanuna va wena hinkvavo va ta yima mahlweni ka Yehovha Xikwembu xa wena endhawini leyi a nga ta yi hlawula: enkhuvweni wa vuswa lebyi nga riki na comela, ni le nkhuvweni wa mavhiki, ni le nkhuvweni wa matende; naswona ku nga tshuki ku va ni loyi a yimaka mahlweni ka Yehovha a tiandla ti mbe;' },
    { n: 17, text: 'Un’wana ni un’wana u ta nyika hilaha a nga kotaka hakona, hi ku landza nkateko lowu Yehovha Xikwembu xa wena a ku nyikeke wona.' },
    { n: 18, text: 'U ta veka vaavanyisi ni vafambisi endzeni ka tinyangwa ta wena hinkwato, leti Yehovha Xikwembu xa wena a ku nyikaka tona, hi ku landza tinyimba ta wena; naswona va ta avanyisa vanhu hi ku lulama.' },
    { n: 19, text: 'U nga tshuki u soholota vuavanyisi; u nga languti xiyimo xa munhu, naswona u nga amukeli tinyiko; hikuva nyiko yi pfala mahlo ya lava tlhariheke, yi soholota ni marito ya lava lulameke.' },
    { n: 20, text: 'Ku lulama, ku lulama ntsena hi kona lomu u nga ta ku landzelerisa, leswaku u hanya u teka tiko leri Yehovha Xikwembu xa wena a ku nyikaka rona.' },
    { n: 21, text: 'U nga tshuki u byala xifaniso xa Axera xa ntsandza lowu nga ni nchumu ni wu un’we kusuhi ni altar ya Yehovha Xikwembu xa wena, leyi u nga ta tiendlela yona;' },
    { n: 22, text: 'naswona u nga tshuki u tiyimisele mhandzi yo kwetsima, leyi Yehovha Xikwembu xa wena a yi vengaka.' }
  ],
  17: [
    { n: 1, text: 'U nga tshuki u tlhavela Yehovha Xikwembu xa wena homu kumbe nyimpfu leyi nga ni vulema kumbe xivati xihi na xihi xo biha; hikuva sweswo i nchumu lowu nyenyetsaka eka Yehovha Xikwembu xa wena.' },
    { n: 2, text: 'Loko ku kumiwa exikarhi ka wena, endzeni ka yin’we ya tinyangwa ta wena leyi Yehovha Xikwembu xa wena a ku nyikaka yona, wanuna kumbe wansati loyi a endlaka swo biha emihlweni ya Yehovha Xikwembu xa wena, hi ku tlula ntwanano wa yena,' },
    { n: 3, text: 'A ya tirhela swikwembu swin’wana, a khinsama mahlweni ka swona, kumbe mahlweni ka dyambu, kumbe n’weti, kumbe vuthu hinkwaro ra le tilweni, leswi ndzi nga swi lerisangiki;' },
    { n: 4, text: 'Kutani u byeriwa swona, u swi twa, u ta lavisisa hi ku hiseka; naswona, loko ku ri ntiyiso lowu tiyisisiweke leswaku xilo lexi nyenyetsaka xi endlekile eIsrayele;' },
    { n: 5, text: 'U ta humesela wanuna yoloye kumbe wansati yoloye loyi a endleke xilo lexi xo biha etinyangweni ta wena, wanuna yoloye kumbe wansati yoloye, u va kandziya hi maribye ku fika loko va fa.' },
    { n: 6, text: 'Munhu u ta dlayiwa hi ku landza rito ra timbhoni timbirhi kumbe tinharhu; a nga tshuki a dlayiwa hi rito ra mbhoni yin’we ntsena.' },
    { n: 7, text: 'Mavoko ya timbhoni hi wona lama nga ta va yo sungula ku yimela ku n’wi dlaya, kutani ku landzela mavoko ya vanhu hinkvavo. Ndlela yaleyo u ta herisa swo biha exikarhi ka wena.' },
    { n: 8, text: 'Loko ku ri ni mhaka leyi ku nonon’hwelaka ku yi avanyisa, exikarhi ka ngati ni ngati, kumbe exikarhi ka ku hoxa nandzu ni ku hoxa nandzu, kumbe exikarhi ka ku tlhavana ni ku tlhavana, ku ri timhaka ta ku kanetsana endzeni ka tinyangwa ta wena; kutani u ta pfuka, u ya endhawini leyi Yehovha Xikwembu xa wena a nga ta yi hlawula;' },
    { n: 9, text: 'U ta ya eka vaprista va Valevhi ni le ka muavanyisi loyi a nga ta va kona emasikwini wolawo, u va vutisa; va ta ku byela xigwevo xa vuavanyisi.' },
    { n: 10, text: 'Kutani u ta endla hi ku landza rito ra xigwevo lexi va nga ta ku byela xona va nga endhawini yaleyo leyi Yehovha a nga ta yi hlawula; u ta hlayisa ku endla hi ku landza hinkwaswo leswi va nga ta ku dyondzisa swona.' },
    { n: 11, text: 'U ta endla hi ku landza nawu lowu va nga ta ku lerisa wona ni xigwevo lexi va nga ta ku byela xona; u nga tshuki u hambuka eka rito lexi va nga ta ku byela xona, ku ya exineneni kumbe eximatsini.' },
    { n: 12, text: 'Kambe wanuna loyi a nga ta endla hi ku titlakusa, a nga n’wi yingiseli muprista loyi a yimeke ku tirhela Yehovha Xikwembu xa wena kwalaho, kumbe muavanyisi, wanuna yoloye u ta dlayiwa; ndlela yaleyo u ta herisa swo biha eIsrayele.' },
    { n: 13, text: 'Kutani vanhu hinkvavo va ta swi twa va chava, naswona va nga ha ta tlhela va endla hi ku titlakusa.' },
    { n: 14, text: 'Loko u fika etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona, u ri teka u dya ndzhaka ya rona, u tshama eka rona, u ku: ‘Ndzi ta veka hosi ehenhla ka mina ku fana ni matiko hinkwaswo lama ndzi rhendzeleke;' },
    { n: 15, text: 'hakunene u ta veka hosi ehenhla ka wena leyi Yehovha Xikwembu xa wena a nga ta yi hlawula; u ta veka hosi ehenhla ka wena exikarhi ka vamakwenu; u nga tshuki u veka munhu wa tiko rimbe loyi a nga riki makwenu.' },
    { n: 16, text: 'Ntsena a nga tshuki a tiandziselalela tihanci, kumbe a vuyisela vanhu eEgipta leswaku a tiandzisela tihanci; hikuva Yehovha u te eka n’wina: ‘Mi nga tshuki mi tlhela mi vuyela hi ndlela yaleyo.' },
    { n: 17, text: 'Naswona a nga tshuki a tiandzisela vasati, leswaku mbilu ya yena yi nga hambukisiwi; naswona a nga tshuki a tiandzisela silivhere ni nsuku swinene.' },
    { n: 18, text: 'Loko a tshama exiluvelweni xa vuhosi bya yena, u ta tikopiyela buku leyi ya nawu ehenhla ka mapapila, a yi tsentsela eka leyi nga mahlweni ka vaprista va Valevhi.' },
    { n: 19, text: 'Yi ta va na yena, naswona u ta yi hlaya masiku hinkwaswo ya vutomi bya yena, leswaku a dyondza ku chava Yehovha Xikwembu xa de yena, ku hlayisa marito hinkwaswo ya nawu lowu ni swileriso leswi, ku swi endla;' },
    { n: 20, text: 'leswaku mbilu ya yena yi nga titlakusi ehenhla ka vamakwavo, naswona a nga hambuki eka xileriso, ku ya exineneni kumbe eximatsini; leswaku a lelehisa masiku ya vuhosi bya yena, yena ni vana va yena exikarhi ka Israyele.' }
  ],
  18: [
    { n: 1, text: 'Vaprista va Valevhi, nyimba hinkwayo ya Levhi, va nga va na xiavelo kumbe ndzhaka swin’we ni Israyele; va ta dya swigandzelo swa Yehovha leswi hisiweke hi ndzilo, ni ndzhaka ya yena.' },
    { n: 2, text: 'Kambe va nga na ndzhaka exikarhi ka vamakwavo; Yehovha i ndzhaka ya vona, hilaha a nga va byela hakona.' },
    { n: 3, text: 'Kuni lowu ku nga ta va nawu wa vaprista lowu humaka eka vanhu, eka lava tlhavelaka swigandzelo, hambi ku ri homu kumbe nyimpfu: ku ta nyikiwa muprista voko, ni marhama, ni khuri.' },
    { n: 4, text: 'U ta n’wi nyika mativula ya mavele ya wena, ya vhinyo ya wena leyintshwa, ni ya mafurha ya wena, ni voya byo sungula bya swifuwo swa wena switsongo.' },
    { n: 5, text: 'Hikuva Yehovha Xikwembu xa wena u n’wi hlawurile exikarhi ka tinyimba hinkwato ta wena, leswaku a yima a tirhela hi vito ra Yehovha, yena ni vana va yena masiku hinkwaswo.' },
    { n: 6, text: 'Loko Mulevhi a huma eka yin’we ya tinyangwa ta wena etikweni hinkwaro ra Israyele, lomu a tshamaka kona, a ta hi ku navela hinkwaro ka mbilu ya yena endhawini leyi Yehovha a nga ta yi hlawula;' },
    { n: 7, text: 'U ta tirhela hi vito ra Yehovha Xikwembu xa de yena, ku fana ni vamakwavo hinkvavo va Valevhi, lava yimeke kwalaho mahlweni ka Yehovha.' },
    { n: 8, text: 'Va ta dya swiavelo leswi ringanaka, handle ka leswi a swi xaviseke hi ndzhaka ya tatana wa yena.' },
    { n: 9, text: 'Loko u fika etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona, u nga tshuki u dyondza ku endla hi ku landza swilo leswi nyenyetsaka swa matiko wolawo.' },
    { n: 10, text: 'Ku nga tshuki ku kumiwa exikarhi ka wena munhu loyi a hundzisaka n’wana wa yena wa jaha kumbe wa nhwanyana endzilweni, kumbe loyi a endlaka vungoma, kumbe mulorhi wa milorhi, kumbe mungoma, kumbe muloyi,' },
    { n: 11, text: 'Kumbe loyi a endleke vungoma bya ku thakatha, kumbe loyi a vutisaka vangoma kumbe vakulu va moya, kumbe loyi a vutisaka vafi.' },
    { n: 12, text: 'Hikuva un’wana ni un’wana loyi a endlaka swilo leswi u nyenyetsaka eka Yehovha; naswona hikwalaho ka swilo leswi nyenyetsaka, Yehovha Xikwembu xa wena u va hlongola mahlweni ka wena.' },
    { n: 13, text: 'U ta va la hetisekeke mahlweni ka Yehovha Xikwembu xa wena.' },
    { n: 14, text: 'Hikuva matiko lawa u nga ta ma hlongola ma yingisela vungoma ni vakulu va moya; kambe wena, Yehovha Xikwembu xa wena a nga ku pfumelelangi ku endla tano.' },
    { n: 15, text: 'Yehovha Xikwembu xa wena u ta ku pfuxela muprofeta loyi a fanaka na mina exikarhi ka wena, eka vamakwenu; hi yena loyi mi nga ta n’wi yingisela;' },
    { n: 16, text: 'hi ku landza hinkwaswo leswi u nga swi kombela eka Yehovha Xikwembu xa wena eHorebe, hi siku ra nhlengeletano, u ku: ‘Ndzi nga tshuki ndzi tlhela ndzi twa rito ra Yehovha Xikwembu xa mina, naswona ndzi nga tshuki ndzi tlhela ndzi vona ndzilo lowu lowukulu, leswaku ndzi nga fi.' },
    { n: 17, text: 'Kutani Yehovha a ku eka mina: ‘Va vurile kahle leswi va nga swi vula.' },
    { n: 18, text: 'Ndzi ta va pfuxela muprofeta loyi a fanaka na wena exikarhi ka vamakwavo; ndzi ta veka marito ya mina enon’wini wa yena, naswona u ta va byela hinkwaswo leswi ndzi nga ta n’wi lerisa swona.' },
    { n: 19, text: 'Kutani un’wana ni un’wana loyi a nga ta ka a nga yingiseli marito ya mina, lawa a nga ta va vulavula hi vito ra mina, ndzi ta n’wi vutisa hi swona.' },
    { n: 20, text: 'Kambe muprofeta loyi a nga ta endla hi ku titlakusa, a vulavula rito hi vito ra mina, leri ndzi nga n’wi lerisangiki ku ri vulavula, kumbe loyi a nga ta vulavula hi vito ra swikwembu swin’wana, muprofeta yoloye u ta dlayiwa.' },
    { n: 21, text: 'Kuni loko u ku embilwini ya wena: ‘Hi ta swi tivisa ku yini rito leri Yehovha a nga ri vulavulangiki?' },
    { n: 22, text: 'Loko muprofeta a vulavula hi vito ra Yehovha, kutani rito rero ri nga endleki kumbe ku nga vi na ntiyiso, ralezo i rito leri Yehovha a nga ri vulavulangiki; muprofeta u ri vulavurile hi ku titlakusa; u nga n’wi chavi.' }
  ],
  19: [
    { n: 1, text: 'Loko Yehovha Xikwembu xa wena a herise matiko lawa Yehovha Xikwembu xa wena a ku nyikaka tiko ra wona, u ma hlongola, u tshama emitini ya wona ni le tiyindlu ta wona;' },
    { n: 2, text: 'U ta tihlawulela miti yinharhu exikarhi ka tiko ra wena, leri Yehovha Xikwembu xa wena a ku nyikaka rona ku ri dya ndzhaka.' },
    { n: 3, text: 'U ta lunghisa ndlela, u avanyisa ndhawu ya tiko ra wena hi swiyenge swinharhu, leri Yehovha Xikwembu xa wena a ku nyikaka rona ku ri dya ndzhaka, leswaku mudlayi un’wana ni un’wana a balukela kona.' },
    { n: 4, text: 'Kuni lowu ku nga ta va nawu wa mudlayi loyi a nga ta balukela kona leswaku a hanya: loyi a dlayaka munghana wa yena handle ka vomu, a nga n’wi venganga khale;' },
    { n: 5, text: 'Ku fana ni loko munhu a ya ni munghana wa yena ekhwatini ku tsema ntsandza, kutani voko ra yena ri tlakusa banga ku tsema ntsandza, kutani xihloka xi suka emhandzini, xi dlayela munghana wa yena; munhu yoloye u ta balukela eka lowu un’wana wa miti leyi, a hanya;' },
    { n: 6, text: 'leswaku mulandzeleri wa ngati a nga hlongoli mudlayi emiseveni ya mbilu ya yena, a n’wi fikelela loko ndlela yi ri kule swinene, a n’wi dlaya, kasi a nga fanelanga ku gweviwa hi rifu, hikuva a nga n’wi venganga khale.' },
    { n: 7, text: 'Hikwalaho ndzi ku lerisaka ndzi ku: ‘U ta tihlawulela miti yinharhu.' },
    { n: 8, text: 'Loko Yehovha Xikwembu xa wena a anamise tiko ra wena, hilaha a nga hlambanyela hakona eka vata va wena, a ku nyika tiko hinkwaro leri a nga tshembisa ku ri nyika vata va wena;' },
    { n: 9, text: 'loko u hlayisa u endla swileriso leswi hinkwaswo leswi ndzi ku lerisaka swona namuntlha, ku rhandza Yehovha Xikwembu xa wena, ni ku famba tindleleni ta yena masiku hinkwaswo; kutani u ta tihlanganisela miti yinharhu ku tlhandleka eka leyi yinharhu;' },
    { n: 10, text: 'leswaku ngati leyi nga riki na nandzu yi nga chuluriwi exikarhi ka tiko ra wena, leri Yehovha Xikwembu xa wena a ku nyikaka rona ku ri dya ndzhaka, kutani ngati yi va ehenhla ka wena.' },
    { n: 11, text: 'Kambe loko ku ri ni munhu loyi a vengaka munghana wa yena, a n’wi tumbelela, a n’wi pfukela, a n’wi tsemakanya a n’wi dlaya a fa, kutani a balukela eka un’wana wa miti leyi;' },
    { n: 12, text: 'vakulu va muti wa yena va ta rhumela va n’wi teka kwalaho, va n’wi nyiketa evokweni ra mulandzeleri wa ngati, leswaku a fa.' },
    { n: 13, text: 'Ihlo ra wena ri nga n’wi tsetseleli; u ta herisa ngati leyi nga riki na nandzu eIsrayele, leswaku swi ku fambela kahle.' },
    { n: 14, text: 'U nga tshuki u tsemeta ndzilakana wa muakelani wa wena, lowu va nga wu veka khale endzhakeni ya wena, leyi u nga ta yi dya ndzhaka etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona ku ri dya ndzhaka.' },
    { n: 15, text: 'Ku nga tshuki ku yima mbhoni yin’we ntsena eka munhu hikwalaho ka vuhlayisi byihi na byihi byo biha, kumbe xidyoho xihi na xihi lexi a nga xi dyohaka; mhaka yi ta tiyisiwa hi rito ra timbhoni timbirhi kumbe tinharhu.' },
    { n: 16, text: 'Loko ku pfuka mbhoni yo hemba eka munhu, yi n’wi lumbeta hi swo biha;' },
    { n: 17, text: 'vavanuna lavambirhi lava nga ni ku kanetsana va ta yima mahlweni ka Yehovha, mahlweni ka vaprista ni vaavanyisi lava nga ta va kona emasikwini wolawo;' },
    { n: 18, text: 'vaavanyisi va ta lavisisa hi ku hiseka; naswona, loko mbhoni yi ri mbhoni yo hemba, yi lumbeta makwavo hi mavunwa;' },
    { n: 19, text: 'Mi ta n’wi endla hilaha a nga anakanya ku endla makwavo hakona. Ndlela yaleyo u ta herisa swo biha exikarhi ka wena.' },
    { n: 20, text: 'Kutani lava nga ta sala va ta swi twa va chava, naswona va nga ha ta tlhela va endla nchumu wo biha lowu fanaka ni lowu exikarhi ka wena.' },
    { n: 21, text: 'Ihlo ra wena ri nga tsetseleli: vutomi hi vutomi, ihlo hi ihlo, tinyo hi tinyo, voko hi voko, nenge hi nenge.' }
  ],
  20: [
    { n: 1, text: 'Loko u huma ku ya lwa ni valala va wena, u vona tihanci, ni tinyimpi, ni vanhu vo tala ku hundza wena, u nga va chavi; hikuva Yehovha Xikwembu xa wena loyi a ku humeseke etikweni ra Egipta u na wena.' },
    { n: 2, text: 'Loko mi ri kusuhi ni ku lwa, muprista u ta tshinela, a vulavula ni vanhu;' },
    { n: 3, text: 'a ku eka vona: ‘Yingiselani, n’wina va Israyele! Namuntlha mi kusuhi ni ku lwa ni valala va n’wina; timbilu ta n’wina ti nga heli mbilu, mi nga chavi, mi nga tshuki mi rhurhumela kumbe mi tsemeka timbilu mahlweni ka vona;' },
    { n: 4, text: 'hikuva Yehovha Xikwembu xa n’wina hi yena loyi a fambaka na n’wina, ku mi lwela ni valala va n’wina, leswaku a mi ponisa.' },
    { n: 5, text: 'Kutani vafambisi va ta vulavula ni vanhu, va ku: ‘I mani wanuna loyi a akeke yindlu leyintshwa, a nga yi khanguliki? A a tlhelele eyindluni ya yena, hikuva a nga fa tinyimpini, kutani yi khanguriwa hi wanuna un’wana.' },
    { n: 6, text: 'I mani wanuna loyi a nga byala nsin’u ya vhinyo, a nga si dyaka mihandzu ya yona? A a tlhelele eyindluni ya yena, hikuva a nga fa tinyimpini, kutani yi dyiwa hi wanuna un’wana.' },
    { n: 7, text: 'I mani wanuna loyi a nga lulama ku teka wansati, a nga si n’wi tekaka? A a tlhelele eyindluni ya yena, hikuva a nga fa tinyimpini, kutani a tekiwa hi wanuna un’wana.' },
    { n: 8, text: 'Vafambisi va ta tlhela va vulavula ni vanhu, va ku: ‘I mani wanuna loyi a chavaka ni loyi mbilu ya yena yi nga xitsongo? A a tlhelele eyindluni ya yena, leswaku timbilu ta vamakwavo ti nga heli mbilu ku fana ni mbilu ya yena.' },
    { n: 9, text: 'Loko vafambisi va hete ku vulavula ni vanhu, va ta veka varhangeri va tinyimpi ehenhla ka vanhu.' },
    { n: 10, text: 'Loko u tshinela eka muti ku ya lwa na wona, u ta rhanga u wu tivisa rito ra ku rhula.' },
    { n: 11, text: 'Kuni loko wu ku hlamula hi ku rhula, wu ku pfululela tinyangwa, vanhu hinkvavo lava kumiwaka eka wona va ta ku tirhela hi ku sindzisiwa va va malandza ya wena.' },
    { n: 12, text: 'Kambe loko wu nga endli ku rhula na wena, wu lava ku lwa na wena, u ta wu rhendzela;' },
    { n: 13, text: 'Kutani Yehovha Xikwembu xa wena u ta wu nyiketa evokweni ra wena, u dlaya hinkwavo va xinuna va wona hi banga.' },
    { n: 14, text: 'Ntsena vasati, ni vana, ni swifuwo, ni hinkwaswo leswi nga mutini, hinkwaswo leswi phangiweke, u ta swi teka swi va swa wena; u ta dya swilo leswi phangiweke swa valala va wena, leswi Yehovha Xikwembu xa wena a ku nyikeke swona.' },
    { n: 15, text: 'U ta endla tano eka miti hinkwayo leyi nga kule swinene na wena, leyi nga riki ya matiko lawa.' },
    { n: 16, text: 'Kambe eka miti ya vanhu lava, leyi Yehovha Xikwembu xa wena a ku nyikaka yona ku ri dya ndzhaka, u nga tshuki u hanya nchumu ni wu un’we lowu hefemulaka;' },
    { n: 17, text: 'Kambe u ta va lovisa hi ku helela: Vahete, ni Vaamori, ni Vakanana, ni Vaperizi, ni Vahivhi, ni Vayebusi, hilaha Yehovha Xikwembu xa wena a ku leriseke hakona;' },
    { n: 18, text: 'leswaku va nga mi dyondzisi ku endla hi ku landza swilo hinkwaswo swa vona leswi nyenyetsaka, leswi va swi endleke eka swikwembu swa vona, kutani mi dyohela Yehovha Xikwembu xa n’wina.' },
    { n: 19, text: 'Loko u rhendzela muti masiku yo tala ku lwa na wona leswaku u wu teka, u nga tshuki u herisa mirhi ya wona hi ku tlakusa xihloka eka yona, hikuva u nga dya eka yona; u nga tshuki u yi tsema, hikuva xana ntsandza wa le nhova i munhu leswaku u wu rhendzela?' },
    { n: 20, text: 'Ntsena mirhi leyi u tivaka leswaku a hi mirhi ya swakudya, hi yona leyi u nga ta yi herisa u yi tsema, u aka makhumbi yo rhendzela muti lowu lwaka na wena, ku fika loko wu wa.' }
  ],
 21: [
    { n: 1, text: 'Loko ku kumeka munhu la dlayiweke etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona leswaku ri va ra wena, a wile enhoveni, naswona ku nga tiviwi loyi a n’wi dlayeke;' },
    { n: 2, text: 'kutani vadyuhari va wena ni vaavanyisi va wena va ta huma, va pima mpfhuka ku ya emitini leyi rhendzeleke mufi;' },
    { n: 3, text: 'kutani muti lowu nga kusuhi swinene ni mufi, vadyuhari va muti wolowo va ta teka rhole ra homu leri nga si tirhisiwaka, leri nga si pambiwaka ejokweni;' },
    { n: 4, text: 'vadyuhari va muti wolowo va ta rhelelisa rhole enkoveni lowu nga ni mati lama khulukaka, lowu nga rimiwangiki kumbe ku byariwa eka wona, va tshova nhamu ya rhole kwalaho enkoveni;' },
    { n: 5, text: 'Kutani vaprista, vana va Levhi, va ta tshinela; hikuva Yehovha Xikwembu xa wena u va hlawurile ku n’wi tirhela ni ku katekisa hi vito ra Yehovha; timhaka hinkwato ta ku lwa ni ta ku ba ti ta avanyisiwa hi rito ra vona.' },
    { n: 6, text: 'Vadyuhari hinkwavo va muti wolowo lowu nga kusuhi ni mufi, va ta hlamba mavoko ya vona ehenhla ka rhole leri tshoviweke nhamu enkoveni,' },
    { n: 7, text: 'va ta hlamula va ku: ‘Mavoko ya hina a ma halatanga ngati leyi, ni mahlo ya hina a ma swi vonanga.' },
    { n: 8, text: 'Rivalela vanhu va wena Israyele lava u va kutsuleke, Wena Yehovha, u nga veki nandzu wa ngati leyi nga riki na nandzu exikarhi ka vanhu va wena Israyele.’ Kutani ngati yoleyo yi ta rivaleriwa eka vona.' },
    { n: 9, text: 'Hi mukhuva wolowo u ta susa nandzu wa ngati leyi nga riki na nandzu exikarhi ka wena, loko u endla leswinene ematihlweni ya Yehovha.' },
    { n: 10, text: 'Loko u huma ku ya lwa ni valala va wena, kutani Yehovha Xikwembu xa wena a va nyiketa emandleni ya wena, u va khoma makhumbi,' },
    { n: 11, text: 'kutani u vona wansati wo saseka exikarhi ka makhumbi, u n’wi navela, u lava ku n’wi teka a va nsati wa wena;' },
    { n: 12, text: 'u ta n’wi nghenisa endlwini ya wena; u ta byevula nhloko ya yena, a tsema min’wala ya yena,' },
    { n: 13, text: 'a hluvula swiambalo swa ku khomiwa ka yena, a tshama endlwini ya wena, a rila tata wa yena ni mana wa yena n’hweti hinkwayo; endzhaku ka sweswo u nga nghena eka yena, u va nuna wa yena, a va nsati wa wena.' },
    { n: 14, text: 'Kutani loko u nga ha n’wi tsakeli, u ta n’wi tshika a tifambela hilaha a rhandzaka hakona; kambe u nga n’wi xavisi hi mali, u nga n’wi khomi ku fana ni nandza, hikuva u n’wi tsongahatile.' },
    { n: 15, text: 'Loko wanuna a ri ni vavasati vambirhi, un’wana a n’wi rhandza, un’wana a n’wi venga, kutani va n’wi tswalela vana va xinuna, loyi a rhandziwaka ni loyi a vengiwaka; naswona loko n’wana wa mativula a ri wa wansati loyi a vengiwaka;' },
    { n: 16, text: 'kutani hi siku leri a avelaka vana va yena ndzhaka ya leswi a nga na swona, a nge swi koti ku endla n’wana wa wansati loyi a rhandziwaka mativula mahlweni ka n’wana wa wansati loyi a vengiwaka, loyi a nga mativula ya ntiyiso;' },
    { n: 17, text: 'kambe u ta tiva n’wana wa wansati loyi a vengiwaka leswaku i mativula, hi ku n’wi nyika swiphemu swimbirhi eka hinkwaswo leswi a nga na swona; hikuva i masungulo ya matimba ya yena, mfanelo ya vumativula i ya yena.' },
    { n: 18, text: 'Loko munhu a ri ni n’wana wo sihalala ni ku tiomisa nhloko, loyi a nga yingisiki rito ra tata wa yena kumbe rito ra mana wa yena, hambileswi va n’wi tshinyaka kambe a nga va yingisi;' },
    { n: 19, text: 'tata wa yena ni mana wa yena va ta n’wi khoma, va n’wi humesa eka vadyuhari va muti wa yena, enyangweni ya ndhawu ya yena,' },
    { n: 20, text: 'va ta byela vadyuhari va muti wa yena va ku: ‘N’wana wa hina loyi u sihalarile naswona u tiomisile nhloko, a nga yingisi rito ra hina; i mukarhari naswona i xidakwa.' },
    { n: 21, text: 'Kutani vavanuna hinkwavo va muti wa yena va ta n’wi khandla hi maribye, a fa; hi mukhuva wolowo u ta susa vubihi exikarhi ka wena, kutani Israyele hinkwawo u ta twa a chava.' },
    { n: 22, text: 'Loko munhu a endle xidyoho lexi faneleke rifu, kutani a dlayiwa, a hayekiwa emurhini;' },
    { n: 23, text: 'ntsumbu wa yena wu nga tshameli emurhini vusiku hinkwabyo, kambe u ta n’wi lahla hi siku rero; hikuva loyi a hayekiweke u rhukaniwile hi Xikwembu; leswaku u nga nyamisi tiko ra wena, leri Yehovha Xikwembu xa wena a ku nyikaka rona ku va ndzhaka.' }
  ],
  22: [
    { n: 1, text: 'U nga voni homu ya makwenu kumbe nyimpfi ya yena yi lahlekile, u tiendla onge a wu yi voni; u ta yi tlhelisela eka makwenu.' },
    { n: 2, text: 'Loko makwenu a nga ri kusuhi na wena, kumbe loko u nga n’wi tivi, u ta yi tisa endlwini ya wena, yi ta tshama na wena ku fika loko makwenu a yi lava, kutani u ta n’wi tlhelisela yona.' },
    { n: 3, text: 'U ta endla tano ni hi mbhongolo ya yena, u ta endla tano ni hi xiambalo xa yena, u ta endla tano ni hi nchumu wun’wana ni wun’wana lowu lahlekeke wa makwenu, lowu lahlekeke eka yena kutani wena u wu kuma; a wu fanelanga ku tiendla onge a wu swi voni.' },
    { n: 4, text: 'U nga voni mbhongolo ya makwenu kumbe homu ya yena yi wile endleleni, u tiendla onge a wu yi voni; u ta n’wi pfuna ku yi pfuxa.' },
    { n: 5, text: 'Wansati a nga ambali swiambalo swa wanuna, ni wanuna a nga ambali swiambalo swa wansati; hikuva mani na mani la endlaka sweswo u nyenyentsa Yehovha Xikwembu xa wena.' },
    { n: 6, text: 'Loko u kuma xisaka xa nyanyana endleleni emurhini wun’wana ni wun’wana kumbe ehansi, xi ri na mavondlo kumbe matandza, kutani mana wa tona a fukamela mavondlo kumbe matandza, u nga teki mana wa tona xikan’we ni vana;' },
    { n: 7, text: 'kambe u ta tshika mana wa tona a famba, u teka vana ntsena; leswaku swi ku fambela kahle ni leswaku u ndlandlamuxa masiku ya wena.' },
    { n: 8, text: 'Loko u aka yindlu yintshwa, u ta akela lwangu ra wena khumbi, leswaku u nga tisi ngati endlwini ya wena, loko munhu a wa ehenhla ka rona.' },
    { n: 9, text: 'U nga byali nsimu ya wena ya vhinya hi mixaka yimbirhi ya timbewu; leswaku ntshovelo hinkwawo wa mbewu leyi u yi byaleke ni ntshovelo wa nsimu ya vhinya swi nga nyamisiwi.' },
    { n: 10, text: 'U nga rimi hi homu ni mbhongolo swi bohiwe xikan’we.' },
    { n: 11, text: 'U nga ambali xiambalo lexi lukiweke hi voya ni nguvu ya ntsembyani xikan’we.' },
    { n: 12, text: 'U ta tiendlela makhubu etinhleni ta mune ta xiambalo xa wena lexi u tifunengetaka ha xona.' },
    { n: 13, text: 'Loko wanuna a teka nsati, a nghena eka yena, kutani a n’wi venga,' },
    { n: 14, text: 'a n’wi hehla hi timhaka ta ku n’wi khomisa tingana, a onha vito ra yena lerinene, a ku: ‘Ndzi teke wansati loyi, kambe loko ndzi nghena eka yena, a ndzi kumanga vuntombi eka yena;' },
    { n: 15, text: 'kutani tata wa nhwanyana ni mana wa yena va ta teka swikombiso swa vuntombi bya nhwanyana, va swi tisa eka vadyuhari va muti enyangweni;' },
    { n: 16, text: 'tata wa nhwanyana u ta byela vadyuhari a ku: ‘Ndzi nyike wansati loyi n’wana wa mina leswaku a va nsati wa yena, kambe u n’wi vengile;' },
    { n: 17, text: 'vonani, u n’wi hehla hi timhaka to khomisa tingana, a ku: A ndzi kumanga vuntombi eka n’wana wa wena; kambe leswi i swikombiso swa vuntombi bya n’wana wa mina.’ Kutani va ta phutulla nguvu mahlweni ka vadyuhari va muti.' },
    { n: 18, text: 'Kutani vadyuhari va muti wolowo va ta teka wanuna yoloye va n’wi ba,' },
    { n: 19, text: 'va n’wi hlawurisa tihekele ta dzana ta silivhere, va ti nyika tata wa nhwanyana, hikuva u onhile vito lerinene ra nhwanyana wa Muisrayele; kutani wansati u ta va nsati wa yena, a nge n’wi tshiki vutomi bya yena hinkwabyo.' },
    { n: 20, text: 'Kambe loko mhaka leyi yi ri ntiyiso, naswona vuntombi byi nga kumekanga eka nhwanyana;' },
    { n: 21, text: 'va ta humesa nhwanyana enyangweni ya yindlu ya tata wa yena, kutani vavanuna va muti wa yena va ta n’wi khandla hi maribye a fa; hikuva u endle vuphukuphuku exikarhi ka Israyele, hi ku endla vunghwavila endlwini ya tata wa yena. Hi mukhuva wolowo u ta susa vubihi exikarhi ka wena.' },
    { n: 22, text: 'Loko wanuna a kumeka a etlele ni wansati la tekiweke hi wanuna un’wana, havambirhi va ta fa, wanuna la etleleke ni wansati, ni wansati hi byakwe. Hi mukhuva wolowo u ta susa vubihi exikarhi ka Israyele.' },
    { n: 23, text: 'Loko nhwanyana wa ntombi a tshembisiwile eka wanuna, kutani wanuna un’wana a n’wi kuma emutini, a etlela na yena;' },
    { n: 24, text: 'mi ta va humesa havambirhi enyangweni ya muti wolowo, mi va khandla hi maribye va fa; nhwanyana hikuva a nga huwelelanga, hambileswi a a ri emutini; naswona wanuna hikuva u tsongahatile nsati wa munhu-kulobye. Hi mukhuva wolowo u ta susa vubihi exikarhi ka wena.' },
    { n: 25, text: 'Kambe loko wanuna a kuma nhwanyana la tshembisiweke endle, kutani wanuna a n’wi khoma hi matimba a etlela na yena; wanuna la etleleke na yena u ta fa yexe;' },
    { n: 26, text: 'kambe eka nhwanyana u nga endli nchumu; a ku na xidyoho lexi faneleke rifu eka nhwanyana; hikuva mhaka leyi yi fana ni loko munhu a pfukela munhu-kulobye a n’wi dlaya;' },
    { n: 27, text: 'hikuva u n’wi kume endle, kutani nhwanyana la tshembisiweke a huwelela, kambe ku nga ri na munhu wo n’wi ponisa.' },
    { n: 28, text: 'Loko wanuna a kuma nhwanyana wa ntombi loyi a nga tshembisiwangiki, a n’wi khoma a etlela na yena, kutani va kumeka;' },
    { n: 29, text: 'wanuna la etleleke na yena u ta nyika tata wa nhwanyana tihekele ta makume ntlhanu ta silivhere, kutani nhwanyana u ta va nsati wa yena, hikuva u n’wi tsongahatile; a nge n’wi tshiki vutomi bya yena hinkwabyo.' },
    { n: 30, text: 'Wanuna a nga teki nsati wa tata wa yena, naswona a nga fununguli nguvu ya tata wa yena.' }
  ],
  23: [
    { n: 1, text: 'Munhu loyi a pfotlosiweke machende kumbe ku tsemiwa xirho xa wumbewu a nga ngheni evandleni ra Yehovha.' },
    { n: 2, text: 'N’wana wa vusumbhwa a nga ngheni evandleni ra Yehovha; hambi ku ri xitukulwana xa yena xa vukhume xi nga ngheni evandleni ra Yehovha.' },
    { n: 3, text: 'Muvamoni kumbe Mumowabu a nga ngheni evandleni ra Yehovha; hambi ku ri xitukulwana xa vona xa vukhume xi nga ngheni evandleni ra Yehovha ni siku ni rin’we;' },
    { n: 4, text: 'hikuva a va mi hlangabezanga hi vuswa ni mati endleleni, loko mi huma eEgipta; naswona hikuva va thole Balamu n’wana wa Bewori wa le Petoro eMesopotamiya, leswaku a ku rhukana.' },
    { n: 5, text: 'Kambe Yehovha Xikwembu xa wena a nga lavanga ku yingisa Balamu; kambe Yehovha Xikwembu xa wena u hundzule ndzhukano wu va nkateko eka wena, hikuva Yehovha Xikwembu xa wena u ku rhandzile.' },
    { n: 6, text: 'U nga lavi ku rhula ka vona ni leswinene swa vona hi masiku ya wena hinkwawo.' },
    { n: 7, text: 'U nga nyenyi Muedomo, hikuva i makwenu. U nga nyenyi Muegipta, hikuva u vile muluveri etikweni ra yena.' },
    { n: 8, text: 'Vana lava tswariwaka eka vona exikulwaneni xa vunharhu va nga nghena evandleni ra Yehovha.' },
    { n: 9, text: 'Loko u famba hi nxaxa ku ya lwa ni valala va wena, u ta tivonela eka swilo hinkwaswo swo biha.' },
    { n: 10, text: 'Loko ku ri ni munhu exikarhi ka wena loyi a nga basangiki hikwalaho ka leswi endlekeke nivusiku, u ta huma a ya ehandle ka nxaxa, a nga ngheni exikarhi ka nxaxa;' },
    { n: 11, text: 'kambe loko ri xwa, u ta hlamba hi mati, kutani loko dyambu ri pela, a nga nghena nxaxeni.' },
    { n: 12, text: 'U ta va ni ndhawu ehandle ka nxaxa, laha u nga ta humela ehandle kona;' },
    { n: 13, text: 'naswona u ta va ni xitirho exikarhi ka matlhari ya wena; kutani loko u tshama ehansi ehandle, u ta cela hi xona, u tlhela u siva leswi humeke eka wena;' },
    { n: 14, text: 'hikuva Yehovha Xikwembu xa wena u famba-famba exikarhi ka nxaxa wa wena, ku ku ponisa, ni ku nyiketa valala va wena eka wena; hikwalaho nxaxa wa wena wu ta kwetsima, leswaku a nga voni nchumu lowu nyenyentsaka eka wena, kutani a fularhela ku ku pfuna.' },
    { n: 15, text: 'U nga nyiketi nandza eka n’wini wa yena, loyi a balekeleke eka wena ku suka eka n’wini wa yena;' },
    { n: 16, text: 'u ta tshama na wena, exikarhi ka wena, endhawini leyi a yi hlawulaka eka yin’we ya tinyangwa ta wena laha a tsakelaka kona; u nga n’wi xanisi.' },
    { n: 17, text: 'Ku nga vi ni nghwavila ya tempele exikarhi ka vana va xisati va Israyele, naswona ku nga vi ni nghwavila ya xinuna ya tempele exikarhi ka vana va xinuna va Israyele.' },
    { n: 18, text: 'U nga tisi hakelo ya nghwavila kumbe mali ya mbyana endlwini ya Yehovha Xikwembu xa wena ku endla xihlambanyo xihi na xihi; hikuva haswimbirhi swa nyenyentsa eka Yehovha Xikwembu xa wena.' },
    { n: 19, text: 'U nga lombisi makwenu hi ntswalo; ntswalo wa mali, ntswalo wa swakudya, kumbe ntswalo wa nchumu wihi na wihi lowu lombisiwaka hi ntswalo;' },
    { n: 20, text: 'munhu mambe u nga n’wi lombisa hi ntswalo, kambe makwenu u nga n’wi lombisi hi ntswalo; leswaku Yehovha Xikwembu xa wena a ku katekisa eka hinkwaswo leswi u nghenisaka voko ra wena eka swona, etikweni leri u yaka eka rona ku ri teka.' },
    { n: 21, text: 'Loko u endla xihlambanyo eka Yehovha Xikwembu xa wena, u nga hlweli ku xi hetisisa; hikuva Yehovha Xikwembu xa wena u ta xi lava eka wena, kutani swi ta va xidyoho eka wena.' },
    { n: 22, text: 'Kambe loko u nga hlambanyi nchumu, a swi nge vi xidyoho eka wena.' },
    { n: 23, text: 'Leswi humeke emilonyeni ya wena u ta swi hlayisa u swi endla; xihlambanyo xa ku tirhandzela lexi u xi endleleke Yehovha Xikwembu xa wena, lexi u xi vuleke hi nomu wa wena.' },
    { n: 24, text: 'Loko u nghena ensin’wini ya vhinya ya makwenu, u nga dya madiriva hilaha u tsakelaka hakona ku fika loko u xurha; kambe u nga cheli nchumu xibyeni xa wena.' },
    { n: 25, text: 'Loko u nghena exikarhi ka mavele lawa ya nga siki tsemiwaka ya makwenu, u nga tsema minxaxa hi voko ra wena; kambe u nga veki rihwevo eka mavele ya makwenu.' }
  ],
24: [
    { n: 1, text: 'Loko wanuna a teka nsati a nghenisa endlwini ya yena, kutani a nga ha n’wi tsakeli hikuva a vone nchumu wo nyenyentsa eka yena, u ta n’wi tsalela papila ra ku dlaya vukati, a n’wi nyika evokweni ra yena, a n’wi humesa endlwini ya yena.' },
    { n: 2, text: 'Loko a humile endlwini ya yena, a nga famba a ya tekiwa hi wanuna un’wana.' },
    { n: 3, text: 'Kutani loko wanuna wa vumbirhi a n’wi venga, a n’wi tsalela papila ra ku dlaya vukati, a n’wi nyika evokweni ra yena, a n’wi humesa endlwini ya yena; kumbe loko wanuna wa vumbirhi loyi a n’wi tekeke a fa;' },
    { n: 4, text: 'nuna wa yena wo sungula loyi a n’wi hlongoleke, a nga fanelanga ku n’wi teka nakambe a va nsati wa yena, endzhaku ka loko a nyamisiwile; hikuva sweswo i manyala mahlweni ka Yehovha; u nga tisi xidyoho etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona ku va ndzhaka.' },
    { n: 5, text: 'Loko wanuna a tekile nsati lontshwa, a nga fambi enyimpini, naswona a nga rhwexiwi ntirho wihi na wihi; u ta tshama ekaya lembe rin’we a ntshunxekile, a tsakisa nsati wa yena loyi a n’wi tekeke.' },
    { n: 6, text: 'Munhu a nga teki ribye ro sila kumbe ribye ra le henhla ku va xibambiso; hikuva swi fana ni ku teka vutomi bya munhu ku va xibambiso.' },
    { n: 7, text: 'Loko munhu a kumeka a yiva un’wana wa vamakwavo exikarhi ka vana va Israyele, a n’wi khoma tanihi nandza kumbe a n’wi xavisa, khamba rero ri ta fa; hi mukhuva wolowo u ta susa vubihi exikarhi ka wena.' },
    { n: 8, text: 'Tivoneleni eka ntungu wa nhlokonho, mi hlayisa swinene, mi endla hi ku ya hi hinkwaswo leswi vaprista ni Valevhi va nga ta mi dyondzisa swona; hilaha ndzi va leriseke hakona, mi ta hlayisa mi swi endla.' },
    { n: 9, text: 'Tsundzukani leswi Yehovha Xikwembu xa n’wina a swi endleke eka Miriyamu endleleni, loko mi huma eEgipta.' },
    { n: 10, text: 'Loko u lombisa makwenu nchumu wihi na wihi, u nga ngheni endlwini ya yena ku ya teka xibambiso xa yena.' },
    { n: 11, text: 'U ta yima ehandle, kutani munhu loyi u n’wi lombiseke u ta ku tisela xibambiso ehandle.' },
    { n: 12, text: 'Loko a ri munhu wo pfumala, u nga etleli hi xibambiso xa yena;' },
    { n: 13, text: 'u ta n’wi tlhelisela xibambiso loko dyambu ri pela, leswaku a etlela exiambalweni xa yena, a ku katekisa; kutani swi ta va ku lulama eka wena mahlweni ka Yehovha Xikwembu xa wena.' },
    { n: 14, text: 'U nga xanisi mutirhi wa ntsengo loyi a nga xisiwana ni mupfumali, hambi a ri un’wana wa vamakwenu kumbe un’wana wa valuveri lava nga etikweni ra wena endhawini ya wena;' },
    { n: 15, text: 'u ta n’wi nyika hakelo ya yena hi siku rero, dyambu ri nga si pela; hikuva i xisiwana, naswona mbilu ya yena yi titshege hi yona; leswaku a nga ku hehli eka Yehovha, kutani swi va xidyoho eka wena.' },
    { n: 16, text: 'Vatata a va fanelanga ku dlayiwa hikwalaho ka vana, ni vana a va fanelanga ku dlayiwa hikwalaho ka vatata; un’wana ni un’wana u ta dlayiwa hikwalaho ka xidyoho xa yena.' },
    { n: 17, text: 'U nga soholoti vululami eka muluveri kumbe xisiwana; naswona u nga teki xiambalo xa noni ku va xibambiso;' },
    { n: 18, text: 'kambe u ta tsundzuka leswaku a wu ri hlonga eEgipta, naswona Yehovha Xikwembu xa wena u ku kutsurile kwalaho; hikwalaho ndzi ku lerisaka ku endla mhaka leyi.' },
    { n: 19, text: 'Loko u tshovela ntshovelo wa wena ensin’wini ya wena, kutani u rivala xitshuva ensin’wini, u nga tlheleli ku ya xi teka; xi ta va xa muluveri, ni xisiwana, ni noni; leswaku Yehovha Xikwembu xa wena a ku katekisa mintirhweni hinkwayo ya mavoko ya wena.' },
    { n: 20, text: 'Loko u hula murhi wa wena wa mutlhwari, u nga tlheleli emarhavini ya wona nakambe; swi ta va swa muluveri, ni xisiwana, ni noni.' },
    { n: 21, text: 'Loko u khakha nsimu ya wena ya vhinya, u nga rholeli madiriva lama seleke; ma ta va ya muluveri, ni xisiwana, ni noni.' },
    { n: 22, text: 'U ta tsundzuka leswaku a wu ri hlonga etikweni ra Egipta; hikwalaho ndzi ku lerisaka ku endla mhaka leyi.' }
  ],
  25: [
    { n: 1, text: 'Loko ku ri ni mholovo exikarhi ka vavanuna, kutani va ya ehubyeni, vaavanyisi va ta va avanyisa; va ta tsetselela la lulameke, va ba la nga ni nandzu.' },
    { n: 2, text: 'Loko loyi a nga ni nandzu a fanele ku biwa, muavanyisi u ta n’wi etlelisa ehansi, a biwa mahlweni ka yena hi nhlayo leyi ringanaka ni nandzu wa yena.' },
    { n: 3, text: 'Va nga n’wi ba hi minkhavi ya makume-mune, kambe va nga hundzi; hikuva loko a biwa hi minkhavi yo tala ku tlula leyi, makwenu u ta tsongahatiwa ematihlweni ya wena.' },
    { n: 4, text: 'U nga bohi nomu wa homu loko yi hula mavele.' },
    { n: 5, text: 'Loko vamakwavo va tshama swin’we, kutani un’wana wa vona a fa a nga ri na n’wana wa xinuna, nsati wa mufi a nga tekiwi hi wanuna wambe ehandle; makwavo wa nuna wa yena u ta nghena eka yena, a n’wi teka a va nsati wa yena, a n’wi pfuxela vana.' },
    { n: 6, text: 'Kutani mativula lawa a nga ta ma tswala ma ta vuriwa hi vito ra makwavo loyi a feke, leswaku vito ra yena ri nga suliwi exikarhi ka Israyele.' },
    { n: 7, text: 'Kambe loko wanuna a nga lavi ku teka nsati wa makwavo, nsati wa makwavo u ta ya enyangweni eka vadyuhari, a ku: ‘Makwavo wa nuna wa mina u arile ku pfuxa vito ra makwavo exikarhi ka Israyele, a nga pfumeli ku hetisisa mfanelo ya yena eka mina.' },
    { n: 8, text: 'Kutani vadyuhari va muti wa yena va ta n’wi vitana va vulavula na yena; loko a yima a ku: ‘A ndzi lavi ku n’wi teka;' },
    { n: 9, text: 'nsati wa makwavo u ta tshinela eka yena mahlweni ka vadyuhari, a n’wi hluvula tintanghu ta yena enengeni, a n’wi tshwutela evusweni, a hlamula a ku: ‘Ku ta endliwa tano eka wanuna loyi a nga akiki yindlu ya makwavo.' },
    { n: 10, text: 'Kutani vito ra yena exikarhi ka Israyele ri ta vuriwa yindlu ya loyi a hluvuriweke tintanghu.' },
    { n: 11, text: 'Loko vavanuna vambirhi va lwa, kutani nsati wa un’wana a tshinela ku ponisa nuna wa yena evokweni ra loyi a n’wi baka, a tshambuluta voko ra yena a khoma vuxinuna bya yena;' },
    { n: 12, text: 'u ta n’wi tsema voko; tihlo ra wena ri nga n’wi tsetseleli.' },
    { n: 13, text: 'U nga vi ni swikalo swimbirhi swo hambana enkwameni wa wena, lexikulu ni lexitsongo.' },
    { n: 14, text: 'U nga vi ni swipimo swimbirhi swo hambana endlwini ya wena, lexikulu ni lexitsongo.' },
    { n: 15, text: 'U ta va ni xikalo lexinene ni xo lulama, u ta va ni xipimo lexinene ni xo lulama; leswaku masiku ya wena ma leha etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona.' },
    { n: 16, text: 'Hikuva mani na mani la endlaka swilo leswi, hinkwavo lava endlaka leswi nga lulamangiki, va nyenyentsa Yehovha Xikwembu xa wena.' },
    { n: 17, text: 'Tsundzuka leswi Amaleke a ku endleleke swona endleleni, loko mi huma eEgipta;' },
    { n: 18, text: 'hilaha a ku hlangabezeke hakona endleleni, a ba lava a va salele endzhaku ka wena, lava a va tsanile endzhaku ka wena, loko wena a wu karhele ni ku hela matimba; naswona a nga chavanga Xikwembu.' },
    { n: 19, text: 'Hikwalaho, loko Yehovha Xikwembu xa wena a ku nyikile ku rhula eka valala va wena hinkwavo lava ku rhendzeleke, etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona ku va ndzhaka leswaku u ri teka; u ta sula vito ra Amaleke ehansi ka tilo; u nga rivali.' }
  ],
  26: [
    { n: 1, text: 'Loko u nghena etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona ku va ndzhaka, u ri teka, u tshama eka rona;' },
    { n: 2, text: 'u ta teka mativula ya mihandzu hinkwayo ya misava, leyi u nga ta yi tisa ku suka etikweni ra wena leri Yehovha Xikwembu xa wena a ku nyikaka rona, u swi chela exidyundzwini, u famba endhawini leyi Yehovha Xikwembu xa wena a nga ta yi hlawula leswaku a tshikisa vito ra yena kona.' },
    { n: 3, text: 'U ta ya eka muprista loyi a nga ta va kona emasikwini wolawo, u ku eka yena: ‘Ndzi vula namuntlha mahlweni ka Yehovha Xikwembu xa wena, leswaku ndzi nghenile etikweni leri Yehovha a ri hlambanyeleke vatata wa hina ku hi nyika rona.' },
    { n: 4, text: 'Kutani muprista u ta teka xidyundzhu evokweni ra wena, a xi veka mahlweni ka altari ya Yehovha Xikwembu xa wena.' },
    { n: 5, text: 'U ta hlamula u vula mahlweni ka Yehovha Xikwembu xa wena u ku: ‘Tatana a a ri Muaramiya loyi a a famba-famba, a xika eEgipta a ya luvela kona a ri ni vanhu vatsongo; kambe kwalaho u ve tiko lerikulu, ra matimba ni ro tala.' },
    { n: 6, text: 'Kutani vaEgipta va hi xanisa, va hi tsikilela, va hi rhwexa ntirho wo tika;' },
    { n: 7, text: 'hi huwelela eka Yehovha Xikwembu xa vatata wa hina; Yehovha a twa rito ra hina, a vona ku xaniseka ka hina, ni ku tikeriwa ka hina, ni ku tsikileliwa ka hina.' },
    { n: 8, text: 'Yehovha a hi humesa eEgipta hi voko ra matimba, ni hi voko leri tshambulutiweke, hi ku chava lokukulu, hi swikombiso ni masingita;' },
    { n: 9, text: 'a hi tisa endhawini leyi, a hi nyika tiko leri, tiko leri khulukaka ntsamba ni vulombe.' },
    { n: 10, text: 'Kutani sweswi, vonani, ndzi tisile mativula ya mihandzu ya misava leyi Wena Yehovha u ndzi nyikeke yona.’ U ta yi veka mahlweni ka Yehovha Xikwembu xa wena, u khizamela mahlweni ka Yehovha Xikwembu xa wena;' },
    { n: 11, text: 'u ta tsaka hi swinene hinkwaswo leswi Yehovha Xikwembu xa wena a ku nyikeke swona, wena ni yindlu ya wena, ni Mulevhi, ni muluveri loyi a nga exikarhi ka wena.' },
    { n: 12, text: 'Loko u hetile ku humesa vukhume hinkwabyo bya ntshovelo wa wena hi lembe ra vunharhu, ku nga lembe ra vukhume, u ta yi nyika Mulevhi, muluveri, xisiwana, ni noni, leswaku va dya emitini ya wena, va xurha;' },
    { n: 13, text: 'kutani u ta ku mahlweni ka Yehovha Xikwembu xa wena: ‘Ndzi susile swilo leswi kwetsimaka endlwini ya mina, naswona ndzi swi nyikile Mulevhi, muluveri, xisiwana, ni noni, hi ku ya hi xileriso xa wena hinkwaxo lexi u ndzi leriseke xona; a ndzi tlulanga swileriso swa wena, naswona a ndzi swi rivalanga.' },
    { n: 14, text: 'A ndzi dyanga nchumu wa swona loko ndzi ri eku rileni, a ndzi susanga nchumu wa swona loko ndzi nga basanga, naswona a ndzi nyikanga nchumu wa swona eka lava feke; ndzi yingisile rito ra Yehovha Xikwembu xa mina, ndzi endlile hinkwaswo hilaha u ndzi leriseke hakona.' },
    { n: 15, text: 'Languta ehansi u ri evutshan’wini bya wena byo kwetsima, etilweni, u katekisa vanhu va wena Israyele, ni tiko leri u hi nyikeke rona, hilaha u hlambanyeleke vatata wa hina hakona, tiko leri khulukaka ntsamba ni vulombe.' },
    { n: 16, text: 'Namuntlha Yehovha Xikwembu xa wena u ku lerisa ku endla milawu leyi ni swiavanyiso; u ta yi hlayisa ni ku yi endla hi mbilu ya wena hinkwayo ni hi moya wa wena hinkwawo.' },
    { n: 17, text: 'Namuntlha u vurile Yehovha leswaku u ta va Xikwembu xa wena, ni leswaku u ta famba etindleleni ta yena, u hlayisa milawu ya yena, swileriso swa yena, ni swiavanyiso swa yena, ni ku yingisa rito ra yena;' },
    { n: 18, text: 'naswona Yehovha u ku vurile namuntlha leswaku u ta va vanhu va yena vo hlawuleka, hilaha a ku tshembiseke hakona, ni leswaku u hlayisa swileriso swa yena hinkwaswo;' },
    { n: 19, text: 'leswaku a ku tlakusa ehenhla ka matiko hinkwawo lawa a ma endleke, eku dzuniseni, eku dhumeni, ni le ku kwetsimeni; ni leswaku u ta va vanhu vo kwetsima eka Yehovha Xikwembu xa wena, hilaha a vuleke hakona.' }
  ],
  27: [
      { n: 1, text: 'Kutani Muxe ni vadyuhari va Israyele va lerisa vanhu, va ku: ‘Hlayisani xileriso hinkwaxo lexi ndzi mi lerisaka xona namuntlha.' },
      { n: 2, text: 'Kutani hi siku leri mi nga ta tsemakanya Yordani ku nghena etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona, u ta tiyimisa maribye lamakulu, u ma phasa hi mupula;' },
      { n: 3, text: 'u ta tsala ehenhla ka wona marito hinkwawo ya nawu lowu, loko u tsemakanyile, leswaku u nghena etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona, tiko leri khulukaka ntsamba ni vulombe, hilaha Yehovha Xikwembu xa vatata wa wena a ku tshembiseke hakona.' },
      { n: 4, text: 'Kutani loko mi tsemakanyile Yordani, mi ta yimisa maribye lawa, hilaha ndzi mi lerisaka hakona namuntlha, entshaveni ya Ebali, u ma phasa hi mupula.' },
      { n: 5, text: 'Kutani kwalaho u ta akela Yehovha Xikwembu xa wena altari, altari ya maribye; u nga ma vatli hi nsimbi.' },
      { n: 6, text: 'U ta aka altari ya Yehovha Xikwembu xa wena hi maribye lama nga vatliwangi; u ta humesela Yehovha Xikwembu xa wena magandzelo ya ku hisiwa ehenhla ka yona;' },
      { n: 7, text: 'naswona u ta tlhaba magandzelo ya ku rhula, u ma dyela kwalaho; u ta tsaka mahlweni ka Yehovha Xikwembu xa wena.' },
      { n: 8, text: 'U ta tsala emaribyeni marito hinkwawo ya nawu lowu, swi hlamuseleka kahle.' },
      { n: 9, text: 'Kutani Muxe ni vaprista va Valevhi va byela Israyele hinkwawo va ku: ‘Miyela u yingisa, Wena Israyele; namuntlha u vile vanhu va Yehovha Xikwembu xa wena.' },
      { n: 10, text: 'Hikwalaho u ta yingisa rito ra Yehovha Xikwembu xa wena, u endla swileriso swa yena ni milawu ya yena, leswi ndzi ku lerisaka swona namuntlha.' },
      { n: 11, text: 'Muxe a lerisa vanhu hi siku rero, a ku:' },
      { n: 12, text: 'Lava hi lava nga ta yima entshaveni ya Gerezimi ku katekisa vanhu, loko mi tsemakanyile Yordani: Simiyoni, Levhi, Yuda, Isakari, Yosefa, na Benjamini.' },
      { n: 13, text: 'Lava hi lava nga ta yima entshaveni ya Ebali ku rhukana: Ruvene, Gadi, Axeri, Zebuloni, Dani, na Naftali.' },
      { n: 14, text: 'Kutani Valevhi va ta hlamula, va byela vavanuna hinkwavo va Israyele hi rito leri tlakukeke, va ku:' },
      { n: 15, text: 'A ku rhukaniwe munhu loyi a endlaka xifaniso xo vatliwa kumbe xo n’wakisiwa, nchumu lowu nyenyentsaka eka Yehovha, ntirho wa mavoko ya mutirhi, a xi veka exihundleni. Kutani vanhu hinkwavo va ta hlamula va ku: “Amen.' },
      { n: 16, text: 'A ku rhukaniwe loyi a tsongahataka tata wa yena kumbe mana wa yena. Kutani vanhu hinkwavo va ta ku: “Amen.' },
      { n: 17, text: 'A ku rhukaniwe loyi a susaka ndzilakano wa munhu-kulobye. Kutani vanhu hinkwavo va ta ku: “Amen.' },
      { n: 18, text: 'A ku rhukaniwe loyi a hambukisaka bofu endleleni. Kutani vanhu hinkwavo va ta ku: “Amen.' },
      { n: 19, text: 'A ku rhukaniwe loyi a soholotaka vululami bya muluveri, ni xisiwana, ni noni. Kutani vanhu hinkwavo va ta ku: “Amen.' },
      { n: 20, text: 'A ku rhukaniwe loyi a etlelaka ni nsati wa tata wa yena, hikuva u funungula nguvu ya tata wa yena. Kutani vanhu hinkwavo va ta ku: “Amen.' },
      { n: 21, text: 'A ku rhukaniwe loyi a etlelaka ni xifuwo xihi na xihi. Kutani vanhu hinkwavo va ta ku: “Amen.' },
      { n: 22, text: 'A ku rhukaniwe loyi a etlelaka ni makwavo wa yena wa xisati, n’wana wa tata wa yena kumbe n’wana wa mana wa yena. Kutani vanhu hinkwavo va ta ku: “Amen.' },
      { n: 23, text: 'A ku rhukaniwe loyi a etlelaka ni mhana-nhamu wa yena. Kutani vanhu hinkwavo va ta ku: “Amen.' },
      { n: 24, text: 'A ku rhukaniwe loyi a dlayaka munhu-kulobye exihundleni. Kutani vanhu hinkwavo va ta ku: “Amen.' },
      { n: 25, text: 'A ku rhukaniwe loyi a tekaka hakelo leswaku a dlaya munhu la nga riki na nandzu. Kutani vanhu hinkwavo va ta ku: “Amen.' },
      { n: 26, text: 'A ku rhukaniwe loyi a nga tiyisisiki marito ya nawu lowu ku ma endla. Kutani vanhu hinkwavo va ta ku: “Amen.' }
    ],
  28: [
    { n: 1, text: 'Loko u yingisa rito ra Yehovha Xikwembu xa wena hi vukheta, ku hlayisa ni ku endla swileriso swa yena hinkwaswo leswi ndzi ku lerisaka swona namuntlha, Yehovha Xikwembu xa wena u ta ku tlakusa ehenhla ka matiko hinkwawo ya misava;' },
    { n: 2, text: 'kutani mikateko leyi hinkwayo yi ta ku wela, yi ku kuma, loko u yingisa rito ra Yehovha Xikwembu xa wena.' },
    { n: 3, text: 'U ta katekisiwa emutini, naswona u ta katekisiwa enhoveni.' },
    { n: 4, text: 'Ku ta katekisiwa mbhandzu wa khwiri ra wena, ni mbhandzu wa misava ya wena, ni mbhandzu wa swifuwo swa wena, ku andza ka tihomu ta wena, ni mintlhambi ya tinyimpfi ta wena.' },
    { n: 5, text: 'Ku ta katekisiwa xidyundzhu xa wena ni xisukelo xa wena.' },
    { n: 6, text: 'U ta katekisiwa loko u nghena, naswona u ta katekisiwa loko u huma.' },
    { n: 7, text: 'Yehovha u ta endla leswaku valala va wena lava ku pfukelaka va hluriwa mahlweni ka wena; va ta huma ku lwa na wena hi ndlela yin’we, kambe va ta baleka mahlweni ka wena hi tindlela ta nkombo.' },
    { n: 8, text: 'Yehovha u ta lerisa nkateko ehenhla ka wena eswitlatini swa wena, ni le ka hinkwaswo leswi u nghenisaka voko ra wena eka swona; naswona u ta ku katekisa etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona.' },
    { n: 9, text: 'Yehovha u ta ku tiyisa u va tiko ro kwetsima eka yena, hilaha a ku hlambanyeleke hakona, loko u hlayisa swileriso swa Yehovha Xikwembu xa wena, u famba etindleleni ta yena.' },
    { n: 10, text: 'Kutani matiko hinkwawo ya misava ma ta vona leswaku u vuriwa hi vito ra Yehovha; kutani ma ta ku chava.' },
    { n: 11, text: 'Yehovha u ta ku andzisela leswinene embhandzwini wa khwiri ra wena, ni le mbhandzwini wa swifuwo swa wena, ni le mbhandzwini wa misava ya wena, etikweni leri Yehovha a ri hlambanyeleke vatata wa wena ku ku nyika rona.' },
    { n: 12, text: 'Yehovha u ta ku pfula xitiko xa yena lexinene, tilo, ku nyika mpfula etikweni ra wena hi nkarhi wa yona, ni ku katekisa ntirho hinkwawo wa voko ra wena; u ta lombisa matiko yo tala, kambe wena a wu nge lombi.' },
    { n: 13, text: 'Yehovha u ta ku endla nhloko, u nga vi ncila; u ta va ehenhla ntsena, a wu nge vi ehansi; loko u yingisa swileriso swa Yehovha Xikwembu xa wena, leswi ndzi ku lerisaka swona namuntlha, ku swi hlayisa ni ku swi endla;' },
    { n: 14, text: 'naswona u nga hambuki eka marito hinkwawo lawa ndzi ku lerisaka wona namuntlha, u ya exineneni kumbe eximatsini, ku landzela swikwembu swin’wana ku swi tirhela.' },
    { n: 15, text: 'Kambe loko u nga yingisi rito ra Yehovha Xikwembu xa wena, ku hlayisa ni ku endla swileriso swa yena hinkwaswo ni milawu ya yena leyi ndzi ku lerisaka yona namuntlha, mindzhukano leyi hinkwayo yi ta ku wela, yi ku kuma.' },
    { n: 16, text: 'U ta rhukaniwa emutini, naswona u ta rhukaniwa enhoveni.' },
    { n: 17, text: 'Ku ta rhukaniwa xidyundzhu xa wena ni xisukelo xa wena.' },
    { n: 18, text: 'Ku ta rhukaniwa mbhandzu wa khwiri ra wena, ni mbhandzu wa misava ya wena, ku andza ka tihomu ta wena, ni mintlhambi ya tinyimpfi ta wena.' },
    { n: 19, text: 'U ta rhukaniwa loko u nghena, naswona u ta rhukaniwa loko u huma.' },
    { n: 20, text: 'Yehovha u ta rhuma ehenhla ka wena ndzhukano, ku pfilunganyeka, ni ku tshinyiwa, eka hinkwaswo leswi u nghenisaka voko ra wena eka swona ku swi endla, ku fika loko u lovisiwa, ni ku fika loko u hela hi ku hatlisa; hikwalaho ka vubihi bya swiendlo swa wena, leswi u ndzi tshikeke ha swona.' },
    { n: 21, text: 'Yehovha u ta namarheta ntungu eka wena, ku fika loko a ku herisa etikweni leri u yaka eka rona ku ri teka.' },
    { n: 22, text: 'Yehovha u ta ku ba hi vuvabyi byo onha, ni mukhuhlwane, ni ku pfurha, ni ku hisa swinene, ni banga, ni nkumba, ni ndzheko; swi ta ku hlongorisa ku fika loko u hela.' },
    { n: 23, text: 'Kutani tilo leri nga ehenhla ka nhloko ya wena ri ta va koporo, naswona misava leyi nga ehansi ka wena yi ta va nsimbi.' },
    { n: 24, text: 'Yehovha u ta hundzula mpfula ya tiko ra wena yi va ritshuri ni ntshuri; swi ta xika hi le tilweni ehenhla ka wena, ku fika loko u lovisiwa.' },
    { n: 25, text: 'Yehovha u ta endla leswaku u hluriwa mahlweni ka valala va wena; u ta huma ku lwa na vona hi ndlela yin’we, kambe u ta baleka mahlweni ka vona hi tindlela ta nkombo; u ta va xilo xo chuhisa eka mimfumo hinkwayo ya misava.' },
    { n: 26, text: 'Ntsumbu wa wena wu ta va swakudya swa tinyanyana hinkwato ta tilo ni swivandzana swa misava; a ku nge vi na munhu wo swi hlongola.' },
    { n: 27, text: 'Yehovha u ta ku ba hi swilondza swa le Egipta, ni hi mathumba, ni hi vuvabyi bya nhlonge, ni hi mavele, leswi u nga ta tsandzeka ku horisiwa eka swona.' },
    { n: 28, text: 'Yehovha u ta ku ba hi ku hlanya, ni hi vubofu, ni hi ku pfilunganyeka ka mbilu;' },
    { n: 29, text: 'u ta phuphuthela ninhlikanhi, hilaha bofu ri phuphuthelaka hakona emunyameni, kambe u nge humeleli etindleleni ta wena; u ta xanisiwa ni ku phangiwa masiku hinkwawo, a ku nge vi na munhu wo ku ponisa.' },
    { n: 30, text: 'U ta tshembisa wansati vukati, kambe wanuna un’wana u ta etlela na yena; u ta aka yindlu, kambe u nge tshami eka yona; u ta byala nsimu ya vhinya, kambe u nge dyi mihandzu ya yona.' },
    { n: 31, text: 'Homu ya wena yi ta tlhavelawa mahlweni ka mahlo ya wena, kambe u nge dyi nyama ya yona; mbhongolo ya wena yi ta tekiwa mahlweni ka wena, yi nga tlheriseriwi eka wena; tinyimpfi ta wena ti ta nyikiwa valala va wena, a ku nge vi na munhu wo ku ponisa.' },
    { n: 32, text: 'Vana va wena va xinuna ni vana va wena va xisati va ta nyikiwa vanhu van’wana, naswona mahlo ya wena ma ta swi vona, ma pfumala matimba masiku hinkwawo hikwalaho ka vona; a ku nge vi na matimba evokweni ra wena.' },
    { n: 33, text: 'Mbhandzu wa misava ya wena, ni mintirho ya wena hinkwayo, ku ta dya tiko leri u nga ri tiviki; u ta va munhu la xanisiwaka ni ku pfotlosiwa masiku hinkwawo;' },
    { n: 34, text: 'leswaku u hlanya hikwalaho ka ku vona ka mahlo ya wena, leswi u nga ta swi vona.' },
    { n: 35, text: 'Yehovha u ta ku ba ematsolweni ni le milengeni hi swilondza swo vava leswi u nga ta tsandzeka ku horisiwa eka swona, ku suka ehansi ka nenge wa wena ku ya fika enhlokweni ya wena.' },
    { n: 36, text: 'Yehovha u ta ku yisa, wena ni hosi ya wena leyi u nga ta yi veka ehenhla ka wena, etikweni leri wena ni vatata wa wena mi nga ri tivangiki; kwalaho u ta tirhela swikwembu swin’wana, swa mhandzi ni ribye.' },
    { n: 37, text: 'U ta va xilo xo hlamarisa, ni xivuriso, ni xirhuko, exikarhi ka matiko hinkwawo laha Yehovha a nga ta ku yisa kona.' },
    { n: 38, text: 'U ta humesa mbewu yo tala ensin’wini, kambe u ta hlengeleta yitsongo; hikuva tinjiya ti ta yi dya.' },
    { n: 39, text: 'U ta byala masimu ya vhinya u ma rima, kambe u nge nwi vhinyo ni ku khakha madiriva; hikuva xivungu xi ta yi dya.' },
    { n: 40, text: 'U ta va ni mirhi ya mitlhwari endhawini ya wena hinkwayo, kambe u nge toli mafurha; hikuva mutlhwari wa wena wu ta hlakahla mihandzu ya wona.' },
    { n: 41, text: 'U ta tswala vana va xinuna ni vana va xisati, kambe va nge vi va wena; hikuva va ta ya evukhumbini.' },
    { n: 42, text: 'Mirhi ya wena hinkwayo ni mbhandzu wa misava ya wena swi ta dyiwa hi tinjiya.' },
    { n: 43, text: 'Muluveri loyi a nga exikarhi ka wena u ta tlakuka ehenhla ka wena swinene; kambe wena u ta xika ehansi swinene.' },
    { n: 44, text: 'Yena u ta ku lombisa, kambe wena a wu nge n’wi lombisi; yena u ta va nhloko, wena u ta va ncila.' },
    { n: 45, text: 'Mindzhukano leyi hinkwayo yi ta ku wela, yi ku hlongorisa, yi ku kuma, ku fika loko u lovisiwa; hikuva a wu yingisanga rito ra Yehovha Xikwembu xa wena, ku hlayisa swileriso swa yena ni milawu ya yena leyi a ku leriseke yona;' },
    { n: 46, text: 'swi ta va xikombiso ni singita eka wena ni le ka vana va wena hilaha ku nga heriki.' },
    { n: 47, text: 'Hikuva a wu tirhelanga Yehovha Xikwembu xa wena hi ku tsaka ni hi mbilu leyinene, hikwalaho ka ku andza ka swilo hinkwaswo;' },
    { n: 48, text: 'u ta tirhela valala va wena lava Yehovha a nga ta va rhuma ehenhla ka wena, hi ndlala, ni torha, ni vumpon’wa, ni ku pfumala swilo hinkwaswo; yena u ta veka joko ra nsimbi enhan’wini ya wena, ku fika loko a ku lovisa.' },
    { n: 49, text: 'Yehovha u ta tisa tiko ri huma ekule ehenhla ka wena, ri huma emakumu ya misava, ri haha ku fana ni gama; tiko leri u nga ri tiviki ririmi ra rona;' },
    { n: 50, text: 'tiko ra xikandza xo kwinya, leri nga ta ka ri nga tsetseleli mudyuhari kumbe ku twela xihlangi vusiwana;' },
    { n: 51, text: 'ri ta dya mbhandzu wa swifuwo swa wena ni mbhandzu wa misava ya wena, ku fika loko u lovisiwa; leri nga ta ka ri nga ku siyeli mavele, vhinyo, kumbe mafurha, ni ku andza ka tihomu ta wena, kumbe mintlhambi ya tinyimpfi ta wena, ku fika loko ri ku herisa.' },
    { n: 52, text: 'Ri ta ku rhendzela emitini ya wena hinkwayo, ku fika loko makhumbi ya wena yo leha ni lama tiyeke lawa u ma tshembaka ma wa ehansi, etikweni ra wena hinkwaro; ri ta ku rhendzela emitini ya wena hinkwayo, etikweni ra wena hinkwaro leri Yehovha Xikwembu xa wena a ku nyikeke rona.' },
    { n: 53, text: 'U ta dya mbhandzu wa khwiri ra wena, nyama ya vana va wena va xinuna ni va xisati lava Yehovha Xikwembu xa wena a ku nyikeke vona, ekurhendzeriweni ni le mahlomulweni lawa nala wa wena a nga ta ku hlomulisa ha wona.' },
    { n: 54, text: 'Wanuna wo olova exikarhi ka wena ni la titsongahataka ngopfu, tihlo ra yena ri ta va ro biha eka makwavo wa yena, ni le ka nsati wa xifuva xa yena, ni le ka vana va yena lava seleke lava a va siyeke;' },
    { n: 55, text: 'leswaku a nga nyiki na un’we wa vona nyama ya vana va yena leyi a nga ta yi dya, hikuva a nga siyeriwa nchumu ekurhendzeriweni ni le mahlomulweni lawa nala wa wena a nga ta ku hlomulisa ha wona emitini ya wena hinkwayo.' },
    { n: 56, text: 'Wansati wo olova ni la titsongahataka exikarhi ka wena, loyi a a nga ringeti ku veka nenge wa yena ehansi ka misava hikwalaho ka ku titsongahata ni ku olova, tihlo ra yena ri ta va ro biha eka nuna wa xifuva xa yena, ni le ka n’wana wa yena wa xinuna, ni le ka n’wana wa yena wa xisati;' },
    { n: 57, text: 'ni le ka ntswamba lowu humaka exikarhi ka milenge ya yena, ni le ka vana lava a nga ta va tswala; hikuva u ta va dya exihundleni hikwalaho ka ku pfumala swilo hinkwaswo, ekurhendzeriweni ni le mahlomulweni lawa nala wa wena a nga ta ku hlomulisa ha wona emitini ya wena.' },
    { n: 58, text: 'Loko u nga tiyisisi ku endla marito hinkwawo ya nawu lowu tsariweke ebukwini leyi, leswaku u chava vito leri ro kwetsima ni ro chavisa ra YEHOVHA XIKWEMBU XA WENA;' },
    { n: 59, text: 'Yehovha u ta endla makhombo ya wena ma hlamarisa, ni makhombo ya vana va wena; makhombo makulu ni ya nkarhi wo leha, ni mavabyi yo vava ni ya nkarhi wo leha.' },
    { n: 60, text: 'U ta tlhelisela eka wena mavabyi hinkwawo ya le Egipta lawa a wu ma chava; kutani ma ta namarhela eka wena.' },
    { n: 61, text: 'Hambi ku ri vuvabyi byihi na byihi, ni khombo rihi na rihi leswi nga tsariwangiki ebukwini ya nawu lowu, Yehovha u ta swi tisa ehenhla ka wena, ku fika loko u lovisiwa.' },
    { n: 62, text: 'Mi ta sala mi ri vanhu vatsongo hi nhlayo, n’wina lava a mi fana ni tinyeleti ta tilo hi ku tala; hikuva a wu yingisanga rito ra Yehovha Xikwembu xa wena.' },
    { n: 63, text: 'Kutani swi ta endleka leswaku, hilaha Yehovha a tsakeke hakona ehenhla ka n’wina ku mi endlela leswinene ni ku mi andzisa, hi hilaha Yehovha a nga ta tsaka hakona ehenhla ka n’wina ku mi herisa ni ku mi lovisa; mi ta tsuvuriwa etikweni leri mi yaka eka rona ku ri teka.' },
    { n: 64, text: 'Yehovha u ta ku hangalasa exikarhi ka matiko hinkwawo, ku suka emakumu man’we ya misava ku ya fika emakumu man’wana ya misava; kwalaho u ta tirhela swikwembu swin’wana leswi wena ni vatata wa wena mi nga swi tivangiki, swa mhandzi ni ribye.' },
    { n: 65, text: 'Exikarhi ka matiko wolawo a wu nge kumi ku wisa, hambi ku ri nenge wa wena a wu nge kumi ndhawu yo wisa; kambe Yehovha u ta ku nyika kwalaho mbilu leyi rhurhumelaka, ni ku pfafuliwa ka mahlo, ni ku hela ka moya.' },
    { n: 66, text: 'Vutomi bya wena byi ta pfafuliwa mahlweni ka wena; u ta chava vusiku ni nhlikanhi, a wu nge vi na ntshembo hi vutomi bya wena.' },
    { n: 67, text: 'Nimixo u ta ku: ‘Loko a ku ri madyambu!’ kutani nimadyambu u ta ku: ‘Loko a ku ri mixo!’ hikwalaho ka ku chava ka mbilu ya wena leyi u nga ta yi chava, ni hikwalaho ka leswi mahlo ya wena ma nga ta swi vona.' },
    { n: 68, text: 'Yehovha u ta ku tlhelisela eEgipta hi tingalawa, hi ndlela leyi ndzi ku byeleke ndzi ku: ‘A wu nge he tlheli u yi vona; kwalaho mi ta tixavisa eka valala va n’wina ku va malandza ya xinuna ni malandza ya xisati, kambe a ku nge vi na munhu la nga ta mi xava.' }
  ],
  29: [
    { n: 1, text: 'Lawa i marito ya ntwanano lowu Yehovha a leriseke Muxe ku wu endla ni vana va Israyele etikweni ra Mowabu, handle ka ntwanano lowu a wu endleke na vona eHorebe.' },
    { n: 2, text: 'Muxe a vitana Israyele hinkwawo, a ku eka vona: ‘Mi vonile hinkwaswo leswi Yehovha a swi endleke mahlweni ka mahlo ya n’wina etikweni ra Egipta eka Faro, ni le ka malandza ya yena hinkwawo, ni le tikweni ra yena hinkwaro;' },
    { n: 3, text: 'miringo leyikulu leyi mahlo ya wena ma yi voneke, swikombiso sweswo ni masingita wolawo lamakulu;' },
    { n: 4, text: 'kambe Yehovha a nga mi nyikanga mbilu yo twisisa, ni mahlo yo vona, ni tindleve to twa, ku fikela namuntlha.' },
    { n: 5, text: 'Ndzi mi fambisile emananga malembe ya makume-mune; swiambalo swa n’wina a swi hlakalanga ehenhla ka n’wina, ni tintanghu ta n’wina a ti hlakalanga emilengeni ya n’wina.' },
    { n: 6, text: 'A mi dyanga xinkwa, naswona a mi nwanga vhinyo kumbe byalwa byo bava; leswaku mi ta tiva leswaku mina Yehovha ndzi Xikwembu xa n’wina.' },
    { n: 7, text: 'Kutani loko mi fika endhawini leyi, Sihoni hosi ya Hesboni na Ogo hosi ya Baxani va huma ku lwa na hina, kambe hi va hlulile;' },
    { n: 8, text: 'hi teka tiko ra vona, hi ri nyika Varuvheni ni Vagadi ni hafu ya rixaka ra Manase ku va ndzhaka ya vona.' },
    { n: 9, text: 'Hikwalaho hlayisani marito ya ntwanano lowu, mi ma endla, leswaku mi humelela eka hinkwaswo leswi mi swi endlaka.' },
    { n: 10, text: 'Namuntlha mi yimile hinkwenu mahlweni ka Yehovha Xikwembu xa n’wina; tindhuna ta n’wina ta tinyimba ta n’wina, vadyuhari va n’wina, ni valanguteri va n’wina, ku nga vavanuna hinkwavo va Israyele;' },
    { n: 11, text: 'swihlangi swa n’wina, vavasati va n’wina, ni muluveri wa wena loyi a nga exikarhi ka nxaxa wa wena, ku sukela eka mutsemi wa tihunyi ta wena ku fika eka mukhi wa mati ya wena;' },
    { n: 12, text: 'leswaku u nghena entwananweni wa Yehovha Xikwembu xa wena, ni le xihlambanyweni xa yena, lexi Yehovha Xikwembu xa wena a xi endlaka na wena namuntlha;' },
    { n: 13, text: 'leswaku a ku tiyisa namuntlha u va vanhu va yena, ni leswaku yena a va Xikwembu xa wena, hilaha a ku byeleke hakona, ni hilaha a hlambanyeleke vatata wa wena, Abrahama, Isaka, na Yakobo hakona.' },
    { n: 14, text: 'Naswona a hi n’wina ntsena ndzi endlaka ntwanano lowu ni xihlambanyo lexi na n’wina;' },
    { n: 15, text: 'kambe ni loyi a yimeke na hina laha namuntlha mahlweni ka Yehovha Xikwembu xa hina, ni loyi a nga riki na hina laha namuntlha.' },
    { n: 16, text: 'Hikuva n’wina ma swi tiva leswaku hi tshame njhani etikweni ra Egipta, ni leswaku hi hundzise njhani exikarhi ka matiko lawa mi hundzeke eka wona;' },
    { n: 17, text: 'naswona mi vonile swilo swa vona swo nyenyentsa, ni swikwembu swa vona swa mhandzi ni ribye, swa silivhere ni nsuku, leswi a swi ri exikarhi ka vona;' },
    { n: 18, text: 'leswaku ku nga vi na wanuna kumbe wansati, kumbe ndyangu kumbe rixaka exikarhi ka n’wina namuntlha, loyi mbilu ya yena yi fularhelaka Yehovha Xikwembu xa hina, ku ya tirhela swikwembu swa matiko lawa; leswaku ku nga vi na rimitsu exikarhi ka n’wina leri tswalaka vuxungu ni mahlaha;' },
    { n: 19, text: 'kutani swi endleka loko a twa marito ya xihlambanyo lexi, a tikatekisa embilwini ya yena, a ku: “Ndzi ta va ni ku rhula, hambileswi ndzi fambaka eku tiomiseni ka mbilu ya mina, ku onha loku tsakamisaka xikan’we ni loku omeke;' },
    { n: 20, text: 'Yehovha a nge n’wi rivaleli, kambe vukari bya Yehovha ni vulaveti bya yena byi ta pfurhela munhu yoloye, kutani ndzhukano hinkwawo lowu tsariweke ebukwini leyi wu ta n’wi wela, Yehovha u ta sula vito ra yena ehansi ka tilo;' },
    { n: 21, text: 'Yehovha u ta n’wi hlawula ku n’wi endlela makhombo exikarhi ka tinyimba hinkwato ta Israyele, hi ku ya hi mindzhukano hinkwayo ya ntwanano lowu tsariweke ebukwini leyi ya nawu.' },
    { n: 22, text: 'Kutani xitukulwana lexi taka, vana va n’wina lava nga ta humelela endzhaku ka n’wina, ni muluveri la humaka etikweni ra le kule, va ta ku, loko va vona makhombo ya tiko rero, ni mavabyi lawa Yehovha a ri vabviseke ha wona;' },
    { n: 23, text: 'ni leswaku tiko rero hinkwaro i xivalivurhu ni munyu ni ku hisiwa, a ri byariwi nchumu, a ri milisi nchumu, a ku hlukisiwi byanyi eka rona, ku fana ni ku lovisiwa ka Sodoma na Gomora, Adima na Seboyimi, lawa Yehovha a ma loviseke hi vukari bya yena ni hi xihluku xa yena;' },
    { n: 24, text: 'matiko hinkwawo ma ta ku: “Hikwalaho ka yini Yehovha a endle leswi etikweni leri? I yini vukari lebyi byikulu lebyi pfurhaka?' },
    { n: 25, text: 'Kutani vanhu va ta hlamula va ku: “Hikuva va tshikile ntwanano wa Yehovha Xikwembu xa vatata wa vona, lowu a wu endleke na vona loko a va humesa etikweni ra Egipta;' },
    { n: 26, text: 'va fambile va ya tirhela swikwembu swin’wana, va swi khizamela, swikwembu leswi a va nga swi tivi, leswi a nga va avelangiki swona;' },
    { n: 27, text: 'hikwalaho vukari bya Yehovha byi pfurhele tiko leri, ku tisa ehenhla ka rona ndzhukano hinkwawo lowu tsariweke ebukwini leyi;' },
    { n: 28, text: 'Yehovha u va tsuvurile etikweni ra vona hi vukari, ni hi xihluku, ni hi ku hlundzuka lokukulu, a va cukumetela etikweni rin’wana, hilaha swi nga hakona namuntlha.' },
    { n: 29, text: 'Swilo swa xihundla i swa Yehovha Xikwembu xa hina; kambe swilo leswi kombisiweke i swa hina ni swa vana va hina hilaha ku nga heriki, leswaku hi endla marito hinkwawo ya nawu lowu.' }
  ],

30: [
    { n: 1, text: 'Kutani swi ta endleka leswaku, loko swilo leswi hinkwaswo swi ku wela, nkateko ni ndzhukano lowu ndzi wu veke mahlweni ka wena, kutani u swi tsundzuka embilwini ya wena exikarhi ka matiko hinkwawo laha Yehovha Xikwembu xa wena a ku hlongoleke kona;' },
    { n: 2, text: 'kutani u tlhelela eka Yehovha Xikwembu xa wena, u yingisa rito ra yena hi hinkwaswo leswi ndzi ku lerisaka swona namuntlha, wena ni vana va wena, hi mbilu ya wena hinkwayo ni hi moya wa wena hinkwawo;' },
    { n: 3, text: 'kutani Yehovha Xikwembu xa wena u ta tlherisela ku phangiwa ka wena, a ku twela vusiwana, a tlhela a ku hlengeleta ku suka exikarhi ka matiko hinkwawo laha Yehovha Xikwembu xa wena a ku hangalaseleke kona.' },
    { n: 4, text: 'Hambi va ri lava va hangalaseke e makumu ya tilo, Yehovha Xikwembu xa wena u ta ku hlengeleta ku suka kwalaho, a ku teka kwalaho;' },
    { n: 5, text: 'kutani Yehovha Xikwembu xa wena u ta ku yisa etikweni leri vatata wa wena va ri teke, kutani u ta ri teka; u ta ku katekisa, u ta ku andzisela ehenhla ka vatata wa wena.' },
    { n: 6, text: 'Yehovha Xikwembu xa wena u ta phuphuthela mbilu ya wena, ni mbilu ya vana va wena, leswaku u rhandza Yehovha Xikwembu xa wena hi mbilu ya wena hinkwayo ni hi moya wa wena hinkwawo, leswaku u hanya.' },
    { n: 7, text: 'Yehovha Xikwembu xa wena u ta veka mindzhukano leyi hinkwayo ehenhla ka valala va wena, ni le henhla ka lava va ku vengaka, lava va ku hlongoriseke.' },
    { n: 8, text: 'Kutani u ta tlhela u yingisa rito ra Yehovha, u endla swileriso swa yena hinkwaswo leswi ndzi ku lerisaka swona namuntlha.' },
    { n: 9, text: 'Yehovha Xikwembu xa wena u ta ku endla u va ni swilo swo tala emintirhweni hinkwayo ya voko ra wena, embhandzwini wa khwiri ra wena, ni le mbhandzwini wa swifuwo swa wena, ni le mbhandzwini wa misava ya wena, leswinene; hikuva Yehovha u ta tlhela a tsaka hi wena leswaku a ku endla u va ni swilo swo tala, hilaha a tsakeke hakona hi vatata wa wena;' },
    { n: 10, text: 'loko u yingisa rito ra Yehovha Xikwembu xa wena, u hlayisa swileriso swa yena ni milawu ya yena leyi tsariweke ebukwini leyi ya nawu; loko u tlhelela eka Yehovha Xikwembu xa wena hi mbilu ya wena hinkwayo ni hi moya wa wena hinkwawo.' },
    { n: 11, text: 'Hikuva xileriso lexi ndzi ku lerisaka xona namuntlha, a xi le kule na wena, naswona a xi le kule.' },
    { n: 12, text: 'A xi le tilweni, leswaku u ku: ‘I mani la nga ta hi tlhandlukela etilweni, a hi tekelo xona, a hi twarisa xona, leswaku hi xi endla?' },
    { n: 13, text: 'Naswona a xi le kusuhi na wena hi le mhefheni ya lwandle, leswaku u ku: ‘I mani la nga ta tsemakanya lwandle hi hina, a hi tekelo xona, a hi twarisa xona, leswaku hi xi endla?' },
    { n: 14, text: 'Kambe rito ri le kusuhi swinene na wena, ri le nomu wa wena, ni le mbilwini ya wena, leswaku u xi endla.' },
    { n: 15, text: 'Vonani, ndzi veke namuntlha mahlweni ka wena vutomi ni leswinene, rifu ni leswo biha;' },
    { n: 16, text: 'loko u yingisa swileriso swa Yehovha Xikwembu xa wena leswi ndzi ku lerisaka swona namuntlha, ku rhandza Yehovha Xikwembu xa wena, ku famba etindleleni ta yena, ku hlayisa swileriso swa yena, milawu ya yena, ni swiavanyiso swa yena, kutani u ta hanya, u andza; Yehovha Xikwembu xa wena u ta ku katekisa etikweni leri u yaka eka rona ku ri teka.' },
    { n: 17, text: 'Kambe loko mbilu ya wena yi hambukela ekutini, naswona u nga yingisi, kambe u kokiwa ku ya tirhela swikwembu swin’wana, u swi khizamela;' },
    { n: 18, text: 'ndzi mi byela namuntlha leswaku mi ta lovisiwa hakunene; mi nge lehi masiku ya n’wina etikweni leri mi tsemakanyaka Yordani ku nghena eka rona leswaku mi ri teka.' },
    { n: 19, text: 'Ndzi vitana tilo ni misava swi va timbhoni namuntlha ehenhla ka n’wina, leswaku ndzi veke mahlweni ka n’wina vutomi ni rifu, nkateko ni ndzhukano; hikwalaho hlawula vutomi, leswaku u hanya, wena ni vana va wena;' },
    { n: 20, text: 'ku rhandza Yehovha Xikwembu xa wena, ku yingisa rito ra yena, ni ku namarhela eka yena; hikuva i vutomi bya wena, ni ku leha ka masiku ya wena, leswaku u tshama etikweni leri Yehovha a ri hlambanyeleke vatata wa wena, Abrahama, Isaka, na Yakobo, ku va nyika rona.' }
  ],
  31: [
    { n: 1, text: 'Muxe a ya a vulavula marito lawa eka Israyele hinkwavo.' },
    { n: 2, text: 'A ku eka vona: ‘Ndzi ni malembe ya khume-khume ni mune namuntlha; a ndzi ha koti ku huma ni ku nghena; naswona Yehovha u te eka mina: “U nga tsemakanyi Yordani lowu.' },
    { n: 3, text: 'Yehovha Xikwembu xa wena u ta tsemakanya mahlweni ka wena; u ta lovisa matiko lawa mahlweni ka wena, kutani u ta ma teka; Yoxuwa u ta tsemakanya mahlweni ka wena, hilaha Yehovha a vuleke hakona.' },
    { n: 4, text: 'Yehovha u ta va endla hilaha a endleke hakona eka Sihoni ni le ka Ogo, tihosi ta Vaamori, ni le tikweni ra vona, loko a va lovisile.' },
    { n: 5, text: 'Yehovha u ta va nyiketa mahlweni ka n’wina, kutani mi ta va endla hi ku ya hi xileriso hinkwaxo lexi ndzi mi leriseke xona.' },
    { n: 6, text: 'Tiyani, mi va ni xivindzi, mi nga chavi, mi nga rhurhumeli mahlweni ka vona; hikuva Yehovha Xikwembu xa wena hi yena loyi a fambaka na wena; a nge ku tshiki, a nge ku fularheli.' },
    { n: 7, text: 'Muxe a vitana Yoxuwa, a ku eka yena mahlweni ka Israyele hinkwavo: ‘Tiya, u va ni xivindzi; hikuva u ta nghena ni vanhu lava etikweni leri Yehovha a ri hlambanyeleke vatata wa vona ku va nyika rona; kutani u ta va avela rona ku va ndzhaka ya vona.' },
    { n: 8, text: 'Yehovha hi yena loyi a fambaka mahlweni ka wena; u ta va na wena; a nge ku tshiki, a nge ku fularheli; u nga chavi, u nga rhurhumeli.' },
    { n: 9, text: 'Muxe a tsala nawu lowu, a wu nyika vaprista, vana va Levhi, lava a va rhwala areka ya ntwanano wa Yehovha, ni vadyuhari hinkwavo va Israyele.' },
    { n: 10, text: 'Muxe a va lerisa, a ku: ‘Eku heleni ka malembe ya nkombo, hi nkarhi wa lembe ra ku rivalela, hi nkhuvo wa matende;' },
    { n: 11, text: 'loko Israyele hinkwavo va ta ku ta vonaka mahlweni ka Yehovha Xikwembu xa wena endhawini leyi a nga ta yi hlawula, u ta hlaya nawu lowu mahlweni ka Israyele hinkwavo, va twa.' },
    { n: 12, text: 'Hlengeleta vanhu, vavanuna, vavasati, vana, ni muluveri loyi a nga exikarhi ka tinyangwa ta wena, leswaku va twa, va dyondza, va chava Yehovha Xikwembu xa n’wina, va hlayisa ku endla marito hinkwawo ya nawu lowu;' },
    { n: 13, text: 'ni vana va vona lava nga swi tiviki, va ta twa, va dyondza ku chava Yehovha Xikwembu xa n’wina, masiku hinkwawo lawa mi nga ta tshama ha wona etikweni leri mi tsemakanyaka Yordani ku nghena eka rona leswaku mi ri teka.' },
    { n: 14, text: 'Yehovha a ku eka Muxe: ‘Vonani, masiku ya wena ya rifu ma tshinele; vitana Yoxuwa, mi yima etendeni ra ntsombano, leswaku ndzi ta n’wi nyika xileriso.’ Muxe na Yoxuwa va ya yima etendeni ra ntsombano.' },
    { n: 15, text: 'Yehovha a humelela etendeni hi phuphu ya refu; refu a ri yimile enyangweni wa tende.' },
    { n: 16, text: 'Yehovha a ku eka Muxe: ‘Vonani, u ta etlela ni vatata wa wena; vanhu lava va ta suka va endla vunghwavila endzhaku ka swikwembu swa matiko ya tiko leri va nghenaka eka rona, va ndzi tshika, va tlula ntwanano wa mina lowu ndzi wu endleke na vona.' },
    { n: 17, text: 'Kutani vukari bya mina byi ta va pfurhela hi siku rero, ndzi ta va tshika, ndzi va fularhela, kutani va ta lovisiwa, makhombo yo tala ni mahlomulo ma ta va wela; va ta ku hi siku rero: “Xana makhombo lawa a ma nga mi welanga hikuva Xikwembu xa mina a xi nga ri exikarhi ka mina?' },
    { n: 18, text: 'Kutani ndzi ta fularhela hi siku rero, hikwalaho ka vubihi hinkwabyo lebyi va nga ta byi endla, hi ku fambela swikwembu swin’wana.' },
    { n: 19, text: 'Hikwalaho tsala risimu leri, u ri dyondzisa vana va Israyele, u ri veka emilonyeni ya vona, leswaku risimu leri ri va mbhoni ehenhla ka vana va Israyele.' },
    { n: 20, text: 'Hikuva loko ndzi va yisile etikweni leri ndzi ri hlambanyeleke vatata wa vona, leri khulukaka ntsamba ni vulombe, kutani va dya, va xurha, va nona, va fularhela swikwembu swin’wana va swi tirhela, va ndzi tshika, va tlula ntwanano wa mina;' },
    { n: 21, text: 'kutani swi ta endleka, loko makhombo yo tala ni mahlomulo ma va wela, risimu leri ri ta va mbhoni mahlweni ka vona; hikuva a ri nge rivaliwi emilonyeni ya vana va vona; hikuva ndzi yi tiva mbilu ya vona leyi va nga ta yi endla namuntlha, ndzi nga si va yisa etikweni leri ndzi ri hlambanyeleke.' },
    { n: 22, text: 'Muxe a tsala risimu leri hi siku rero, a ri dyondzisa vana va Israyele.' },
    { n: 23, text: 'Yehovha a lerisa Yoxuwa n’wana wa Nuni, a ku: ‘Tiya, u va ni xivindzi; hikuva u ta nghena ni vana va Israyele etikweni leri ndzi ri hlambanyeleke, naswona ndzi ta va na wena.' },
    { n: 24, text: 'Endzhaku ka sweswo, loko Muxe a hete ku tsala marito ya nawu lowu ebukwini ku fika emakumu,' },
    { n: 25, text: 'Muxe a lerisa Valevhi lava rhwalaka areka ya ntwanano wa Yehovha, a ku:' },
    { n: 26, text: 'Tekani buku leyi ya nawu, mi yi veka etlhelo ka areka ya ntwanano wa Yehovha Xikwembu xa n’wina, leswaku yi va mbhoni ehenhla ka n’wina;' },
    { n: 27, text: 'hikuva ndzi yi tiva ku sihalala ka n’wina ni ku tiomisa nhloko ka n’wina; vonani, loko ndza ha hanya na n’wina namuntlha, mi vile va-ku-tsemakanya Yehovha; nkarhi wo fika wa mina, mi ta tsemakanya ngopfu.' },
    { n: 28, text: 'Hlengeletani eka mina vadyuhari hinkwavo va tinyimba ta n’wina ni valanguteri va n’wina, leswaku ndzi ta vula marito lawa etindleveni ta vona, ndzi vitana tilo ni misava swi va timbhoni ehenhla ka vona.' },
    { n: 29, text: 'Hikuva ndzi tiva leswaku endzhaku ka rifu ra mina mi ta hambukisa swinene, mi fambela etlhelo eka ndlela leyi ndzi mi leriseke ha yona; naswona makhombo ma ta mi wela emasikwini lama taka, hikuva mi ta endla leswi nga biha ematihlweni ya Yehovha, mi n’wi hlundzukisa hi ntirho wa mavoko ya n’wina.' },
    { n: 30, text: 'Muxe a vula marito ya risimu leri etindleveni ta vandla hinkwaro ra Israyele, ku fika emakumu.' }
  ],
32: [
    { n: 1, text: 'Tilo, twa, ndzi ta vulavula; misava, yingisa marito ya nomu wa mina.' },
    { n: 2, text: 'Dyondzo ya mina yi ta phaphalata ku fana ni mpfula, marito ya mina ma ta xika ku fana ni mume; ku fana ni mpfula leyitsongo ehenhla ka byanyi, ni ku fana ni mpfula leyikulu ehenhla ka swimilana.' },
    { n: 3, text: 'Hikuva ndzi ta huwelela vito ra Yehovha; dzunisani vukulu bya Xikwembu xa hina.' },
    { n: 4, text: 'Yena i Ribye, ntirho wa yena i wo hetiseka; hikuva tindlela ta yena hinkwato i ta ku lulama; i Xikwembu xa ntiyiso, a xi na vubihi; wa lulama naswona wa tshembeka.' },
    { n: 5, text: 'Va n’wi onhele; a va ha ri vana va yena hikwalaho ka swidyoho swa vona; i rixaka ro khwirisela ni ro soholoka.' },
    { n: 6, text: 'Xana mi pfuxela Yehovha hi mhaka leyi, n’wina vanhu va xiphukuphuku ni lava va nga riki na vutlhari? Xana a hi yena tatana wa n’wina loyi a mi xaveke? I yena loyi a mi endleke, a mi simeka.' },
    { n: 7, text: 'Tsundzukani masiku ya khale, ehleketa malembe ya swiitukulwana swa swiitukulwana; vutisa tata wa wena, u ta ku byela; vadyuhari va wena, va ta ku byela.' },
    { n: 8, text: 'Loko La-henhla-henhla a avela matiko ndzhaka ya wona, loko a a hambanisa vana va vanhu, u vekile mindzilakano ya vanhu hi ku ya hi nhlayo ya vana va Israyele.' },
    { n: 9, text: 'Hikuva mugero wa Yehovha i vanhu va yena; Yakobo i xiphemu xa ndzhaka ya yena.' },
    { n: 10, text: 'U n’wi kumile etikweni ra mananga, ni le ku rila ka nhova leyi nga ni khombo; u n’wi rhendzerile, u n’wi langutisisile, u n’wi hlayisile ku fana ni mbhoni ya tihlo ra yena.' },
    { n: 11, text: 'Hilaha gama ri pfuxaka xisaka xa rona, ri haha ehenhla ka mavondlo ya rona, ri tshambuluta timpapa ta rona, ri ma teka, ri ma rhwala ehenhla ka timpapa ta rona;' },
    { n: 12, text: 'Yehovha a n’wi fambisile a ri yexe, naswona a ku na xikwembu xin’wana na yena.' },
    { n: 13, text: 'U n’wi tlakusile ehenhla ka tindhawu ta misava, kutani a dya mihandzu ya nhova; u n’wi dyisile ntsamba hi maribyeni, ni mafurha ya mutlhwari hi ribye leri tiyeke;' },
    { n: 14, text: 'switlatlana swa tihomu, ni mafurha ya tinyimpfi, xikan’we ni tihomu ta xifuyu, ni timbuti, ni swikhomba swa mavele, u n’wi nwise vhinyo yo tshwuka ya madiriva.' },
    { n: 15, text: 'Kambe Yexuruni u nonile, kutani a tlhaba ntsalo; u nonile, u tsakile, u tiyile; kutani a tshika Xikwembu lexi xi n’wi endleke, a langutela hi ku delela Ribye ra ku ponisiwa ka yena.' },
    { n: 16, text: 'Va n’wi vangele ku n’wi monya hi swikwembu swin’wana, va n’wi hlundzukisa hi swilo swo nyenyentsa.' },
    { n: 17, text: 'Va endle magandzelo eka mademona, ku nga ri Xikwembu, eka swikwembu leswi va nga swi tivangiki, swikwembu leswintshwa leswi humeleleke, leswi vatata wa vona va nga chaveniki.' },
    { n: 18, text: 'U rivale Ribye leri ku tswaleke, u rivale Xikwembu lexi ku endleke.' },
    { n: 19, text: 'Yehovha a swi vona, kutani a va venga, hikwalaho ka ku hlundzukisiwa hi vana va yena va xinuna ni va xisati.' },
    { n: 20, text: 'A ku: ‘Ndzi ta fularhela vuso bya mina eka vona, ndzi ta vona leswi swi nga ta va makumu ya vona; hikuva i rixaka ro khwirisela, vana lava nga riki na ku tshembeka.' },
    { n: 21, text: 'Va ndzi vangele ku va monya hi leswi nga riki Xikwembu, va ndzi hlundzukisa hi swikwembu swa vona swa hava; kutani na mina ndzi ta va vangela ku va monya hi lava nga riki tiko, ndzi va hlundzukisa hi tiko ra vahlanya.' },
    { n: 22, text: 'Hikuva ndzilo wu pfurhile evukarini bya mina, wu ta hisa ku fika eku titameni ka hayi, wu ta hisa misava ni mihandzu ya yona, wu hisa masungulo ya tintshava.' },
    { n: 23, text: 'Ndzi ta va ntswela makhombo, ndzi va rhumela mitswalo ya mina hinkwayo.' },
    { n: 24, text: 'Va ta fa hi ndlala, va dyiwa hi vuvabyi ni ku hisa loku vavisaka; ndzi ta va rhumela meno ya swivandzana, ni thyu ra swilo leswi hambahambaka entshurini.' },
    { n: 25, text: 'Banga ri ta lovisa vana va xinuna ehandle, ni vana va xisati va ta chava, xikan’we ni xihlangi, ni n’wana la dyuhaleke.' },
    { n: 26, text: 'A ndzi te, ndzi ta va hangalasa, ndzi sula vito ra vona exikarhi ka vanhu;' },
    { n: 27, text: 'loko a ku ri ku chava vukari bya nala, leswaku valala va vona va nga tiendli va kulukumba, naswona va ku: “Voko ra hina ri tlakukile, a hi Yehovha la endleke hinkwaswo leswi.' },
    { n: 28, text: 'Hikuva i tiko leri nga riki na vutlhari, naswona a va na ku twisisa.' },
    { n: 29, text: 'Loko a va ri na vutlhari, a va ta va va swi twisisa sweswi, a va ta va va ehleketela makumu ya vona.' },
    { n: 30, text: 'Xana un’we a a ta hlula ntlhanu-wa-madzana, naswona vambirhi va hlongola ntlhanu-wa-madzana, loko Ribye ra vona a ri nga va xavisanga, Yehovha a nga va nyiketanga?' },
    { n: 31, text: 'Hikuva ribye ra vona a hi Ribye ra hina, ni valala va hina a va swi tiva.' },
    { n: 32, text: 'Hikuva vhinyo ya vona i ya nsimu ya vhinya ya Sodoma, ni ya masimu ya Gomora; madiriva ya vona i madiriva ya vuxungu, ma na mahlaha yo baba;' },
    { n: 33, text: 'vhinyo ya vona i vuxungu bya tihanyi, ni byalwa byo chavisa bya tiyoka.' },
    { n: 34, text: 'Sweswo a swi nga hlayisiwanga eka mina, swi funengetiweke eswitlatini swa mina?' },
    { n: 35, text: 'Ku rihisela i ka mina, ndzi ta tlherisela hi nkarhi wa kona, loko nenge wa vona wu ta wa; hikuva siku ra khombo ra vona ri tshinele, swilo leswi nga ta va wela swi ta hatla swi fika.' },
    { n: 36, text: 'Hikuva Yehovha u ta avanyisa vanhu va yena, a ta twela malandza ya yena vusiwana, loko a vona leswaku matimba ya vona ma herile, a ku ha na munhu la khomiweke kumbe la tshikiweke.' },
    { n: 37, text: 'A ku, “Xana swikwembu swa vona swi kwihi, ribye leri va titshegeke ha rona?' },
    { n: 38, text: 'Swilo leswi a va dya mafurha ya magandzelo ya vona, a va nwa vhinyo ya magandzelo ya vona? A swi pfuke swi va pfuna, swi va sirhelela.' },
    { n: 39, text: 'Vonani sweswi, hi mina, hi mina, a ku na xikwembu xin’wana na mina; ndzi dlaya, ndzi hanyisa; ndzi ba, ndzi horisa; a ku na munhu la nga ponisaka evokweni ra mina.' },
    { n: 40, text: 'Hikuva ndzi tlakusela voko ra mina etilweni, ndzi ku: “Hi mina la hanyaka hilaha ku nga heriki;' },
    { n: 41, text: 'loko ndzi vatsa banga ra mina leri phazilaka, voko ra mina ri khoma ku avanyisa, ndzi ta tlherisela valala va mina, ndzi rihisela eka lava va ndzi vengaka.' },
    { n: 42, text: 'Ndzi ta dakusa mitswalo ya mina hi ngati, banga ra mina ri ta dya nyama, hi ngati ya lava dlayiweke ni lava khomiweke, ku suka etinhlokweni ta tindhuna ta valala.' },
    { n: 43, text: 'Tsakani, n’wina matiko, ni vanhu va yena; hikuva u ta rihisela ngati ya malandza ya yena, a tlherisela valala va yena, a kombisa musa etikweni ra yena ni vanhu va yena.' },
    { n: 44, text: 'Muxe a ta a vula marito hinkwawo ya risimu leri etindleveni ta vanhu, yena na Yoxuwa n’wana wa Nuni.' },
    { n: 45, text: 'Muxe a heta ku vula marito lawa hinkwawo eka Israyele hinkwavo;' },
    { n: 46, text: 'a ku eka vona: ‘Tiyisisani marito hinkwawo lawa ndzi mi byelaka wona namuntlha, mi ma lerisa vana va n’wina, leswaku va hlayisa, va endla marito hinkwawo ya nawu lowu.' },
    { n: 47, text: 'Hikuva a hi rito ra hava eka n’wina; hikuva i vutomi bya n’wina, hi rito leri mi ta leha masiku ya n’wina etikweni leri mi tsemakanyaka Yordani ku nghena eka rona leswaku mi ri teka.' },
    { n: 48, text: 'Yehovha a vulavula na Muxe hi siku rero, a ku:' },
    { n: 49, text: 'Tlhandluka entshaveni leyi ya Abarimi, ntshava ya Nebo, leyi nga etikweni ra Mowabu, leyi nga mahlweni ka Yeriko, u languta tiko ra Kanana, leri ndzi ri nyikaka vana va Israyele ku va ndzhaka;' },
    { n: 50, text: 'u ta fela entshaveni leyi u tlhandlukaka eka yona, u hlengeletiwa eka vanhu va wena, hilaha Aroni makwenu a feke hakona entshaveni ya Hori, a hlengeletiwa eka vanhu va yena;' },
    { n: 51, text: 'hikwalaho ka leswi mi ndzi tluleke exikarhi ka vana va Israyele ematini ya Meriba-Kadexi, emananga ya Sini; hikuva a mi ndzi kwetsimisanga exikarhi ka vana va Israyele.' },
    { n: 52, text: 'Hikuva u ta vona tiko mahlweni ka wena; kambe a wu nge ngheni etikweni leri ndzi ri nyikaka vana va Israyele.' }
  ]

};
